const hymns = [
  { id: 1, title: 'Ngcwele, ngcwele, ngcwele', lyrics: `1 Ngcwele, ngcwele, ngcwele\nMninimandla onke!\nUkuphuma kwelanga siyohuba kuwe;\nNgcwele, ngcwele, ngcwele\nMninimusa wonke!\nNibathath’ eMunye oMakade!\n\n2 Ngcwele, ngcwele, ngcwele!\nAbangcwele bonke.\nBemi phambi kwakho, bayethula imiqhele\nBayibeka kuwe; namakherubimi\nAkukhothamela, Simakade!\n\n3 Ngcwele, ngcwele, ngcwele,\nNom’ ufihlekile.\nNoma ungabonwa yibo abonayo,\nKuphela wena uhlanzekile\nUyedwa!\n\n4 Ngcwele, ngcwele, ngcwele,\nNkulunkulu wamandla!\nZintathu iziqu zakhe zodumo,\nZinoyedwa amandla.\nThixo Somandla!` },
  { id: 2, title: 'SesiZe Lapha, Thixo Omkhulu', lyrics: `1 Sesize lapha, Thixo omkhulu,\nNgalolusuku oluyingcwele;\nSondela kithi ngoMoya wakho,\nSikudumise endlini yakho.\n\n2 Usinikile usukuIwakho;\nUsinikile ilizwi lakho;\nWasinikeza othandekhayo\nUkusifela, thin' abonayo.\n\n3 Yizani nonke, masimdumise\nUBaba wethu uMninimandla,\nUJesu Kristu OnguMsindisi,\nUMoya wakhe uMthokhozisi.\n\n4 Masimdumise ngomlomo wethu;\nMasimdumise ngezenzo zethu;\nMasimdumise sisemhlabeni;\nMasimdumise nasezulwini.` }, 
  { id: 3, title: 'Nkosi, Baba, sihlangene', lyrics: `1 Nkosi, Baba, sihlangene,\nThin' abantu bakho;\nMawufike kithi namhla;\nNgobubele bakho.\n\n2 Jesu, Mhlawuleli wethu,\nThina singabakho;\nSifundise izwi lakho,\nSenz' intando yakho.\n\n3 Nkosi, Moya oyiNgcwele,\nYiba-nathi sonke;\nNgoba asinal' usizo\nNxa ungekho kithi.\n\n4 Nkosi, mawuhlale nathi,\nNgaphakathi kwethu,\nSithokoze njalonjalo\nNgobukhona bakho.` },
  { id: 4, title: 'Woza Thixo wethu', lyrics: `1 Woza, Thixo wethu\nOngamandla ethu\nUsisize;\nBaba obusayo,\nWena onqobayo,\nWena osizayo,\nUsibheke.\n\n2 Jesu, Mbusi wethu,\nNqob' izitha zethu\nUzahlule;\nVez' amandla akho,\nUkuhleng’abakho,\nInhliziyo yabo\nIme kuwe\n\n3 Moya oyiNgcwele,\nWoza usihole,\nSibusise;\nUzihlanzisise\n'Zinhliziyo zethu;\nUbe-phezu kwethu,\nSilungise.\n\n4 Nkulunkulu wedwa,\nAbathathu 'Munye\nMana njalo!\nUbukhosi bonke,\nNaw' amandla onke,\nNal' udumo lwonke,\nkungokwakho.` }, 
  { id: 5, title: 'Sivulele, Nkosi', lyrics: `1 Sivulele, Nkosi,\nIzinhliziyo zethu;\nSingene ngokuthula,\nPhambi kwakho.\n\n2 Sifundise izindlela zakho,\nSihambe kuzo;\nSikholwe ngokweqiniso,\nSikuthande.` },
  { id: 6, title: 'O Jehova, Uyangazi', lyrics: `1 O Jehova, uyangazi\nUyabon' ukwenza kwami\nUkuhlala, nokuvuka,\nNokuhamba konke kwami.\n\n2 Uyahlala ezulwini,\nLona liyikhaya lakho;\nKhepha okusemhlabeni\nKusobala phambi kwakho.\n\n3 Uyawaz' amazwi ami,\nNokuzindla kwami konke;\nNguwe ongizungezayo\nEndleleni yami yonke.\n\n4 Ubumnyama nokukhanya\nKuyafana, Baba kuwe;\nAnginakho ukubaca\nLapha ngingabonwa nguwe.\n\n5 Lokhukwazi nokuhlola\nKuyangesabisa, Baba,\nNgoba inhliziyo yami\nIyavama ukweduka.` },
  { id: 7, title: 'UJehova Unamandla', lyrics: `1 Ujehova unamandla,\nZonk' izinto zenzwa uye;\nUyinkosi yamabandla\nAmkhonzayo ezulwini.\n\n2 UJehova unokwazi,\nUyazaz' izinto zonke;\nThin' abantu asizazi,\nSi 'ziwula thina sonke.\n\n3 UJehova ulungile,\nNayo imithetho yakhe;\nKodwa thina sedukile,\nSinecala phambi kwakhe.\n\n4 UJehova uyingcwele,\nSingengene phambi kwakhe,\nKanti uyasivumela\nNgayo iNdodana yakhe.\n\n5 Ujehova unomusa,\nUsiphatha sonke ngawo\nKufanele ukunxusa\nKuye ubumnandi bawo.` },
  { id: 8, title: 'Dumisa uJehova', lyrics: `1 Dumisa uJehova,\nOwenz' izinto zonke;\nDumisa uJehova\nEzweni lakhe lonke.\n\n2 Dumisa uJehova,\nOwazi konke kade;\nDumisa uJehova\nNamandla aphakade.\n\n3 Dumisa uJehova,\nOsiz' abantu bakhe,\nDumisa uJehova,\nNibone umsa wakhe.\n\n4 Dumisa uJehova\nUBaba neNdodana;\nDumisa uJehova,\nNomoya oyiNgcwele.` },
  { id: 9, title: 'Hubanini KuJehova', lyrics: `1 Hubanini kuJehova,\nNina, bantu bezwe lonke;\nNimdumise, nithokoze,\nNijabule ngaye nonke.\nUyiNkosi uJehova.\nUnguMenzi wethu yena;\nWosiphatha, wosilonda,\nSingabantu bakhe thina.\n\n2 Ngenanini nimdumise,\nNiy’emasangweni akhe;\nBonganini nokubonga,\nNikhulis' igama lakhe.\nUlungile uJehova,\nUphakade umsa wakhe;\nNeqiniso lisahlezi\nEbantwini, alipheli.` },
  { id: 10, title: 'Wathanda izwe Kangaka', lyrics: `1 Wathanda izwe kangaka!\nKukhulu ukusinaka!\nKusinde abantu bakhe;\nDumisani uJehova.\nMudumise uYise,\nMudumise uYise,\nDumisani, dumisani,\nDumisani uJehova\n\n2 UKristu usihambile,\nNgothando usitshelile,\nNangakho ukusifela;\nDumisani uJehova.\n\n3 Wagqoka ubuntu bethu,\nWaba-uMlamuli wethu,\nWaqed' izinhlupho zethu;\nDumisani uJehova\n\n4 Emuthini wabafela,\nAbantu basebephela,\nNeliba wabanqobela;\nDumisani uJehova\nMudumise uYise,\nMudumise uYise,\nDumisani, dumisani,\nDumisani uJehova.\n\n5 Uphakeme ngaphezulu,\nUbatshazwa 'hhe kakhulu;\nBanamhla nabasendulo,\nDumisani uJehova.` },
  { id: 11, title: 'Qondanini Umsebenzi', lyrics: `1 Qondanini umsebenzi\nKaJehova onguMenzi,\nE'ndaweni zonke;\nBuyabonwa ezulwini,\nEncwadini nasezweni,\nubukhulu bakhe.\n\n2 UJehova unamandla,\nUyiNkosi yamabandla,\nUnguMenzi wethu;\nUze enamandla onke\nUkubasindisa bonke\nAbakholwa uye.\n\n3 UsenguMvikeli wabo,\nUyanqob' izitha zabo,\nBayalondwa nguye;\nNxa behlelwa ukwesaba,\nMhla kushiw' umhlaba lona,\nBokhwezeka kuye.\n\n4 Masithobe phambi kwakhe,\nSidumis' igama lakhe,\nSizinike kuye;\nO bakithi, qaphelani!\nWozanini, phendukani,\nNize kuJehova.` },
  { id: 12, title: 'UThixo Omkhulu', lyrics: `1 UThixo omkhulu\nUyiNkos' yezulu,\nUyatuswa:\nZingelosi zonke,\nNamaKristu onke,\nMuvumeni nonke\nNgamagama\n\n2 Nina enihlezi\nEmbusweni wakhe\nOphezulu,\nManivume nonke,\nKanye nabezwile\nNgal' uthando lwakhe\nOlukhulu.\n\n3 Bakhululiweyo\nNikani uThixo\nUdumiso;\nMasethabe kuye\nEsisinda ngaye,\nSisondele kanye,\nSimbabaze.\n\n4 Masinyane thina\nSohlangana naye\nEmbusweni;\nSomdumisa khona,\nSenze izibongo\nEzingapheliyo\nEzulwini.` },
  { id: 13, title: 'Ezintabeni Ngiyophakamisa', lyrics: `1 Ezintabeni ngiyophakamisa\nAmehlo ami. Ukusiza lapho\nKuyovelaphi? E Jehova, siza,\nOwenz' izulu naw' umhlaba.\n\n2 Unyawo lwakho alungasheleli;\nOkuthandayo akayikozela.\nBheka-ke, yean ogcina uIsrayeli\nAnakulala nokozela.\n\n3 UMlondolozi wakho nguJehova,\nUmthunzi wakho\nNgakwesokunene;\nEmini alinakushay' ilanga,\nNasebusuk' inyang' imnene.\n\n4 Uyakugcina ebubini bonke,\nUmphefumulo wakho\nawuphase;\nUyakulonda ukuphuma kwakho,\nNakh' ukungena naphakade.` },
  { id: 14, title: 'Wehla UJehova', lyrics: `1 Wehla uJehova\nKhon' endulo,\nWafikel' eSinayi\nLinomlilo:\nKwakukhon' udumo\nEmnyameni,\nNokuzamazama\nEmhlabeni.\n\n2 Wakusho kuMosi,\nEntabeni,\n"Tshel' abant' ukuthi\nBekuyimi\nOnelusileyo\nEndleleni,\nNgamaphik' okhozi\nNganigcina.\n\n3 Manje yizwanini,\nNas' esami\nIsivumelwano:\nNob'-abami\nUma nilalela\nIzwi lami.\nUma nikugcina\nKonk' okwami:\n\n4 Nob'-umbuso wam\nWabapristi,\nNob'-isizwe' esihle\nSabangcwele\"\nEbuyil' uMosi\nWabatshela,\nBathi, \"Sivuma\nKuhl' impela,\"\n\n5 Njengokusho kwabo\nKuwe, Baba,\nNathi siyavuma\nNgokwethaba,\nSithi, Nkosi yethu\nSingabakho.\nSoyenza intando\nYonke yakho.` },
  { id: 15, title: 'Ngenhliziyo Yonke Yami', lyrics: `1 Ngenhliziyo, yonke yami\nNgiyambong' uThixo wami\nOngibusisile;\nUyekel' ukona kwami,\nUsusil' izifo zami,\nUngiphilisile.\n\n2 Nginezinto eziningi,\nNgiyabusa, angidingi,\nNgiyaphiwa nguye;\nNina enihluphekayo,\nNina enithwesiweyo,\nManibheke kuye.\n\n3 Thina sonke sedukile\nYena akasiphathile\nNjengo kona kwethu;\nUnomusa nobubele,\nNgakho masimdumise\nNgenhliziyo yethu.\n\n4 Bonganini uJehova,\nNimdumise ngokuthanda,\nUyiNkosi yethu;\nThembanini ENkosini,\nIyahlala ezulwini,\nUMbusisi wethu.` },
  { id: 16, title: 'E Jehova UnguMenzi', lyrics: `1 EJehova, unguMenzi,\nOwasenza sonke;\nUyasiza, unamandla,\nUsigcina sonke.\n\n2 Ebusuku nasemini\nSiyalondwa nguwe;\nSiyahamba, siyalala,\nSiyagcinwa nguwe.\n\n3 Zonk' izinto esinazo\nSizamkele kuwe;\nSinokudla nezivatho\nSikuphiwe nguwe.\n\n4 Sinencwadi yokuphila,\nEyavela kuwe,\nNab' abasifundisayo\nBayathunywa nguwe.\n\n5 Nkosi, siyamangaliswa\nUbubele bakho;\nNkosi, siyakudumisa\nNgokulonda kwakho.` },
  { id: 17, title: 'Dumisani UJehova', lyrics: `1 Dumisani uJehova,\nBakhululiweyo bakhe;\nNiyhi, yena ulungile,\nUphakade umsa wakhe;\n\n2 Nina, nisekhona ngaye,\nNiyaphiwa uye konke,\nNiyaphila, niyahamba,\nNiyasizwa uye nonke.\n\n3 Bonganini uJehova\nNonke nin' abantu bakhe;\nBabazan' izenzo zakhe,\nNemimangaliso yakhe.` },
  { id: 18, title: 'Thin\' Abantu Balomhlaba', lyrics: `1 Thin' abantu balomhlaba,\nMasivuke, simdumise\nUJehova oyinqaba,\nUyathanda sisindiswe.\n\n2 Ekulahlekeni kwethu\nSedukile ngamacala,\nAsibanga-nakulunga,\nSabopheka ezonweni.\n\n3 Wasibona sidingile,\nWasisiza ngoMsindisi;\nSinokufa, sichithiwe,\nWasinika uMphilisi.\n\n4 Usamem' abantu bonke\nBalalele namhla kuye:\nKuyekelw' izono zonke\nZabo abakholwa kuye.` },
  { id: 19, title: 'Vusan\' Umsindo Wentokozo', lyrics: `1 Vusan' umsindo wentokozo,\nWe, mhlaba wonke, kuJehova;\nNikhonz' iNkosi ngokwethaba,\nZanini kuyo ngokuvuma.\n\n2 Bhek' uJehova unguThixo;\nSenziwe nguye thin' abantu;\nAsizenzanga, singabakhe,\nIzimvu zelidlelo lakhe\n\n3 Emasangweni anongena,\nNasemagumen' akhe, nina;\nNimbonge, nimbabaze, nithi,\nMalibusisw' igama lakhe.\n\n4 Ngokub' iNkosi ilungile,\nNomusa wayo uphakade;\nLihlezi iqiniso layo\nEzizukulwaneni zonke.` },
  { id: 20, title: 'UJehova Ungomkhulu', lyrics: `1 UJehova ungomkhulu,\nUnguThixo yena yedwa;\nUnguMenzi wakho konke,\nOkuse 'ndaweni zonke.\n\n2 Akanakho ukuqala,\nWayephambi kwakho konke;\nAkanakho ukuphela,\nKofa konke woba-khona.\n\n3 Unokwazi okukhulu,\nUyazaz' izinto zonke;\nUyabhek' indlela yazo,\nZimi ngokomthetho wakhe.\n\n4 Kufanele ukumkhonza,\nNgenhliziyo yokubonga;\nSiyabonga umsa wakhe,\nNabo ubukhulu bakhe.` },
  { id: 21, title: 'Sidumisa Ngenjabulo', lyrics: `1 Sidumisa ngenjabulo,\nNkosi enothando,\nNjengokuba izimbali\nZithokoz' ilanga.\nXosh' amafu onk' amnyama.\nSus' ukungabaza;\nInjabulo yaphakade\nMayisikhanyise.\n\n2 Unomusa nobunene\nUyasibusisa,\nUngumthombo wokuphila,\nMasiphuze kuwo.\nUnguBaba, sinoJesu,\nSinothando lwakhe.\nSiifundis' ukuthandana,\nSaz' uthabo lwakho.\n\n3 Hubanini, bantu nonke\nKanye ne' nkanyezi,\nSiyabusw' uthando lwakhe,\nZonk' izizwe kanye;\nSiyahuba, siqhubeka,\nKuzophel' ukulwa,\nLisivuselel' ihubo,\nLisinqobisisa.` },
  { id: 22, title: 'Unkulunkulu Onguthando', lyrics: `1 UNkulunkulu onguthando\nnguMalusi wami;\nNgiswele ntoni? Ngingowakhe,\nnaye ungowami.\n\n2 Uyangiyisa emanzini ahambayo\nkahle;\nNasehlungwini uyangiph' ukudla\nokungcwele.\n\n3 Ngaduka futhifuthi, kodwa\nwangifuna njalo,\nEhlombe wangetshatha waze\nwangileth' ekhaya.\n\n4 Nxa esekhona engalusa angesab'\nukufa;\nNgithemb' isandla sakhe\nengibambelele kuso.\n\n5 Ethafuleni lakho, Nkosi, unginik'\namandla;\nUleth' indeb' ethabisayo,\nungithokozise.\n\n6 Umusa wakho uyabongwa\nongayikuphela;\nSengathi ngingabona wena,\nNkosi, naphakade.` },
  { id: 23, title: 'Bongani\' INkos\' USomandla', lyrics: `1 Bongan' iNkos' uSomandla, umdali womhlaba,\nMbonge, nhliziyo, nguyen' okunik' ukwethaba;\nYizweni nonke, ngenani endlini yakhe.\nSimbonge sikhothamile.\n\n2 Bongan' iNkosi ebus' ezindaweni zonke\nEmaphikweni iyakusithez' ikukhweze;\nAwukaboni ukuthi konke okuhle\nKuvela ngomusa wayo?\n\n3 Bonga iNkosi ehlahlamelis' okwenzayo\nKungumusa wayo nothsndo olukuphasayo;\nKhumbula lokho owenzelwakho yiyona\nNgoba ungumuntwana wayo.\n\n4 Bonga iNkosi, ituswe ngalokh' esinakho.\nUdumo lwakhe luvuswe ngabantu bomhlaba.\nNithi Ameni! Masibabaze iNkosi,\nKuze kube-naphakade.` },
  { id: 24, title: 'Siyakudumisa, Msindisi NoMdali', lyrics: `1 Siyakudumisa, Msindisi noMdali:\nSethula kuwen' im' nikelo yethu,\nSiguqa, sibonga, sikhothamela wena.\nSitus' igama lakho ngengoma yethu.\n\n2 UnguNkulunkulu wawobaba bethu,\nOkad' usihol' endleleni yonke;\nNoma singehlelwa ingozi sophephiswa,\nSophumelela ngawe, O Mholi wethu.\n\n3 Sibonga ngelizwi lilinye, sisonke.\nKuwena, Jehova, sihlabelela;\nSoholwa ngeyakho ingalo enamandla,\nUnguMkhululi wethu, sibonga wena.` },
  { id: 25, title: 'Zidalwa Zonke Zakhe', lyrics: `1 Zidalwa zonke zakhe,\nHlabelelani nathi,\nAleluya, Aleluya!\nLanga obus' emini,\nNenyanga yakusihlwa.\nNimbonge uJesu,\nAleluya! Aleluya! Aleluya!\n\n2 Wena, sivunguvungu,\nNawe, sibakabaka,\nNimbabaze, Aleluya!\nThokoza wena, kusa,\nNcincani, zinkanyezi,\nNimbonge uJesu,\nAleluya! Aleluya! Aleluya!\n\n3 Mifula echwazayo,\nGwabel' iNkosi yenu,\nAleluya, Aleluya!\nWe! mlilo ovuthayo,\nOfudumez' abantu,\nNimbonge uJesu,\nAleluya! Aleluya! Aleluya!\n\n4 We! mame ongummhlaba,\nOsivezel' ukudla,\nUmbabaze, Aleluya!\nZimbali nezithelo.\nVezan' udumo lwakhe,\nNimbonge uJesu.\nAleluya! Aleluya! Aleluya!\n\n5 Bongani, bantu nonke,\nEninomusa wakhe,\nHubanini, Aleluya!\nNibonge iNdodana,\nNoYise nay' uMoya,\nNimbonge, nimbonge,\nAleluya! Aleluya! Aleluya!` },
  { id: 26, title: 'Lomhlab\' UngokaBaba', lyrics: `1 Lomhlab' ungokaBaba,\nKuyezwakala kimi\nIhubo elivunywa\nIzinto zonke zakhe.\nLomhlab' ungokaBaba,\nIsandla sakhe sodwa\nEsiyenzi' imithi,\nNamatshe, nakho konke.\n\n2 Lomhlab' ungokaBaba,\nKubonga izinyoni,\nNokusa nezimbali,\nKubon' amandla akhe.\nLomhlab' ungokaBaba,\nUvezwa kahle ngawo,\nUmoy' ophephethayo\nUnjengelizwi lakhe.\n\n3 Lomhlab' ungokaBaba,\nMangingaKhohlwa neze\nUkuthi uyabusa,\nNokub' efihlwe kimi.\nLomhlab' ungokaBaba.\nPho ngingasab' intoni?\nKubus' iNkos' enkulu,\nKubong' umhlaba wonke.` },
  { id: 27, title: 'Obaba Bethu, Nkosi', lyrics: `1 Obaba bethu, Nkosi,\nBasizwa nguwe;\nSithemba kuwe nathi,\nUsivikele\n\n2 Ziningi izivungu,\nZisisongela;\nWosiphephisa kuzo\nNgengalo yakho.\n\n3 Wasitha abangcwele,\nBacasha ngawe,\nSebekhosel' ekhaya\nSisithe nathi.\n\n4 Kungakadalw' umhlaba,\nO Simakade\nUnguy' uNkulunkulu,\nNgenkathi yonke.\n\n5 Im' nyaka yaphakade\nIfana kuwe\nNemini yayizolo\nSekusa futhi.\n\n6 Kudlula isikhathi\nSinjengomfula,\nSibakhukhul' abantu,\nBakhohlakale.\n\n7 Obaba bethu, Nkosi,\nBasizwa nguwe,\nUsivikele nathi,\nSiyis' ekhaya.` },
  { id: 28, title: 'Bonganini-bo Mazulu', lyrics: `1 Bonganini-bo Mazulu,\nNezidalwa zenu,\nLanga, nawe wena nyanga,\nMubongen' uJehova,\nBong' iNkos' ekhulumile\nKwadaleka konke,\nNemithetho ayenzayo\nIniqondisa nonke.\n\n2 Bong' iNkosi yobukhosi,\nInqobil' ukona;\nLuph' udosi lwakho, Kufa?\nIsinqobisile nya.\nBong' iNkosi yosindiso,\nNiyitus' amandla,\nZulu, mhlaba, nakho konke,\nNiyidumise Yona.` },
  { id: 29, title: 'Masithokoze Ngayo', lyrics: `1 Masithokoze ngayo\nIm' thetho eyenziw' iNkosi;\nSithembe yona' singesabi,\nYenzelw' impilo yethu yonke.\n\n2 Ipheth' ulwandle yona\nNomoya nomhlabathi wonke,\nNenyanga naz' izinkanyezi,\nNehlobo nabo ubusika.\n\n3 Ibus' izulu lonke,\nImini nabo ubusuku,\nIlenza izwe libe-lihle\nKubantu bonke emhlabeni.\n\n4 Nathi siphiw' im' thetho\nEmihle nesizayo futhi\nYokusaz' intando yayo,\nSihambe ngayo sithuthuke.` },
  { id: 30, title: 'Yonke Into Enhle', lyrics: `1 Yonke into enhle\nIsenzo sakho, Nkos',\nNezimangalisa\nZenziwe nguwe, Nkos'\n\n2 Imbal' eqhakazayo,\nInyon' ehlabelela.\nNguwen' owenz' im'bala\nNamaphikwana azo.\n\n3 Intaba eluhlaza,\nUmful' ogobozayo,\nUkuhlwa nakh' ukusa\nOkubhejis' izulu:\n\n4 Umoya wobusika,\nNemfudumal' ehlobo,\nNokudla ensimini;\nNguwen' owakwenzayo.\n\n5 Imithi ehlathini\nNethafa lokudlala,\nUmhlanga emanzini\nSiwukha nsukuzonke;\n\n6 Namehlo nemilomo\nUkuba sibabaze\nSibonge uSomandla\nOwenze konke--kuhle.` },
  { id: 31, title: 'Umsa KaJehov\' Ubanzi', lyrics: `1 Umsa kaJehov' ubanzi\nNjengolwandle kithi,\nIzahlulo zakhe zinhle\nKunenkululeko.\n\n2 Izinsizi zalomhlaba\nZijabhis' izulu;\nAmaphutha asezweni\nAhlulelwa ngomsa.\n\n3 Ngob' uthando lukaThixo\nLuphakeme kithi;\nInhliziyo yoPhakade\nIyamangalisa.\n\n4 Nxa simthanda ngentobeko,\nNgasikholwa izwi\nKukhanyisw' impilo yethu\nIy' iNkosi yethu.` },
  { id: 32, title: 'Lizwe, Thokoza, Nans\' INkosi', lyrics: `1 Lizwe thokoza, nans' iNkos'!\nMayamukelwe du!\nMayibe-nokuhlala\nE'nhliziyweni zonke,\nKuhlatshelelwe kuyo\nEzulwini lonke;\nBonga, we mhlaba, ozayo.\n\n2 Nang' uMsindisi wezwe,\nWobusa njalo la.\nKabongwe ngezemvelo,\nLanga nenkanyezi,\nAbongwe ngentokozo\nYizidalwa zonke.\nYek' injabulo enkulu bo!\n\n3 Konke okon' abantu\nSekuyophela nya!\nUkhula ensimini\nNosizi enhliziyweni\nSelwahluliwe nguye\nOsibusisayo.\nYek' intokozo ngeyethu!\n\n4 Obusa ezulwini\nYilo oseze la!\nUbusa ngeqiniso,\nAphathe ngokulunga,\nAzenze zonk' izizwe\nZimangale ngalo\nUthando lwakhe, uKristu.` },
  { id: 33, title: 'Namhla Siyahlabelela', lyrics: `1 Namhla siyahlabelela,\nSinegam' elihle;\nSiyambonga onamandla,\nOyiNkosi yethu.\n\nWe, bakithi, bonganini\nObatshazw' izingelosi;\nBonganini oyiNkos',\nYen' unguMsindisi.\n\n2 UMsindisi ufikile,\nKade ebhekiwe,\nOwabusa ezulwini\nUze ebantwini.\n\n3 Weza lapha engumntwana,\nWayesemkhombeni;\nWathabath' ubuntu bethu,\nWazithoba yena.\n\n4 Masimbonge oyingcwele!\nNonke nisondele!\nVumanini, nimdumise!\nMasimtusisise!` },
  { id: 34, title: 'Yizwa Ingelosi Ithi', lyrics: `1 Yizwa ingelosi ithi;\nMakubongw' iNkosi,\nUkuthula nomsa kithi,\nUsindil' umhlaba.\nVukanini zizwe zonke,\nVumanin' nabaphezulu,\nYishonini ne' ngelos',\nUzelwe eBethlehem.\n\n2 He, iNkosi yokuthula\nNakho ukulunga,\nIfikile nokuphila,\nIpheth' ukulunga;\nNgasigwaba nengelosi,\nMakubongw' iNkosi entsha,\nKuhle, kuhle emhlabeni,\nUfikil' uKristu.` },
  { id: 35, title: 'Ebusuku Abalusi', lyrics: `1 Ebusuku abalusi\nBezalus' izimvu,\nKwabazuma ukukhanya\nOkwabehaqayo;\nYeza kubo ingelosi,\nYehl' ivela ezulwini,\nYathi kubo, "Ningesabi\nNginendaba enhle."\n\n2 Sengivela eNkosini,\nNgize 'kunitshela\nIzwi lokuthokozisa\nBonke emhlabeni;\nNgoba sekuzelwe namhla\nUMsindis' iNkos' uKristu,\nEzobusa njalonjalo\nAbasindisiwe.\n\n3 Usendlini yezinkomo,\nLaph' ezelwe khona;\nOyiNkosi yakho konke\nKungath' akananto.\n\n4 Lahubela abalusi\nLelihub' elihle:\nUkuthula emhlabeni,\nBethandan' abantu.\nKadunyiswe njalo\nOyiNkosi emakade.` },
  { id: 36, title: 'Yizwanini Izw\' Elihle', lyrics: `1 Yizwanini izw' elihle\nElivela kophezulu;\nIzwi elahlatshelelwa\nIngelosi khon' endulo;\nIzwi elamemezela\nUkuzalwa koMsindisi.\n\n2 Yath' ifika ingelosi\nKubalusi ebusuku,\nYathi, "Ningesabi;\nNgilethel' izindaba\nZosindiso sabantu."\n\n3 Bhekanini, sekuzelwe\nUMesiya, uMsindisi,\nNizombona elele\nEmkhombeni wezinkomo,\nKhon' emzini kaDavide.\n\n4 Akube kuThixo wethu\nUbukhosi nobukhosi,\nNakinina emhlabeni\nUkuthula nothando.\n\n5 Yizwanini, zizwe nonke,\nUfikile uMsindisi;\nSheshanini nimamkele\nNimdumise ngenjabulo.` },
  { id: 37, title: 'Lalelan\' Izingelosi', lyrics: `1 Lalelan' izingelosi\nZisho ngaphezulu,\nZiyahlabelel' iNkosi,\nYon' iNkos' enkulu.\nMadunyiswe uMsindisi,\nYen' ungobusayo.\n\n2 Ukuthula emhlabeni,\nKul' elakhiweyo;\nKwabasindisiwe bonke\nNgokufika kukaJesu.\n\n3 Nani, bantu, phuthumani\nNililandele izwi;\nLidumiseni izizwe\nNgokuzalwa kwakhe.` },
  { id: 38, title: 'Njengabantu Ababona', lyrics: `1 Njengabantu ababona\nInkanyezi leyo,\nBelandela yona njalo\nLapho yayakhona,\nNathi siyakulandela\nMkhanyiseli wethu.\n\n2 Njengalokhu bathokoza\nBefuman' iNkosi,\nBekhuleka kulomntwana\nOyingcwele-ngcwele;\nNathi masifune yena,\nMasiguqe kuye.\n\n3 Njengalokhu bamdumisa\nNgamagugu abo,\nNathi masilethe kuye\nNgenhliziyo yethu.\n\n4 Jesu, ngezinsuku zonke\nMasifuze wena\nSize sifinyelele\nEmbuso wakho.` },
  { id: 39, title: 'Huba, Huba, Namhla', lyrics: `1 Huba, huba, namhla,\nKuzelwe uMsindisi,\nBikelan' izizwe,\nNang' uMthabisi.\nHuba, huba, huba,\nIzizwe mazikuzwe.\n\n2 Huba, huba, kahle,\nHubis' okwengelosi,\nUthando nokuthula\nKuvela kophezulu.\n\n3 Huba, huba, namhla,\nYizwa ukudlala\nOkwensindiso enkulu\nKubantu bonke.` },
  { id: 40, title: 'Kwath\' Ebusuku Abalusi Bezalus\'', lyrics: `1 Kwath' ebusuku abalusi bezalus' izimvu,\nYehlela kubo ingelos' ikhanya njengelanga,\nYathi, "Ningesabi, ngize nginendaba,"\nManijabule nabo bonke abezwayo.\n\n2 EBethlehema usezelwe namhla uMsindisi,\nUKristu yena oyiNkos', inzalo kaDavide;\nNiyombona elele emkhombeni wezinkomo.\n\n3 Izingelosi zahlangana zithi ngazwi linye,\nUNkulunkulu kadunyiswe,\nUkuthula emhlabeni kubantu abasindisiwe.` }, 
  { id: 41, title: 'UMkhululi Wethu', lyrics: `1 UMkhululi wethu\nUfikile kithi;\nInhliziyo yethu\nMayethabe ithi,\nUMkhululi ufikile,\nUMkhululi sesimzwile.\n\n2 Sonke masethabe\nEbusweni bakhe;\nSibuyele kuye,\nNgokubiza kwakhe:\nUMkhululi ufikile,\nUMkhululi sesimzwile.\n\n3 Siyafunwa uye,\nUMkhululi wethu;\nNgaye asethabe,\nNgenhliziyo yethu;\nUMkhululi ufikile,\nUMkhululi sesimzwile.\n\n4 Futhi usitshela\nNgobubele bakhe;\nUyasibizela\nEzulwini lakhe:\nUMkhululi ufikile,\nUMkhululi sesimzwile.` },
  { id: 42, title: 'Dumisani, Bantu Nonke', lyrics: `1 Dumisani, bantu nonke!\nZimdumis' izinto zonke!\nNamhla ngumhla wendumiso,\nNamhla ngumhla wentabiso:\n\n2 Umkhululi usezelwe,\nUbusiso lwehlisiwe;\nNamhla ububele bukho,\nNamhla insindiso ikho.\n\n3 Akezanga ngal' ushaba;\nHambisani lezindaba:\nUze kithi ngobubele,\nUze yena ukusifela.\n\n4 Hambisani lezindaba,\nZiye kuwo wonk' umhlaba.\nBonganini, bantu, nonke!\nZiyabong' izinto zonke.` },
  { id: 43, title: 'Zingelosi Enahuba', lyrics: `1 Zingelosi enahuba\nSekudalw' umhlaba,\nMemezani ngentokozo\nSekuzelw' uKristu;\nNimdumise, nimdumise,\nYen' ozelwe namhla.\n\n2 Nina enalus' izimvu,\nSekuhlwile lapho,\nNakho ukukhany' okuhle,\nSihanjelw' uThixo;\nNimdumise, nimdumise\nYen' ozelwe namhla.\n\n3 Nina zazi, vukanini\nNiyifun' iNkosi,\nYon' iNkosi yokuthula,\nNansi inkanyezi;\nNimdumise, nimdumise\nYen' ozelwe namhla.\n\n4 Nin' ekade senihlezi,\nNilindel' iNkosi,\nIzokwehla, inizume\nKhon' endlini yayo;\nNimdumise, nimdumise\nYen' ozelwe namhla.` },
  { id: 44, title: 'Yizanini Nonke', lyrics: `1 Yizanini nonke, ngentokoz' enkulu,\nYizani emzini waseBethlehem,\nNibone iNkosi, yona ezelweyo,\nNiyidumise,\nNiyidumise,\nNiyidumise\nINkosi.\n\n2 Nina, zingelosi hubanini nonke,\nNebandla lalapho ezulwini,\nAkube-ku Yise ubukhosi bonke,\nNiyidumise,\nNiyidumise,\nNiyidumise\nINkosi.\n\n3 Sikuthakazela, wen' ozelwe namhla,\nUdumo ngolwakho, Jesu, njalo;\nULizwi kaThixo, oze emhlabeni,\nNiyidumise,\nNiyidumise,\nNiyidumise\nINkosi.` },
  { id: 45, title: 'Umuzi Wase Bethlehem', lyrics: `1 Umuzi waseBethlehem\nUthule, uthe du,\nKulelwe ubuthongo,\nZinhle izinkanyezi;\nKanti emigwaqweni\nyomuz' omncane lo\nUbhaqa lwaphakade\nLukhanya namhla.\n\n2 Kuzelw' uKristu Jesu,\nBelel' abantu,\nKulind' umntwana;\nE, nina zingelosi,\nNimhalalise:\nHozana kweliphezulu,\nNasemhlabeni.\n\n3 Savela ngokuthula\nIsipho leso,\nKufika uMsindisi\nKanjalo kithi;\nUfik' angena kithi,\nUma simvumela,\nKuphel' izono zethu\nNgamandla akhe.\n\n4 O Mntwana waseBethlehem,\nYehlela kithi,\nUngen' ukhiph izono,\nUzalwe kithi;\nSizizw' izingelosi\nZikumemezela.\nO, ngen' uhlale nathi,\nOnguEmmanuwel.` },
  { id: 46, title: 'Makholwa Thokozani', lyrics: `1 Makholwa, thokozani\nNgephimbo nomphefumlo,\nYizwanin' ilizwi;\nUMsindis' uzelwe,\nZiguqil' imfuyo,\nUsemkhombeni wazo,\nUsezelwe namhla,\nUsezelwe la.\n\n2 Makholwa, thokozani\nNgephimbo nomphefumlo\nSekukhon' uthabo,\nWazalelwa lona,\nUvulil' izulu,\nAbantu babusisiwe;\nWazalelwa lokho,\nUsezelwe la.\n\n3 Makholwa, thokozani\nNgephimbo nomphefumlo\nSekuphel' uvalo,\nUzonqob' ukufa,\nUnibiza nonke\nNihlale naye njalo;\nWazalelwa lokho,\nUsezelwe la.` },
  { id: 47, title: 'Nxa INkosi Yethu\' UJesu', lyrics: `1 Nxa iNkosi yeth' uJesu\nIsahamba emhlabeni,\nYaya ekusithekeni,\nIye ekuthandazeni.\n\n2 Yayivuka ekuseni,\nKhona nasebumnyameni,\nIye khona entabeni,\nIye ekuthandazeni.\n\n3 Nami, khon' ezinsukwini,\nNgiyakuya eNkosini;\nNxa ngivuka ekuseni\nNgiye ekuthandazeni.\n\n4 Ngingakay' ekulaleni,\nNgiyakuba endaweni\nEthandeka enhliz' yweni,\nNgiye ekuthandazeni.\n\n5 Ngiyohamba endleleni\nEqondayo eNkosini,\nEholela ebomini;\nYongiyisa ezulwini.` },
  { id: 48, title: 'Ingalo Yakho Kwezendulo', lyrics: `1 Ingalo yakho kwezendulo\nYayinamandl' okuphilisa;\nYaqob' izifo nobumnyama,\nYaze yanqoba zonk' izifo.\n\n2 Izimpumputhe nezithulu\nZafika kuwe nezinyonga,\nUmlepheri ompilo embi,\nNemizimba ebuthakathaka.\n\n3 Kwath' ekubaphatheni kwakho,\nBabona bakhuluma futhi,\nBenziwa basha bathanjiswa,\nBabonga bakwamkela, Nkosi.\n\n4 Manje sondela ubusise, Nkos',\nNgamandla akho akudala,\nEzindlelen' ezicinene,\nNjengokwenziwa eGenesaret.\n\n5 Ban' umkhululi wethu njalo,\nWena, O Nkos' enokuphila;\nPhilis' uvuse ubusise,\nNgoMoya wakho onamandla.\n\n6 Izandla ezisebenzayo\nZinike yonk' imithetho yakho,\nOsephilile nogulawo\nBakudumise wena njalo.` },
  { id: 49, title: 'Ubani Lo Osemkhombeni', lyrics: `1 Ubani lo osemkhombeni,\nAbalusi bayamkhonza?\nUyiNkosi yal' izulu,\nUyiNkosi yaw' umhlaba,\nMasiguq' ezinyaweni\nSithi, Nkosi yamakhosi!\n\n2 Ubani lo ososizini,\nOzilayo esehlane?\n\n3 Ubani lo okhala khona\nKuLazaro elibeni?\n\n4 Ubani lo okhulekayo\nEnsimin' eGetsemane?\n\n5 Ubani lo obethelweyo\nEnxusel' ababulali?\n\n6 Ubani lo oselibeni\nOsengath' usahluliwe?\n\n7 Ubani lo osephumile;\nOngebanjwe, enqobile?\n\n8 Ubani lo owenyukele?\nBheka ifu limamkele!\n\n9 Ubani lo osezulwini,\nOnxusel' abantu bakhe?\n\n10 Ubani lo oyakubuya\nNobukhosi naw' amandla?` },
  { id: 50, title: 'Udumo Nenhlonipho', lyrics: `1 Udumo lenhlonipho\nKuy' uMkhululi;\nKuyena ozingane\nZamhalalisa.\nAbantu bakwaJuda\nBendlal' isundu,\nNezindumiso zakho\nZiphambi kwakho.\n\n2 Unguye uMesiya,\nUngokaDavide,\nOzayo ngal' igama\nLeNkos' engcwele.\nKwath' ungakabethelwa,\nBakudumisa;\nKuwe osuphakeme\nSihlabelela.\n\n3 Iviyo laphezulu\nLikudumisa,\nNabantu nezinto zonke\nZivuma kanye,\nUdumo nenhlonipho\nKuy' uMkhululi;\nKuyena ozingane\nZamhalalisa.` },
  { id: 51, title: 'Khangel\' UMsindisi Wethu', lyrics: `1 Khangel' uMsindisi wethu\nEbethelw' emthini;\nHayi, uthando olungaka,\nNgokufel' aboni!\n\nHayi, iMvana eyophayo\nYahlatshelwa thina;\nHayi, uMmeli wabonayo\nWasimela thina.\n\n2 Yizwa ethi, "Thethelela\nLabababulali;\nAbakwazi lokhu, Baba,\nAbakwenza kimi."\n\n3 Wasekhala, Thixo wami,\nUngishiyeleni?\nWagebis' ikhanda lakhe,\nWafa ngenxa yethu.\n\n4 Wasuzamazam' umhlaba\nEkufeni kwakhe;\nIlanga lafihlakala;\nAqhephuk' amatshe.\n\n5 Bhek' icala lihlawulwe\nNgobuhlungu bakhe,\nNakithina uzwakele\nLowomusa wakhe.` },
  { id: 52, title: 'Kukhon\' Intaba Engaphandle', lyrics: `1 Kukhon' intaba engaphandle kweJerusalema;\nINkosi yethu yafa khon' ukuze sisindiswe.\nThin' asinakho ukuyazi inhlupheko yayo;\nSikholw' ukuthi yabethelwa, yafa ngenxa yethu.\n\n2 Yathand' ukuba sifumane ukuthethelelwa,\nSilunge siye ezulwini; ngakho yasophela.\nOmunye wayengekho wokuhlawulel' abantu,\nUJesu yedwa wafa nokusivulel' izulu.\n\n3 O, wasithanda, wasithanda, nathi masimthande!\nSethemb' igazi lakhe, sihambis' okwakhe njalo.\nKukhon' intaba engaphandle kweJerusalema,\nINkosi yethu yafa khon' ukuze sisindiswe.` },
  { id: 53, title: 'Ngibheka Esiphambanweni', lyrics: `1 Ngibheka esiphambanweni,\nNgibon' iNkosi yobukhosi;\nKuyize yonk' imfuyo yami,\nNginengwa nokuzindla kwami.\n\n2 Ukufa koMkhululi wami,\nYikhona okubonga kwami;\nNgenxa yeNkos' zikude kimi\nLezinto ezathandwa yimi.\n\n3 Sengizibon' ezinyaweni\nIzipikil', nasezandleni;\nNgimangaliswa enhliz' yweni,\nNgibon' uthando olunjena.\n\n4 Uma nginawo wonk' umhlaba,\nUngaba umnikel' omncane;\nNgothando lwakhe olungaka,\nNgimnik' uJesu uqobo lwami.` },
  { id: 54, title: 'Wazithwal\' Izono, Jesu', lyrics: `1 Wazithwal' izono, Jesu,\nZinge' zono zakho;\nWahlawul' icala, Jesu,\nLinge' cala lakho.\n\n2 Wab' umuntu onosizi,\nUngonanga wena;\nLaphalal' igazi lakho,\nUlungile wena.\n\n3 Lezo ezabalwa kuwe\nZaz' izono zethu;\nLel' elahlawulwa uwe\nLalicala lethu.\n\n4 Sekukhon' ukuyekelwa\nNgobuhlungu bakho;\nZonk' izono zingahlanzwa\nEgazini lakho.` },
  { id: 55, title: 'Nxa Ngimbona UMsindisi', lyrics: `1 Nxa ngimbona uMsindisi\nEfa esiphambanweni,\nNgiyilahla yonk' imfuyo,\nNakho ukuzindla kwami.\n\n2 Ngingephikelele lutho\nOluphambeneyo naye;\nKonke engikuthandayo\nNgikudela ngenxa yakhe.\n\n3 O, bhekan' inhloko yakhe,\nLezozandla nezinyawo!\nYek' uthando, yek' usizi,\nOlukhulu olungaka!\n\n4 Ngingayisa ntoni kuye\nEfanele ukumbonga?\nAnginakho okwanele,\nNgiyamnik' uqobo lwami.` },
  { id: 56, title: 'Namhla Uvukile', lyrics: `1 Namhla uvukile, Aleluya!\nNamhla uphumile, Aleluya!\nNamhla unqobile, Aleluya!\nUMkhululi wethu, Aleluya!\n\n2 Nansi insindiso, Aleluya!\nNanti iqiniso, Aleluya!\nNayo impiliso, Aleluya!\nAsiphayo yona, Aleluya!\n\n3 Ngokuzalwa kwakhe, Aleluya!\nNangokufa kwakhe, Aleluya!\nNokuvuka kwakhe, Aleluya!\nThina saphiliswa, Aleluya!\n\n4 Yizwa, mhlaba wonke, Aleluya!\nVuma, muntu wonke, Aleluya!\nZish' izinto zonke, Aleluya!\nUyiNkos' enkulu, Aleluya!` },
  { id: 57, title: 'Kwaphel\' Ukulwa Nempi', lyrics: `1 Aleluya, Aleluya, Aleluya!\nKwaphel' ukulwa nempi;\nSek' ukuphila kithi;\nMasilivume sithi, Aleluya!\n\n2 Ukufa kuphelile,\nUKristu wahlulile,\nVumani, nisindile, Aleluya.\n\n3 Zintathu ubefile,\nUvuke ephilile,\nKonke sekuvumile, Aleluya.\n\n4 Aqhuma amaliba,\nAmademon' ethuka,\nSihuba siyagwaba, Aleluya.\n\n5 Ngemivimbo saphiliswa,\nIzimvu zasindiswa,\nNgabantu wodunyiswa, Aleluya.` },
  { id: 58, title: 'Usaphil\' UJesu Manje', lyrics: `1 Usaphil' uJesu manje;\nAwusesabeki, Kufa!\nUsaphil' uJesu manje;\nAwusenamandla, thuna!\nAleluya!\n\n2 Usaphil' uJesu manje;\nUsephume kuwe, thuna!\nNawe, Kufa, ungumnyango\nWokungena ebomini!\nAleluya!\n\n3 Usaphil' uJesu manje;\nWafa kanye ngenxa yethu;\nAsimphileleke njalo,\nSimdumise ngokulunga.\nAleluya!\n\n4 Usaphil' uJesu manje;\nAsisahlukani naye;\nSisaphila noma sifa,\nUsilondoloza njalo.\nAleluya!\n\n5 Usaphil' uJesu manje;\nUyabusa kukho konke;\nSiya kuye siphumule,\nNokubusa naye njalo.\nAleluya!` },
  { id: 59, title: 'Uvukil\' UJesu Namhla', lyrics: `1 Uvukil' uJesu namhla, Aleluya!\nUsesinqobele thina, Aleluya!\nWafa kanye ngenxa yethu!\nAleluya!\nUsihlawulele njalo, Aleluya!\n\n2 Asibonge kuye njalo, Aleluya!\nOyiNkosi yaphakade, Aleluya!\nWahluphek' onqamlezweni,\nAleluya!\nWangeniswa ethuneni, Aleluya!\n\n3 Kodwa ahlupheka ngakho, Aleluya!\nSekusizuzel' ubomi, Aleluya!\nUyiNkosi ye' ngelosi, Aleluya!\nEzimbonga njalo, zithi Aleluya!` },
  { id: 60, title: 'Uphilile UMsindisi', lyrics: `1 Uphilile uMsindisi,\nUphilile yena;\nSijabula thina zoni,\nUphilile yena.\n\n2 Kad' efile uMsindisi,\nKad' efile yena;\nWabulawa ngenxa yethu,\nWabulawa yena.\n\n3 Wenyukela ezulwini,\nWenyukela yena;\nUyathandazela thina,\nUthandaza yena.\n\n4 Uyabusa uMkhululi,\nUbusela thina;\nSisindiswe ezonweni,\nSisindile thina.` },
  { id: 61, title: 'Uvukil\' UJesu Ethuneni Lakhe', lyrics: `1 Uvukil' uJesu\nEthuneni lakhe;\nWakwahlul' ukufa\nNgokuvuka kwakhe;\nAbalindi banyakaza,\nBawa phansi ngokwesaba.\n\n2 Nina, bantu, nonke\nManihlabelele,\nNithokoze ngaye\nOsihlawulele!\nUphumile ethuneni,\nUbuyele embusweni.\n\n3 Wena, Nkosi yethu!\nThin' abantu bakho\nUyasisindisa\nNgaw' amandla akho,\nKanye nawe sizovuswa,\nKanye nawe sizobusa,` },
  { id: 62, title: 'Usuku Lokuvuka', lyrics: `1 Usuku lokuvuka!\nLumemezele;\nIPasika lothabo\nLikaSomandla\nUKrist' usiwezile,\nSisuka ekufeni,\nSathola ukuphila\nOkuphakade.\n\n2 Masihlanzeke kahle,\nSibone njalo\nINkos' evukileyo,\nEkukhanyeni;\nSilizw' iphimbo layo,\nSelisibingelela.\nSisheshe sisabele,\nSihalalise.\n\n3 Malithokoz' izulu,\nUvum' umhlaba,\nIlizwe lenz' umkhosi.\nKonk' okukulo;\nKuvume izidalwa,\nNazon' ezingababonwa,\nMazithi, \"Ivukile\nINkosi yethu.\"` },
  { id: 63, title: 'Uvukil\' UJesu', lyrics: `1 Uvukil' uJesu, waphuma ethuneni;\nUnqobil' ukufa. Bafika, ekuseni,\nItshe ligingqiwe! Unqobile,\nAleluya!\n\n2 Makabongw' uJesu wanqoba khon' ukufa\nBabazan' uJesu, unobukhosi, yedwa;\nMasiguqe kuye, sicule, sith'\nAleluya!\n\n3 Lwandisen' udumo ezindaweni zonke,\nHubani kakhulu, uvukil' uMsindisi\nNathi, masivuke, simbabaze,\nAleluya!\n\n4 Thokozani nonke, isivukil' iNkosi;\nVukani zihlobo, siyilandel' iNkosi,\nYosiyis' ekhaya isivukil',\nAleluya!` },
  { id: 64, title: 'Zasho Izingubu', lyrics: `1 Zasho izingubu,\nFuthi nengelosi,\n\"Vula iminyango,\nKuvulelw' iNkosi.\"\nKristu onothando,\nJesu onomusa,\nWakhuphuka wena,\nNgena; uzobusa.\nUmsebenze wakhe,\nBheka; uphelile;\nManje wenyukile,\nBheka; usizile.\n\n2 Wez' ukusisiza,\nWopha; wasifela;\nManje umisiwe;\nUyiNkos' impela,\nPhinde ahlupheke,\nPhinde asifele,\nYena, onodumo,\nUsekhuphukile.\nUyasikhalela,\nEndawen' engcwele,\nUyosiph' okuhle,\n'Moya oyingcwele,\nUyakhomba nendlu\nYokuhlala khona,\nSizohlala njalo\nNay' uJesu kuyo.` },
  { id: 65, title: 'UngokaJehov\' Umhlaba', lyrics: `1 UngokaJehov' umhlaba\nNokugcwala konke kwawo,\nIzwe nabahlezi kulo;\nUmi ngaphezulu\nKwezilwandle nemisinga;\nUngubani ongakhuphuka,\nOngahlala noJehova\nEntaben' engcwele?\n\n2 Onezandla ezimhlophe,\nOnhliziyo igeziwe;\nOngazang' aqamb' okubi,\nOngafung' amanga.\nUJehova wombusisa,\nNgokulunga womsindisa:\nYiso isizukulwane\nEsimusingayo.\n\n3 Amasango aphakame,\nNeminyango yaphakade;\nKuyongen' iNkosi enhle,\nIngubani yona?\nUJehova onamandla,\nUliqhawe uJehova.\nUliqhawe, ulwa impi,\nYena uliqhawe.\n\n4 Amasango aphakame,\nNeminyango yaphakade;\nMaziphakamis' inhloko,\nKungenis' iNkosi.\nYona enenkazimulo,\nIngubani iNkosi enhle?\nUJehova wamabandla\nUyiNkosi enhle.` },
  { id: 66, title: 'Bhekanini, Nang\' uMnqobi', lyrics: `1 Bhekani, nang' uMnqobi\nEsamkelw' amafu.\nIsiqumbi se' ngelosi\nSiyahlabelela.\nAmasango aphakeme,\nKungenisw' iNkosi.\n\n2 Oza ngobukhos' ubani?\nUyiNkosi yethu.\nWaphanyekwa wahlupheka,\nKonke wakwahlula,\nEkufeni wasenqoba\nZonk' izitha zakhe.\n\n3 Wenyusel' ubuntu bethu\nEzulwini naye;\nIsihlalo sobukhosi\nSekuhleli kuso\nOngumuntu enguThixo.\nUyobusa njalo.\n\n4 Moy' oNgcwele, Mkhanyiseli,\nSikhanyise thina,\nSifuzise uStefano.\nSilibhek' izulu,\nSiyibone iNdodana\nIbasiz' abayo.\n\n5 Sibe- nokumbona Yena\nOsesandulele;\nOsikhulekela njalo\nLapho ezulwini;\nOzakwahlulela izwe\nEza emafwini.\n\n6 Senyusele ngaphezulu,\nNgamaphikw' enkolo,\nImiqondo ne' nhliziyo,\nUzikhuphulele\nKoyiNkosi yobukhosi,\nYen' uJesu Kristu.` },
  { id: 67, title: 'Ngosuku Lokwenyuka', lyrics: `1 Ngosuku lokwenyuka\nSibong' uNkulunkulu\nNgeNkosi yeth' uJesu,\nEngena ezulwini.\n\n2 Wayezithobisile\nNgokuza kwakhe kithi,\nWafel' izono zethu\nUkuba asihlenge.\n\n3 Wavuka alibeni\nEbonakala futhi,\nWabafundis' abantu\nNgebandka elingcwele.\n\n4 Kwath' ub' eseqedile,\nWenyuk' enobukhosi,\nIzulu lavuleka,\nWangena enguMnqobi.\n\n5 Uhlez' ebukhosini,\nUkhonzw' izingelosi,\nNokho uyabamela\nabantu bakhe bonke.\n\n6 Masimlandele njalo,\nSilapha emhlabeni.\nUkuba ezulwini\nSihlale njalo kuye.` },
  { id: 68, title: 'Ujesu Usevukile', lyrics: `1 Ujesu usevukile,\nUngulibo lwabalele;\nLuph' udosi lwakho, Kufa\nNokunqoba kwakho, liba?\nNangu usekhuphukile!\nMvuleleni, O masango!\nOngenayo uyiNkosi\nEliqhawe, edumile.\n\n2 Bhek' izandla, nezinyawo,\nBhek' ibunzi, nohlangothi!\nWahlaselw' izitha zakhe,\nWazahlula ekulweni\nDedanini, zingelosi!\nKhothamani phambi kwakhe!\nYena uyiNkosi yenu,\nUmisiwe phezu kwenu.\n\n3 Bandla lakhe emhlabeni,\nHubanin' udumo lwakhe!\nWeha yena, wanilwela,\nNibe-nokuphila ngaye:\nWenyukele ezulwini,\nUnimele nina lapho,\nUnilungisel' indawo,\nBandla! khonzanin' iNkosi.` },
  { id: 69, title: 'Bhekani Bangcwele', lyrics: `1 Bhekani, bangcwele: uJesu okad' ehlushiwe,\nNguyena obuy' ekulweni ahlule;\nnimtuse!\nQhelisani iNkosi, qhelisani iNkosi,\nQhelisani iNkosi, esiyukele phezulu.\n\n2 Esesemhlabeni wagqoka\numqhele wameva;\nOnqatshwe ngababi ngosini nosulu\nbemhleka.\n\n3 Uthixo, uYise, way' ngeke\namshiy' elibeni,\nWamvusake; eseboniwe ngabanye,\nwenyuka.\n\n4 Guqani, madolo abantu basezweni lonke,\nNwezingelosi zezulu;\nyiNkosi enkulu.\n\n5 Vumani, bangcwele enethembekile kuJesu;\nUdumo ngolwakhe, obusa\nphakade, atuswe.` },
  { id: 70, title: 'Bheka, Mphefumulo Wami', lyrics: `1 Bheka, mphefumulo wami,\nNang' uMprist' omkhulu!\nEkumela endaweni\nEyingcwele-ngcwele.\nNanka amacons' egazi\nAfafazwe nguye,\nAligaz' elihle lelo\nLokuhlawulela.\n\n2 Yek' ubuhle bukaKristu\nOnguMprist' omkhulu!\nOwambethe ubungcwele\nNjengengubo enhle.\nBheka law' amatsh' amahle\nAqoshiwe kuwo\nAmagama onke abo\nAbamelwa nguye.\n\n3 Yizwa, mphefumulo wami,\nNans' imphepho enhle!\nIliphunga elimnandi\nLukukunxusela.\nBheka lowoMprist' omkhulu\nEncengela wena.\nYisho, kugenzeka yini\nUba ulahleke?\n\n4 Sula i' nyembezi zakho\nMpefumulo wami,\nYima isisbindi ngaye\nOnguMprist' omkhulu;\nNoma nxa lidlul' izulu\nUfe naw' umhlaba,\nakasoze alahleka\nYen' omelwa nguye.` },
  { id: 71, title: 'Malusi Onamandla', lyrics: `1 Malusi onamandla,\nOhlezi ezulwini,\nUsizwe ngomsa wakho,\nSisekuthandazeni;\nZilind' izimvu zakho,\nZinik' amandla akho,\nZiholel' endleleni\nEbheka ezulwini.\n\n2 Malusi olungile,\nMasizwe izwi lakho,\nUsikhmbis' indlela,\nSihambe emva kwakho;\nSibheke emhlambini,\nSigcin' esibayeni;\nUma silahlekela\nSifun' ungasideli.\n\n3 Holela edlelweni\nElifanel' ezakho,\nSiyise emanzini\nAnokuphila kwakho;\nSikhiphe osizini,\nVikela empisini,\nSondela nxa kumnyama,\nSehlelwa ukwesaba.\n\n4 Malusi, Musindisi,\nOthand' abantu bakho;\nSize ukukubonga,\nNgokusigcina kwakho;\nMasizwe izwi lakho,\nSinak' intando yakho,\nSilande emhlabeni,\nSamkelwe ezulwini.` },
  { id: 72, title: 'O Malus\' Olungileyo', lyrics: `1 O Malus' olungileyo,\nUnezimvu zakho;\nO Malus' olungileyo,\nNamachwane akho.\n\n2 Ziyalizwa izwi lakho,\nLezizimvu zakho;\nZilandela wena, Jesu\nZiyalaz' elakho.\n\n3 Izwi lomalus' omubi\nazilazi lona;\nAzivum' ukumlandela,\nZimesaba zona.\n\n4 Ziyalondwa uwe, Jesu,\nLezozimvu zakho;\nKungesuswe nanye yazo\nEsandleni sakho.` },
  { id: 73, title: 'Umsindisi Usahlezi', lyrics: `1 UMsindis usahlezi,\nUkuYise ezulwini;\nYen' uyasilamulela,\nEsihlanza egazini.\n\n2 Selikhulu lon' icala,\nSisenokwesaba ngalo;\nKanti yena ulithwele,\nUsenzela ukulunga.\n\n3 Mthetheleli ophezulu,\nMhlobo wethu onamandla!\nMasithembe kuwe wedwa,\nEzonweni wosihlenga.` },
  { id: 74, title: 'Uphi Umhlobo Onjengo Jesu?', lyrics: `1 Uphi umhlobo onjengoJesu?\nKakho,qha; kakho, qha.\nOngaphilisa izifo zethu?\nKakho, qha; kakho, qha.\n\nUyazaz' izinsizi zethu,\nNgaye ziyakuphela nya.\nUphi umhlobo onjengoJesu?\nKakho, qha; kakho, qha.\n\n2 Kakh' onjengaye nangobungcwele,\nKakho, qha; kakho, qha;\nNozithobisa okwakh' impela,\nKakho, qha; kakho, qha.\n\n3 Ngeke amshiye omethembayo,\nKakho, qha; kakho, qha;\nNgek' amalele nophendukayo,\nKakho, qha; kakho, qha;\n\n4 Kakho omunye osindisayo,\nKakho, qha;kakho, qha;\nNasezulwini osamkelayo,\nKakho, qha; kakho, qha;` },
  { id: 75, title: 'Sinomhlobo OnguJesu', lyrics: `1 Sinomhlobo onguJesu,\nUnothando;\nAkanjengeminy' im' hlobo,\nUnothando;\nAkanayo injabiso,\nAkanayo inkohliso,\nUyasiza ngeqiniso;\nUnothando.\n\n2 Ungumhlobo weth' uJesu\nUnothando;\nakadel' abantu bakhe,\nUnothando;\nUbahola endleleni,\nUbagcina engozini,\nUbakhipha osizini;\nUnothando.\n\n3 Sezomuka emhlabeni,\nWabathanda;\nSeyekhona ezulwini,\nUbathanda;\nUbalungisela khona,\nUyabahlalela bona,\nWobamkela bonke khona,\nNgal' uthando.\n\n4 Nina niyamdinga yini?\nUnothando,\nKade nihlupheka yini?\nUnothando.\nKungezono zenu yini?\nEnilahlwa ngazo yini?\nWonikhipha kuzo yena;\nUnothando.\n\n5 Loluthando, hawu, lukhulu,\nSiyabona;\nMasimthande 'he kakhulu,\nOsithanda,\nNgalo masihambe sonke;\nNgalo sokwahlula konke;\nLuyadlul' olunye lonk,\nLoluthando.` },
  { id: 76, title: 'Ungumhlobo Weth\' uJesu', lyrics: `1 Ungumhlobo weth' uJesu,\nUzithwala izinsizi,\nKuye singaletha konke,\nKonke ngomthandazo wethu,\nAsinakho ukuthula,\nNezinsizi zisihlupha,\nUma singayisi kuye\nKonke ngomthandazo wethu.\n\n2 Nxa silngwa sihlupheka,\nSizwa ubunzima njalo,\nAkudingi sidangale,\nSiye kuye ngomthandazo.\nUngumhlob' othembekayo,\nIzinsizi wozithwala,\nUyabaz' ubuntu bethu,\nSiye ngomthandazo.\n\n3 Uma sinomthwal' onzima,\nSigcwel' ukukhathazeka,\nJesu, Nkosi, uyinqaba,\nSiye kuwe ngomthandazo.\nNxa sizondwa singathandwa,\nMasihambe siye kuye,\nWosigon' ezingalweni,\nSifumane ukuthula.` },
  { id: 77, title: 'Umhlobo Ngimtholile', lyrics: `1 Umhlobo ngimtholile,\nUmhlob' omkhul' impela,\nOwathi ngingamazi\nWangisondeza kuye.\nZingebe zisaqaqwa zon'\nI'ntambo zaluthando;\nSengingowakhe, ungowam'\nPhakade naphakade.\n\n2 Umhlobo ngimtholile,\nUmhlob' owangifela,\nWangipha ukuphila\nNgokuzidela kwakhe,\nKungakho enginakho la\nNgikuphathele Yena,\nUmzimba nomphefumlo wam'\nNgokwakhe naphakade.\n\n3 Umhlobo ngimtholile,\nOnomsa enothando,\nUmholi nomluleki,\nUngumvikeli futhi!\nNgohlukaniswa ntoni pho\nKuyen' ongithandayo?\nUkufa na?\nOMubi qha!\nNamanje naphakade!` },
  { id: 78, title: 'Dwala Lami Laphakade', lyrics: `1 Dwala lami laphakade,\nMangicashe njalo kuwe,\nZonk' izono enginazo\nMazihlanzw' igazi lakho,\nMaliphel' icala lami,\nNgihlanzeke ngaphakathi.\n\n2 Yonk' imisebenzi yami\nAyisoz' ingilungele.\nYonke imizamo yami\nNe' nyembezi zonke zami\nZingeqed' izono zami;\nNguwe wedwa, msizi wami.\n\n3 Anginal' eliny' ithemba,\nUnqamlezo lwakho lodwa,\nMawungambathise wena,\nUngiphase ngomsa wakho;\nMangihlambe emthonjeni,\nNgiphilise, Nkosi yami.\n\n4 Uma sengiphel' amandla,\nUmphefumlo sewuphuma,\nNxa sengindizela kuwe,\nNgikubon' esihlalweni;\nDwala lami laphakade,\nMangicashe njalo kuwe.` },
  { id: 79, title: 'Emafwini, Nangu Ehla', lyrics: `1 Emafwini, nangu ehla,\nOwafel' aboni kanye;\nAmabandla aphezulu\nNabangcwele abaningi\nBeza naye bejabula,\nAleluya, aleluya!\nEmafwini, nangu ehla,\nAleluya, Amen\n\n2 Uyabonw' amehlo onke,\nEhlobele ubukhosi;\nLabo adeleka kubo,\nAbamhlaba bambethela,\nBahlupheka, bahlupheka,\nSebemazi unguKristu.\nEmafwini, nangu ehla.\nAleluya, Amen.\n\n3 Ukushaywa kwecilongo,\nAlisayikuma izwe;\nLibalek' izulu futhi;\nBonke ababemuzonda,\nBayakuzwa izwi lithi,\n\"Niyabizwa nguMahluli.\"\nEmafwini, nangu ehla,\nAleluya, Amen.\n\n4 Kuhle; sekufike manje\nLokhokusindiswa kwethu;\nAbangcwele bakhe bonke\nBenyukela bamfumane;\nBayahuba ngenjabulo,\nAleluya, aleluya!\nEmafwini, nangu ehla,\nAleluya, Amen.\n\n5 Yebo, Amen; sokhuleka\nSonke kunkos' kuMsindisi wethu,\n\"Thatha, Nkos', amandla akho\nBusa embusweni wakho,\"\nKhona sizohlabelela,\nAleluya, aleluya!\nEmafwini, nangu ehla,\nAleluya, Amen.` },
  { id: 80, title: 'Yizwani, Nina Ziqhingi Zolwandle', lyrics: `1 Yizwani, nina ziqhingi zolwandle,\nNin' enikade nifile;\nYizwani namhla ukuhlabelela,\nBheka, uJesu uyabuya.\n\n2 Nina eningabaseningizimu,\nSheshani nimhlangabeze;\nNani-ke, zizwe, zasemakhazeni,\nBheka, uJesu sewuyiza.\n\n3 Nabahleziyo ngasempumalanga,\nBebuk' ikhwezi lokusa,\nNabo abantu basentshonalanga\nBheka, iNkosi inomusa!\n\n4 Suka-ke, mhlaba wonke, ekoneni,\nINkosi' iyehl' emafwini;\nNan' enikade nambelwa, vukani,\nNimhlangabeze ezulwini.` },
  { id: 81, title: 'Lalelani, Nant\' Ilizwi', lyrics: `1. Lalelani, nant' ilizwi,\nIzwi loMsindisi wethu,\n\"Bheka, ngiza masinyane,\nNgiza nokuvuza kwami,\"\n\n2. Izelan' iNkosi yethu?\nIza ukwamkel' abayo,\nBabe-nayo laph' ikhona,\nBabon' ubukhosi bayo.\n\n3. Bayomiswa phambi kwayo,\nBazilande bonke kuyo\nNgawo onk' amazwi abo,\nNem' sebenzi yabo futhi.\n\n4. Obehamba ngenhliziyo\nEphelele eNkosini,\nOmsebenzi wakhe umi,\nUyobongw' iNkos' avuzwe.\n\n5. Keph' obengahambi kahle,\nEngahlali eNkosini,\nUyolahlekelw' umvuzo,\nAngabon' iNkosi yakhe.\n\n6. Nkosi, siza ngomsa wakho,\nSikubheke, sithandaze,\nSihambis' okwakho njalo,\nSikubone ngokwethaba.` },
  { id: 82, title: 'Kade Kubhekwa Emafwini', lyrics: `1. Kade kubhekwa emafwini\nUkub' uJes' abuye\nNezingelosi nobukhosi,\nIzwe libuswe nguye.\n\n2. Kanti useseduze nathi\nNgakh' ukukholwa kwethu,\nKuyezwakal' uthando kithi\nNgakh' ukusizwa kwethu.\n\n3. Singezw' isandl' esihle sakhe\nSithob' izifo zethu,\nIphimbo elimnandi lakhe\nLivus' umoyo wethu.\n\n4. Singaselul' isandla sethu\nSithint' ingubo yakhe,\nSithol' impilo entsh' impela\nNgawo amandla akhe.\n\n5. O Jesu, uyiNkosi yethu,\nBusa ezinhliz' yweni;\nQondisa ukuhamba kwethu,\nSifike ezulwini.` },
  { id: 83, title: 'Kungathi Ngingavum\' Okuhle', lyrics: `1. Kungathi ngingavum' okuhle,\nKungathi ngingabon' ubuhle,\nObukuMsindisi,\nNgithinte ezulwini,\nKuGabriyel nom' ethini,\nNgihub' okuhle nya.\n\n2. Ngivum' igazi, walichitha,\nLangihlawula, langikhipha,\nNgasinda mina.\nNgihuba ukulunga,\nEngambathiswa ngakho,\nNgikhanya naphi mfe!\n\n3. Nesimo esikhona kuye\nNothando lonke olunguye.\nEsezulwini!\nNgiphakamis' amehlo\nImini nobusuku,\nNgigwab' owakakhe du!\n\n4. Usuku luyangifikela,\nNgithathw' iNkosi ukuphela\nNgiyibon' ubuso!\nNginaye uMsindisi,\nNgihlezi yonk' imihla,\nNgethaba ngomsa lo!` },
  { id: 84, title: 'Vum\' UJesu, Vuma Njalo', lyrics: `1. Vum' uJesu, vuma njalo,\nVum' uthando lol' analo;\nThina esasinda ngaye,\nSize kuye.\n\n2. Ngal' igazi wasizuza;\nNaz' izono wazisusa,\nSisandinda wasimisa.\nSimdumise.\n\n3. Nasehlane wasihola,\nNangemana wasihola;\nKuyo yonk' indlela yakhe\nhub' okwakhe.\n\n4. Nans' iNkosi, sisyibona,\nIfikile kwelakhona,\nVuma nangomoya, ukuthi,\n\"Baba, Nkosi.\"\n\n5. Vum' uJesu, vuma njalo\nVum' uthando lol' analo;\nVuma esasinda ngalo,\nVuma njalo.` },
  { id: 85, title: 'Nans\' INkos\' Ethandekayo', lyrics: `1. Nans' iNkos' ethandekayo!\nYiyo eyasifelayo!\nNgawo umsebenzi wayo,\nMasibonge.\n\n2. Kade sasisecaleni,\nKade sasisekoneni,\nManje sesisenqabeni,\nNgomsa wayo.\n\n3. Ngomsa wayo siphumule,\nNgomsa wayo sijabule;\nManje njalo simkhumbule\nLoMkhululi.\n\n4. Wasikhipha nasempini,\nWasikhipha ebubini,\nManje sesisebomini,\nEsigcina.\n\n5. Njalo uzosisindisa,\nNjalo uzosibusisa,\nNathi thina somdumisa\nEzulwini.` },
  { id: 86, title: 'Njengabase Jerusalema', lyrics: `1. Njengabase Jerusalema\nBambong' uJesu oyiNkosi,\nNathi sonke khona la\nMasimbong' uJesu\nVumanini, masibong' iNkos'\nVumanini, masibong' iNkos'\nDumisani, dumisani,\nDumisan' iNkosi yethu!\n\n2. Wahlala wahlupheka yean,\nWadela ubukhosi bakhe,\nWehla phansi khona la,\nAbe-uMsindisi\n\n3. Wayenomus', enobunene,\nAbeza kuye basindiswa,\nBavuswa, baphiliswa nya,\nBonke babusiswa.\n\n4. Futhi nguMsindisi wethu,\nUthando lwakhe lumi njalo,\nOthemba kuye khona la\nWosindiswa nguye.\n\n5. Sonke masimbabaz' uJesu,\nMasilwandis' udumo lwakhe,\nKuze kuthi bonke la\nBamdumise yean.` },
  { id: 87, title: 'Mangivus\' Ingoma Yam\'', lyrics: `1. Mangivus' ingoma yam'\nKuye oyiNgcwele!\nKuy' uJes' iNkosi yam'\nOngihlawulele!\n\n2. Nguye osizini lwam'\nOangihlengayo,\nNasekuboshweni kwam'\nOwangifelayo.\n\n3. Ekuhluphekeni kwam'\nNgiyabheka kuye,\nNxa ephel' amandla am'\nNgiyagcinwa nguye.\n\n4. Manje enhliz' yweni yam\nAkungen' uvalo,\nNgoba, phel', Nkosi yam',\nIsekhona njalo.\n\n5. Nkosi, nank' umoya wam',\nUyakunxanela;\nUngihole, Nkosi yam',\nNgiyakulandel.\n\n6. Khanyisis' indlela yam',\nMawungiqinise!\nNaphakade, Nkosi yam',\nMawungisindise.` },
  { id: 88, title: 'Manjena Kuy\' Nkosi Vuma', lyrics: `1. Manjena kuy' iNkosi vuma!\nYishoni mlomo nomphefumlo,\nHozana kul' igama lakhe,\nNishumayel' uthando lwakhe:\nAh! ikuJesu ebusweni\nInkazimulo emuseni;\nUThixo, ngaye uMntanakhe,\nUdlule im'sebenzi yakhe.\n\n2. Umusa - izwi elimnandi!\nUJesu - hawu, 'kuzindla ngaye!\nNgelosi, yizwa lelogama!\nNezulu, lise emhlabeni\nEbambulil' ubuso bakhe!\nAh! kungangingafika lapho,\nNgibuke bonk' ubuhle bakhe,\nNihub' iama lakhe lapho!` },
  { id: 89, title: 'Bayede, Nkosi Yamakhos\'', lyrics: `1. Bayede, Nkosi yamakhos',\nOgama linguJesu!\nLethan' umqhele wobukhos'\nNimthwese wona, nithi,\n\"Nkosi yakho konke!\"\n\n2. Nin' eningelukhohlwe, qha,\nUthando olukhulu\nLomfeli wenu, zanini,\nNimthwes' umqhele, nithi,\n\"Nkosi yakho konke!\"\n\n3. Makuthi bonk' abezizwe,\nBaguqe phambi kwakhe,\nBambonge bengaphezi la,\nBamthwes' umqhele, bethi,\n\"Nkosi yakho konke!\"\n\n4. Nami-ke, Jesu, Mhlengi wam'\nSengisondele kuwe,\nNgileth' okwami konke, Nkos',\nNgithele kuwe ngithi,\n\"Nkosi yakho konke!\"` },
  { id: 90, title: 'We, Bandla Laphezulu', lyrics: `1. We, bandla laphezulu,\nBongan' iNkosi yenu,\nEnimbonay' uJesu,\nVukani nimdumise!\nNin' abasezulwini,\nVumani nani nonke,\nMasibabaze kanye\nUthando lwakhe.\n\n2. Bhekani, nina bantu,\nUnguMsindisi wethu,\nYizwani izindaba\nNgokuza kwakhe lapha'.\nWasuka ezulwini,\nWeza la emhlabeni,\nWadela ubukhosi,\nWafel aboni.\n\n3. Yizani nina bantu,\nNimtusise, bethu!\nBongani umsa wakhe,\nOnguMkhululi wethu;\nWaveza ukukhanya\nEbumnyameni bethu,\nSilondolozwa nguye\nOsithandayo.\n\n4. Sihlabelela ngaye\nUMhlawulwli wethu,\nSiphakamisa izwi\nNgenhliziyo zethu;\nNempela kufanele\nUkuba thinabakhe\nNgegam' elihle.` },
  { id: 91, title: 'Masimdumis\' uJesu', lyrics: `1. Masimdumis' uJesu\nNgenhliziyo zethu;\nMasimdumis' uJesu\nUMhlawuleli wethu,\nUsezulwini yena,\nUyadunyiswa khona,\nVukani, nimbabaze,\nNibong' igama lakhe.\n\n2. Masimdumis' uJesu,\nNgokuba wasifela;\nMasimuthand' uJesu\nUmhlobo weth' impela;\nAbeza kuye bonke,\nEkhona emhlabeni,\nWahamb' ebasindisa,\nNabesenhluphekweni.\n\n3. Masimethemb' uJesu\nNgokuba enomusa;\nMasimethemb' uJesu,\nUkwahluli' ukufa;\nMasimethemb' uJesu\nOwasihluphekela;\nMasimdumise njalo\nOwasihlawulela.` },
  { id: 92, title: 'Kwehl\' Uban\' Ukuza La?', lyrics: `1. Kwehl' uban' ukuza la?\nUMsindis' uJesu.\nWehla engumntwana -nje?\nUMsindis' uJesu.\n\nVumanini, bandla,\nNimdumis' uJesu.\nNant' uthando! Muhle\nUMsindisi wethu.\n\n2. Yen' owabethelw' uba?\nUMsindis' uJesu.\nOsahlawulel' uba?\nUMsindis' uJesu.\n\n3. Osithethelel' uba?\nUMsindis' uJesu,\nKwash' ubani, \"Kholwa-nje?\"\nUMsindis' uJesu.\n\n4. Osenobukhos' uba?\nUMsindis' uJesu.\nOsikhulumel' uba?\nUMsindis' uJesu.\n\n5. Wobuyela futhi la?\nYebo, washo njalo.\nNathi soba-naye na?\nYebo, washo njalo.` },
  { id: 93, title: 'Hubelani ENkosini', lyrics: `1. Hubelani eNkosini!\nYiyo eyasifelayo!\nNina nonke, bonganini!\nNiyikhonz' ethandekayo!\n\nHubanini! Ungomkhulu\nOsenzela intabiso!\nYi' iNkosi ephezulu\nEsiphile insindiso!\n\n2. Yiyo eyazinikela,\nIsikhiphe ekufeni;\nYiyo eyathol' indlela\nIsihlanze ekoneni.\n\n3. Yiyo esihlawulela\nNgokuhlenga okukhulu!\nYiyo esilungisela\nIfa elingaphezulu!\n\n4. Nayo isithembisile\nNjalo izosisindisa;\nNathi futhi, sesizwile,\nNjalo izosibusisa.\n\n5. Sesiyalangazelela\nIsikhathi esizayo\nLapho iyakubehlela\nLabo abasindindiswayo.` },
  { id: 94, title: 'Mangiyenze Indumiso', lyrics: `1. Mangiyenze indumiso,\nENkosini yensindiso;\nIngenzele intabiso;\nNgiyabonga, Mfeli wami.\nIngenzele intabiso;\nNgiyabonga, Mfeli wami,\n\n2. Bengikhona ezonweni,\nBengibanjwe ecaleni,\nBengiqonde ekufeni;\nWangikhipha, Mfeli wami.\nBengiqonde ekufeni;\nWangikhipha, Mfeli wami.\n\n3. Wangizwisa izwi lakho,\nWangibiza ngomsa wakho,\nNgize ngib' umuntu wakho,\nNgisindiswa, Mfeli wami.\nNgize ngib' umuntu wakho,\nNgisindiswa, Mfeli wami.\n\n4. Wangikhipha osizini,\nWangibeka ebomini,\nSengisinga ezulwini,\nNgomsa wakho, Mfeli wami,\nSengisinga ezulwini,\nNgomsa wakho, Mfeli wami.` },
  { id: 95, title: 'Khangelani UMsindisi', lyrics: `1. Khangelani uMsindisi,\nOwafel' izono zethu,\nOwahawukel' aboni,\nOwathwal' icala lethu.\n\n2. Sisahamba emnyameni,\nSingayazi leyondlela,\nWehla weza emhlabeni,\nWeza ngakh' ukusifela.\n\n3. Wazishiy' izingelosi,\nWawushiy' umbuso wonke,\nNgazo izinswelo zethu,\nNgakh' ukona kwethu sonke.\n\n4. Inkathazo nenhlupheko\nWayeyisa ngenxa yethu;\nBamuceba, bamphanyeka,\nNgakho konk' ukona kwethu.\n\n5. Moya wami, bheka kuye\nLowo uMsindisi wakho;\nUmdumise, umthokoze,\nOwaqed' icala lakho.\n\n6. Sondezela njalo kuye\nOnamandla nobubele,\nKuze kuthi ekufeni\nUbe-nabo abangcwele.` },
  { id: 96, title: 'Mina, Jesu, Ngiyindlela', lyrics: `1. Mina. Jesu, ngiyindlela,\nNeqiniso, nokuphila,\nWozanini, nisondele,\nNamkeliswe usindiso.\n\n2. Jesu, wena uyindlela,\nSoya ngawe ezulwini,\nWeza wasihlawulela,\nWasikhipha ebubini\n\n3. Jesu, wen' uliqiniso,\nNgawo onk' amazwi akho;\nKonke okuyinkohliso\nKubi ebusweni bakho.\n\n4. Jesu, wen' ungukuphila,\nSingathemba sonke kuwe,\nUphilisa im' phefumlo\nYabo abakholwa kuwe.\n\n5. Jesu, wena oyindlela,\nNeqiniso, nokuphila!\nSiyabonga nokubonga;\nSiyethemba nokwethemba.` },
  { id: 97, title: 'Masivez\' Igam\' Elihle', lyrics: `1. Masivez' igam' elihle\nLokubong' uJesu,\nSihlangane namabandla\nLa aphezu kwethu;\nIzilimi zawo lawa\nZiyinkulungwane,\nKepha ngenjabulo yazo\nZijabula kanye.\n\nIfanele yon' iMvana\nIbe-nal' udumo lonke,\nSiyavuma, Aleluya,\nAleluya, Amen.\n\n2.Ufanel' uJesu Kristu\nUbukhosi bonke;\nNokubonga kungapheli,\nKungokwakhe njalo.\nWasinik' umzimba wakhe,\nWalichith' igazi,\nSidle wona, siliphuze,\nSibe-nokuphila.\n\n3. Wozanini, zinto zonke!\nNizithobe phansi.\nPhambi kwesihlalo sakhe,\nLaph' ehlezi khona;\nNibabaz' ibizo lakhe\nNgoba lihle lodwa,\nLidunyiswa ezulwini,\nMalituswe phansi` },
  { id: 98, title: 'Nkosi Yam\', Ubungithanda', lyrics: `1. Nkosi yam', ubungithanda\nEkulahlekeni kwam',\nNkosi yami, walandela\nFuthi emkhondweni wam',\nNgafunywanw' iNkosi yam'.\n\n2. Nkosi yam', ilizwi lakho\nLona inkanyiso yam',\nNkosi yam', umusa wakho\nUyinjabuliso yam',\nNgibusiswa, Nkosi yam'.\n\n3. Nkosi yam', umoya wakho\nUyangigcwalisa nam',\nNkosi yam', izulu lakho\nLona lilikhaya lam',\nMangingene, Nkosi yam'.` },
  { id: 99, title: 'O Nkosi Jesu', lyrics: `1. O Nkosi Jesu,\nMbusi wakho konke,\nOnguy' uThixo nomuntu\nNgiyakuthanda,\nNgokudumisa\nOngipha konk' eninakho.\n\n2. Muhle umhlaba,\nLihl' impel' izulu,\nLibengezel' i'nkanyezi,\nKudlulw' uJesu.\nMuhle uJesu\nKunakho konk' okukhona.\n\n3. Bonke ubuhle\nBezwe nobezulu\nBufunyaniswa kuJesu,\nAkukho Lutho\nOluhle kimi\nNjengawe, Jesu, Msindisi.` },
  { id: 100, title: 'Yizwani Nginitshele', lyrics: `1. Yizwani, nginitshele\nNgoThixo, nobubele,\nNokusithanda kwakhe,\nNgay' iNdodana yakhe,\nSazalwa ezonweni,\nSabanjwa ekufeni,\nKwabekungekh' umuntu\nUkusindis' abantu.\n\n2. UThixo wasibona\nSihlezi sinokona;\nWabanosizi ngathi,\nWasiphuthuma futhi,\nWathuma uMntanakhe\nKithi 'zitha zakhe,\nEz' ukusibuyisa,\nWez' ukusisindisa.\n\n3. UJesu wasifela,\nEmthini olihlazo;\nWathath' ubuntu bethu\nNas' isikhundla sethu,\nKungamanxeba akhe,\nNangemivimbo yakhe,\nAbantu babusiswa,\nAboni basindiswa.` },
  { id: 101, title: 'Nkosi, Moya OyiNgcwele', lyrics: `1 Nkosi,Moya oyiNgcwele,\nNgalomuhla wozi kithi;\nNgomsa mawusikhanyise\nInhliziyo ngaphakathi;\nPhefumula phezu kwethu\nUmphefumlo wokuphila,\nSibe-nokuphila ngawe;\nSingaphila ngawe wedwa.\n\n2. Ngawuthela phezu kwethu\nLezizipho ezikhulu\nZokusilungisa njalo,\nSize sifanel’izulu\nLokhu okuvela kuwe\nSithokoze ngakho kodwa;\nSibe-nokuphila ngakho,\nNenhliziyo yokuthanda.\n\n3. Mawuvul’amehlo ethu\nAz’abon’indlela yakho;\nSazi injabul’enkulu\nNgokuhamba ngayo njalo,\nMakukhany’ubuso bethu\nNgokwethaba kwenhliziyo\nOkuvela ngokukwazi,\nNokwethemba kuwe njalo.` },
  { id: 102, title: 'Woza, Moya OyiNgcwele', lyrics: `1 Woza ,Moya oyiNgcwele;\nWoza,mawungene kithi.\nThina sesikunxanele,\nSizizwele wena futhi.\n\nMoya oyingcwele,\nMawungene kithi;\nThina sesikunxanele,\nSizizwele wena futhi.\n\n2. UnguMoya wab’ ubomi,\nObuvela bungadalwa;\nKodwa thina singaboni,\nSinokufa ngokuzalwa.\n\n3. Wena, Moya, uthulisa,\nUphumuza inhliziyo,\nThin’ abantu siyafisa,\nAsithuli, sinyakaza.\n\n4. UnguMoya wokuthanda,\nKade wenza ububele,\nIzeduko zethu zanda,\nUthandano lonakele\n\n5. Moya oyiNgcwele, yiza\nUkusigcwalisa sonke,\nSiyacela, siyabiza\nLezozipho zakho zonke.` },
  { id: 103, title: 'UMsindisi Weth’ UJesu', lyrics: `1. Umsindisi weth’ uJesu\nWabatshel’abakhe,\nWathi, “Koza onganenza nibengcwele.”\n\n2. S’enyukele ezulwini wathumela\nKubo\nYen’ uMoya oyiNgcwele\nWentembiso.\n\n3. Manje usekhona kithi uba\nAsisize.\nUyangena enhliz’yweni\nEmthandayo.\n\n4. Ukhuluma kithi njalo nxa\nSilingw’ ukona,\nAsikhuze, sikuyeke, singakwenzi.\n\n5. Uma senz’ okuhle kwakhe,\nSimnqabel’ oMubi,\nKungu Yena osinik’ amandla\nAkhe.\n\n6. Woza, Moya oyiNgcwele,\nNgena kithi sonke,\nUsiqhube njalo, senz’ intando\nyakho.` },
  { id: 104, title: 'Moya OyiNgcwele, Yiza', lyrics: `1 Moya oyiNgcwele,\nYiza phezu kwethu;\nMawusikhanyise\nE’ nhliz’ yweni zethu:\n\nMawusikhanyise,\nMawusikhanyise\nE’ nhliz’ yweni zethu.\n\n2. Siyakulahleka\nSingadonswa uwe,\nNakhu, sesibheka\nNgenhliziyo kuwe\n\n3. Moya oyiNgcwele,\nYiza phezu kwethu;\nSenze simazise\nUMkhululi wethu\n\nMawusikhanyise,\nMawusikhanyise\nE’ nhliz’ yweni zethu\n\n4. Mawusiholele\nE’nyaweni zakhe;\nUsiqinisele\nUyekelo lwakhe\n\n5. Moya oyiNgcwele,\nYiza phezu kwethu;\nUsicwengisise\nInhliziyo zethu\n\n6. Uwe uMthembisi\nNgokwaseNkosini,\nUwe uMthabisi\nNgokwasezulwini` },
  { id: 105, title: 'Kalokhu, Moya, Woza', lyrics: `1 Kalokhu, Moya, woza,\nFika phakathi kwethu;\nNgamandla uzivuse\nIzinhliziyo zethu,\nNgesinye isikhathi\nAbantu baphenduka,\nuMoya waba-nathi,\nNangaye sasibusa.\n\nKalokhu, Moya muhle!\nWoza phakathi kwethu;\nNgamandla uzivuse\nIzinhliziyo zethu.\n\n2. Sabuya sakukhohlwa\nUkubusiswa kwethu;\nUMoya sammukisa\nNgemisebenzi yethu.\nIzinhliziyo zethu\nZikhala ngobuhlungu;\nYekel’ icala lethu,\nUgcine umphefumlo.` },
  { id: 106, title: 'Woza, Moya, OyiNgcwele', lyrics: `1 Woza, Moya oyingcwele,\nThusa inhliziyo,\nWoza, yebo, sikuswele,\nUzikhomb’ izono.\nUsikhumbuze okubi,\nNesingakwaziyo;\nUsiyekise ububi\nObusahleziyo.\n\n2. Vus’ uvalo lwabonayo,\nBabubon’ ububi;\nWena obakhumbuzayo\nOnk’ amazw’ eNkosi,\nBakhalis’izinyembezi,\nBekhumbul’ izono;\nUngenise umsebenzi,\nBakushiy’ ukona.\n\n3. Usikhombise indlela,\nEya ezulwini;\nSingeduki, sikudele,\nSiye ekoneni,\nUsijwayeze ukuzwa,\nLapho usitshela;\nSilalele usikhuze,\nSingamphik’ uJesu.` },
  { id: 107, title: 'Moya OyiNgcwele, Wena', lyrics: `1 Moya oyiNgcwele, wena\nUnguMvuseleli wethu;\nMawuvuselele thina,\nUhlale phakathi kwethu.\n\n2. Mulungisi wenhliziyo.\nSingcolile ekoneni;\nUwe osigezisayo,\nSikhulule ekufeni.\n\n3. Muholeli wamaKristu,\nSibonis’ indlela yakho;\nMasikulandele kahle,\nSingadeli umsa wakho.\n\n4. Muthabisi wamaKristu,\nSiphe intabiso yakho;\nZwisa izifuba zethu\nYona injabulo yakho.` },
  { id: 108, title: 'Vukani, Bandla-bo', lyrics: `1 Vukani, bandla-bo, nilaleleni\nna?\nAnikamuzwa yin’ uMoy’ omuhle\nlo?\nUsemhlabeni la; somthola nini na?\nNang’ uMthokozisi.\n\nNempel’ usemhlaben’, uvela\nEzulwin’,\nUyakuhlanza konke okusenhliz’ywen’.\nSiyoba-mhlophe qhwa?\nSohlanzwa yebo na?\nNang’ uMthokozisi.\n\n2. O,sekusile-bo; kwaqala khona-\nle,\nLapho ngePentekost’,\nKwakhanya Kwathi nge;\nKwath’ eJerusalem babonga,\nBath’, “Ehe’,\nNang’ uMthokozisi.”\n\n3. Yebo, ukhona lo, nakhona-\nLapha-nje,\nSize sinqob’ izitha zethu zonke Nya;\nMasigcwaliswe swi, sigcinwe\nSithi Nge;\nNang’ uMthokozisi.\n\n4. Nanamhla umi nqo, use-\nNamandla nya,\nUyasihlanzisisa sibe-mhlophe Qwa.\nPhaphama, wena, mngan’, umzuze\nMasinyan’,\nNang’ uMthokozisi` },
  { id: 109, title: 'Phefumulela Kimi', lyrics: `1 Phefumulela kimi\nMoya ongcwele,\nIz’ ith’ intando yami\nIbe-ngeyakho.\n\n2. Phefumulela kimi,\nNgize ngivuthe,\nKuphel’ okubi kimi\nKukhany’ okwakho.\n\n3. Phefumulela kimi,\nWahlul’ ukufa,\nKoze kube-phakade\nNgiphile kuwe.` },
  { id: 110, title: 'Moya OnoMusa, Yiza', lyrics: `1 Moya onomusa, yiza,\nNami ngibe-naw’ umusa;\nNgaw’ amazwi asizayo\nNgibonis’ umusa wakho,\nNangezenzo zokulunga,\nNgiyikhulumel’ iNkosi.\n\n2. Moya weqiniso, yiza,\nNami ngibe-neqiniso,\nNgaw’ amazwi obuqotho\nNgibonis’ isimo sakho;\nNgibe-nab’ ubuzalwane\nObufakazel’ iNkosi.\n\n3. Moya onamandla, yiza,\nNami ngibe-naw’ amandla\nNgibe-nokuphumelela\nNgizahlule izilingo;\nNginethemb’ elinamandla\nNgiqinise, ngingesabi.\n\n4. Moya oyingcwele, yiza,\nNami ngibe-nobungcwele,\nNgihlukane nakh’ ukona,\nNgenze ukulunga kodwa;\nKonke engingakwenzayo,\nNgimenzel’ uNkulunkulu.` },
  { id: 111, title: 'Izwi Lakhe UJehova', lyrics: `1 Izwi lakhe uJehova\nLilungile lona;\nLiyaxosha ubumnyama\nLinamandla lona.\n\n2. Lona liyasifundisa,\nSinokwazi ngalo;\nIzindaba ezinkulu\nSiyayazi ngalo.\n\n3. Lona liyasikhanyisa,\nLiyilanga lethu;\nLona liyasiqondisa,\nLingumholi wethu.\n\n4. Masilizwe lelilizwi\nSilalele lona;\nSilibambe, siligcine,\nSilithande lona.` },
  { id: 112, title: 'Izwi Limakade', lyrics: `1 IZWI limakade,\nLisihola njalo;\nLibatho kozise\nAbakholwa kulo.\n\n2. Uma kuza impi\nYokusihlasela,\nIzwi liyasiza,\nLiyasisindisa.\n\n3. Uma sekumnyama,\nSingaboni lutho,\nIzwi lisihola\nNgokukhanya kwalo.\n\n4. Kakho ongabika\nNgenjabul’ enkulu\nAyakuba-nayo\nOlibheka lodwa.\n\n5. Elomusa lona\nNoma sisaphila,\nNoma sizakufa\nLiyasiza njalo.\n\n6. Nkosi, mawusiphe\nUkulamukela,\nSifundiswe ngalo\nSikuthandisise.` },
  { id: 113, title: 'Izwi Lika Nkulunkulu', lyrics: `1 Izwi likaNkulunkulu,\nSiyaphila ngalo,\nSiyazaz’ izono zethu\nNoMsindisi ngalo.\n\n2. Izwi lelo lihambile,\nLisahamba lona;\nLezozizwe ezikude\nZilindele lona.\n\n3. Ziyanqotshw’ izitha zakho\nNgezwi lakho, Nkosi;\nWogcwalisw’ umhlaba wonke\nIzwi lakho, Nkosi.\n\n4. Imifula yalelizwe\nYojabula ngalo;\nAbantwana balelizwe\nBocetshiswa ngalo\n\n5. Ziyophel’ izimpi zonke\nNgezwi lakho, Baba,\nKoba-ngukuthula kodwa\nKuwo wonk’ umhlaba` },
  { id: 114, title: 'Ngenxa Yalabo AbaseNkosini', lyrics: `1 Ngenxa yalabo abaseNkosini\nAbabekudumisa khona-la,\nLibongw’ igama lakho, Jesu.\nAleluya, aleluya!\n\n2. Wawungamandla abo ekulweni,\nNenduna yabo, nesihlangu,\nNkos’,\nEbumnyameni ukukhanya.\nAleluya,aleluya!\n\n3. Makuthi bon’ abasekhona\nManje\nBafuze labo ngobuqhawe, Nkos’,\nBazuze nabo ukunqoba.\nAleluya, aleluya!\n\n4. Nasekulweni nxa ephel’\nAmandla,\nBolindwa nguye engabeni,\nNkos’,\nBophiw’ igama lokubonga\nAleluya, aleluya!\n\n5. Siyeza isikhath’ esihle leso\nLapho bezophumul’ abakho,\nNkos’\nBongena nawe ebomini.\nAleluya, aleluya!\n\n6. Nebandla lonke emhlabeni\nWonke\nLelivela lapha nangalaphaya,\nLizobuthana ezulwini, Nkos’.\nAleluya, aleluya!` },
  { id: 115, title: 'UJesu Uyinsika', lyrics: `1. UJesu uyinsika yebandla lakhe,\nLiyisidalw' esisha, ngamanzi nezwi;\nWehla ukulifuna libe-ngelakhe,\nNgegazi walihlenga ngokufa kwakhe.\n\n2. ElikaKrist' ibandla ezweni lonke,\nLibheke usindiso 'Nkosini yalo,\nIgama liny' elihle lithemba kulo,\nLiyadl' ukudla kunye, inyama yayo.\n\n3. Nokuba lihlupheka, linenkathazo,\nNokhoke abangcwele babheke njalo,\nBalindel' isikhathi esihle leso\nLapho izinyembezi zovez' uthabo.\n\n4. Phakathi kwezinsizi nokuzingelwa\nIbandla lilindela inhlalakakhe,\nKufike isikhathi sokubusiswa,\nLinqobile lingen' ekuphumuleni.\n\n5. Noma lisemhlabeni, ukhona, Nkosi,\nNabadlulel' ekhaya bakanye nalo;\nO, sebeyathokoza! Usiphe nathi\nNjengabo sibe-ngcwele sikanye nawe.` },
  { id: 116, title: 'Bandla LikaJesu', lyrics: `1 Bandla likaJesu,\nHlomanini nonke,\nSiye ekulweni,\nSilwe noSathane;\nNang’ uMholi wethu,\nUnguKrist’ uqobo,\nUyiNkosi yamakhosi,\nUnguMnqobi yena.\n\nHlomanini nonke,\nHambani nithi nqo,\nNang’ uMholi wethu\nSimlandele lo.\n\n2. Lihambis’ okwempi\nEleNkos’ ibandla;\nMasibalingise\nBon’ abanqobayo.\nNokh’asahlukene,\nSonke-nje simunye,\nIny’ iNkosi, liny’ ithemba,\nKunye ukuthanda.\n\n3. Amakhos’ omhlaba\nAyadlula onke,\nKeph’ ibandla lethu\nLizokuma njalo;\nNempi kaSathane\nIngehlule lona,\nWash’ uJes’ uqobo lwakhe;\nLimi izwi lakhe.\n\n4. Ngakho hambanike,\nHlanganani nathi,\nVumanini nonke\nNgezwi lokwahlula,\nNimbabaz’ uJesu\nOyiNkos’ enkulu,\nNaphakade wodunyiswa\nAbangcwele bonke.` },
  { id: 117, title: 'Wen’ Ongabona Konke', lyrics: `1. Wen’ ongabona konke,\nOkhona lapha kithi,\nYibheke lendlu yakho, nathi,\nUsithokozise.\n\n2. Babhapathizwa lapha\nUkuba basindiswe,\nBonk’ abamthand’ uJesu Kristu\nBenethemb’ elihle.\n\n3. Ubaphe lapha yena\nUkundla okungcwele,\nBonk’ abafuna lawomandla\nEsiswela wona.\n\n4. Kushunyayelwa lapha\nUkukhululwa kwazo\nIzoni ezicela kuye\nUkuthethelelwa.\n\n5. Ukhon’ uNkulunkulu;\nUzakubabusisa\nAbantu bakhe, abayis’\nEkhaya ezulwini.\n\n6. Ngalokho masimbonge\nUNkulunkulu wethu,\nOkhona manje, ozakuba-\nKhona naphakade.\n\n7. Simbong’ uNkulunkulu,\nUyise nendodana,\nNaye uMoya oyiNgcwele\nManje naphakade.` },
  { id: 118, title: 'Siyathanda, Nkosi', lyrics: `1. Siyathanda, Nkosi,\nIndlu yakho leyo;\nSinothab’ impela\nOlujulileyo.\n\n2. Yindlu yomthandazo\nWezinceku zakho;\nWen’ ukhona, Nkosi,\nEbandleni lakho.\n\n3. Ilizwi lempilo\nLileth’ inkululo\nLiyathunduzela,\nLinik’ injabulo.\n\n4. Kumnand’ ukugwaba\nNgaw’ umusa wakho;\nSifundis’ ingoma\nYasekhaya lakho.\n\n5. Jesu, siph’ umusa,\nSikuthande njalo,\nSize ezulwini,\nSikubuke njalo.` },
  { id: 119, title: 'Nkosi, Bheka Lendlu Yakho', lyrics: `1. Nkosi, bheka lendlu yakho,\nEyakhelwa wena,\nUyivume, uyamkele,\nIb’ eyakho ‘mpela.\nWena onguNkulunkulu,\nWena OnguBaba,\nVuma lomnikelo wethu,\nEsibonga ngawo.\n\n2. Jesu Kristu uMsindisi,\nWen’ oyiNdodana,\nLamulel’ ababntu bekho\nAbezayo lapha.\nNkosi, Moya oyingcwele,\nOnguNkulunkulu,\nKhanyisel’ abantu bakho\nBekukhonza lapha.\n\n3. Nkulunkulu, Simakade,\nOyi’ngqobo ‘ntathu\nBabusis’ abantu bakho\nBebuthene lapha.\nSiyabonga wena, Nkosi\nYise neNdodana,\nNawe Moya OyiNgcwele,\nNkulunkulu munye.` },
  { id: 120, title: 'Kuvela Kuwe Konk’ Okwethu', lyrics: `1. Kuvela kuwe konk’ okwethu;\nAsinalutho lokukupha,\nKepha okwakho, ngenjabulo,\nSiyakwethula phambi kwakho.\n\n2. Umakhi wasebenza nawe;\nAwakh’ amandl’ avela kuwe;\nKonk’ obekuyinhloso yethu\nBekuyintando yakho, Nkosi.\n\n3. Siyakumema, sibancane,\nWena omkhulu kunezulu,\nNans’ indlu yakh’ esiyakhile,\nMayigcwal’ ubukhosi bakho.\n\n4. Ngenake, Nkos’ uyigcwalise;\nNgothando lwakho yibusise;\nOmnyango, nxa singena kuwo,\nSithole usindiso lwakhe.` },
  { id: 121, title: 'Masimdumise Sihlobe Okungcwele', lyrics: `1. Masimdumise sihlobe \nOkungcwele, \nSimkhothamele, simkhonz’ \nUJesu; \nMniken’ izipho, nimshiselel’ \nImphepho \nNgokuthobela intando yakhe. \n\n2. Ezinyaweni nethule imithwalo, \nEnikhathaza nisindwa yiyo; \nNgemithandazo nozuz’ amandl’ \nAmasha, \nAniqondis’ endleleni yakhe. \n\n3. Endlini yakhe ningene \nNi’bampofu \nNingelalutho olumfanele; \nUma niletha uthando nobunene, \nYiwo ‘mnikelo welathi lakhe.` },
  { id: 122, title: 'Sihlangene Lapha, Nkulunkulu Wethu', lyrics: `1. Sihlangene lapha, Nkulunkulu \nWethu, \nNgesabatha lakho elingcwele; \nSondela kithina nangoMoya \nWakho, \nSikudmise endlini. \n\n2. Walwahlukanisa lolusuku \nlwakho, \nWalubusisela izwi lakho; \nNoJesu, iNkosi ,esayona thina, \nWavuka ngalo,efile. \n\n3. Yizanini, bantu nonke, \nNgalomuhla \nWeNkosi, uBaba onamandla, \nNoJesu Kristu, uMsindisi wethu, \nNoMholi wethu ongcwele. \n\n4. Kuhle simdumise ngemilomo \nYethu, \nKuhle simdumise nangezenzo; \nMasimudumise sisesemhlabeni, \nMasimdumise nanini.` },
  { id: 123, title: 'Usilondile, Baba', lyrics: `1. Usilondile,Baba, \nKweliny’ isonto leli; \nUsihlanganisile \nNgalomhla oyingcwele; \nSize ‘kukudumisa, \nMawuz’ usibusise. \n\n2. Usuku lwakh’ oluhle, \nKuqala walumisa; \nUkuphumula kwakho \nKuyasikhumbuza \nEsiyakuba-nakho \nSisembusweni wakho. \n\n3. Sesisondele kuwe, \nSenzele umsa wakho, \nUsikhanyise sonke \nNgaye uMoya wakho; \nZisus’ izono zethu, \nKhulis’ inkolo yethu. \n\n4. Uzibonakalise \nPhakathi kwendlu yakho; \nUliqinise izwi \nLibe-namandla akho; \nAbakho bethabiswe, \nAboni bathotshiswe, \n\n5. Lelivangeli lakho \nMalande emhlabeni, \nLibakhulule bonke \nAbasekuboshweni, \nIzizwe zikhanyiswe, \nAbantu basindiswe.` },
  { id: 124, title: 'Imini YeNkosi Ibuye Yafika', lyrics: `1. Imini yeNkosi ibuye yafika, \nImini yenhlanhla enkulu; \nImini enkulu yenhlanganisela \nYabantu beNkosi yezulu. \n\n2. Imini yesonto insimb’ iyakhala, \nIbutha abantu, mabeze, \nIbiza abasha, imem’ abadala, \nUkuzwa ilizwi lobomi. \n\n3. Imini yaphumla iNkosi yezulu \nIlenzil’ izulu nomhlaba; \nImini wavuk’ umkhululi omkhulu \nWaphuma kwelakhe ingcwaba. \n\n4. Imini abantu beNkosi bezile \nUkuzwa indaba yenzuzo; \nImin’ amaKristu alangazelela \nIndawo abheka ngakuyo. \n\n5. Vumani maKristu, vumani \nBangcwele, \nBongani iNkosi enkulu; \nKodlula uhlupho, nosizi luphele, \nNiphumleke nani phezulu.` },
  { id: 125, title: 'Lolusuku Lungolwakho', lyrics: `1. Lolusuku lungolwakho, \nNkos’ enkulu, Menzi wethu; \nWalumisa lub’ –olwakho, \n‘Suqedile umsebenzi. \n\n2. Awuvumi silukhohlwe \nLolusuku lwesabatha; \nWasiyala silulonde \nLolusuku olungcwele. \n\n3. Kufanele sisondele, \nSize kuyo indlu yakho, \nKufanele siqaphele, \nSilalele izwi lakho. \n\n4. Njalo masifunde kahle \nLokho okuvela kuwe; \nNjalo masigcine konke \nEsikwamukele kuwe.` },
  { id: 126, title: 'Isabatha, Nkosi Yami', lyrics: `1. Isabatha, Nkosi yami, \nLiyimini yakho; \nMabethab’ abantu bakho \nEbusweni bakho. \n\n2. Wavukake, Nkosi, namhla, \nElibeni lakho; \nWakunqoba khon’ ukufa, \nNgokuvuka kwakho. \n\n3. Uvukile wena, Jesu, \nNhloko yamaKristu, \nSizovuka nathi sonke, \nThin’ abakholwayo. \n\n4. Malizwiwe izwi lakho \nNqabaningi namhla; \nMabavuswe ekufeni, \nNamhla basindiswe. \n\n5. Siyakudumisa, Jesu, \nSisendlini yakho; \nSinethemb’ elihle, thina, \nNgokuvuka kwakho.` },
  { id: 127, title: 'Baba, Kungusuku Lwakho', lyrics: `1. Baba, kungusuku lwakho, \nMangiyeke umsebenzi; \nMangifune indlu yakho, \nNgikukhonze wena, Menzi. \nKuhle ngithandaze kuwe, \nNgidumis’ igama lakho; \nKuhle ngifundiswe uwe, \nNgikhulis’ udumo lwakho. \n\n2. Vula izindlebe zami, \nZilamkele izwi lakho; \nYenze inhliziyo yami \nIwuthand’ umthetho wakho. \nNgisahlezi emhlabeni, \nNgithembela eNkosini; \nNjalo, Baba, ekufeni \nMangingene ezulwini.` },
  { id: 128, title: 'Nxa Libhejil’ izulu', lyrics: `1. Ekuvukeni Kwami, \nKabongw’ uJesu! \nEmsebenzini wami, \nNasekukhulekeni, \nKabongw’ uJesu! \n\n2. Nxa izwakal’ insimbi, \nIkhala esontweni, \nKabongw’ uJesu! \nInshumayelo ithi, \nNgenani, nikhuleke, \nKabongw’ uJesu! \n\n3. Alukhathal’ ulimi, \nNgihlabelela ngithi, \nKabongw’ uJesu! \nIhubo lelo lihle, \nLiyasithokozisa, \nKabongw’ uJesu! \n\n4. Nakuba ngingelale \nNgivuke ebusuku, \nKabongw’ uJesu! \nUSathan nxa elinga, \nNgimxosha ngalelizwi; \nKabongw’ uJesu! \n\n5. Uma ngidabukile, \nLelizwi liyasiza, \nKabongw’ uJesu!  \nUma kuphela kimi \nOkuhle kwalomhlaba \nKabongw’ uJesu, \n\n6. Akukho ubumnyama \nNxa sithi nganhliziyo, \nKabongw’ uJesu! \nUSathan uyesaba \nKathand’ ukuzw’ ukuthi \nKabongw’ uJesu!` },
  { id: 129, title: 'Vuka, Mphefumulo Wami', lyrics: `1. Vuka, mphefumulo wami! \nNjengelanga vuka nawe; \nNjengelanga yenza namhla \nWonke umsebenzi wakho. \n\n2. Ungalali ubuthongo, \nSekusile, vuka phansi; \nMayenyuke inhliziyo \nNgokubonga nokucela. \n\n3. Sekuqal’ oluny’ usuku, \nKumbe lungolokuphela; \nHamba namhla ngokungathi \nAwuyikuvuka ngomso. \n\n4. Njengongathi ingomuso \nAlisenandawo lona, \nYokuzilungisa kahle \nUkubon’ iNkosi yakho \n\n5. Ngokwempela kufanele \nUcabang’ okuhle namhla, \nOnk’ amazwi abe-mahle, \nZibe-zinhl’ izenzo zakho. \n\n6. Ngokukhanya kwaphezulu, \nKhanya nawe njalonjalo; \nUkhanyise abanawe, \nUye nabo ezulwini.` },
  { id: 130, title: 'Jesu, Okhanyis’ Izizwe', lyrics: `1. Jesu, okhanyis’ izizwe, \nUyilanga leqiniso; \nWayiletha insindiso, \nNokuphila nentabiso, \n\n2. Izwi lakho liyakhanya \nNxa lingena enhliz’ yweni; \nLiwubhaqa onyaweni, \nUkukhanya endleleni. \n\n3. Wath’ ibandla likukhanya, \nIsibani ebantwini. \nLingumuzi entabeni \nOngehlale,usitheke. \n\n4. Bandla elikhanyisiwe, \nSukanini nikhanyise \nAbasesebumnyameni \nNgevangeli loMsindisi.` },
  { id: 131, title: 'Ilanga Liyakhanya', lyrics: `1. Ilanga liyakhanya; \nSicela kuwe, Baba, \nKhanyisa inhliziyo, \nSihole endleleni. \n\n2. Mazibe-kude nathi \nIzinto zonk’ ezimbi; \nUlimi luthambise, \nThandisa inhliziyo. \n\n3. Yilinde impi yethu \nEsihlasela thina; \nWovimba iminyango \nYokuzwa kwethu, Nkosi! \n\n4. Konk’ esikubonayo, \nNokungabonwa nakho, \nKuhlala kudumisa \nKubong’ igama lakho. \n\n5. Malwand’ udumo lwakho \nNgokusebenze kwethu, \nKusasa nasemini, \nKuze kube-kusihlwa.` },
  { id: 132, title: 'Langa Lomphefumulo Wam’', lyrics: `1. Langa lomphefumulo wam’ \nWen’ okhanyis’ izulu, \nYehla ngamandla, Nkosi yam’, \nXosh’ ubumnyama kithi. \n\n2. Kungebe-ubusuku, Nkos’, \nUma unami njalo; \nMakungabikho into la, \nYokukkufihla kimi. \n\n3. Uma ngilele, Nkosi yam’ \nNgikhwelwe ubuthongo, \nMangizw’ ukuthi kuhle Nkos’, \nUba ngikhwezwe nguwe. \n\n4. Mawube-nami, Nkosi yam’, \nKusasa kuze kuhlwe; \nUma ungekho kimi, Nkos’, \nNgingebe-ngisaphila. \n\n5. Uma ekhon’ owakho, Nkos’, \nEduka endleleni, \nShesha umsize, funa, Nkos’, \nAlale ekoneni. \n\n6. Nabagulayo, Nkosi yam’, \nBalind’, ubaphilise, \nNabanosizi, Msizi wam’, \nBagcin’ ubabusise. \n\n7. Sondela nxa sivuka, Nkos’, \nKhanyis’ indlela yethu; \nUngasishiy’ nakanye, Nkos’, \nSize sifike kuwe.` },
  { id: 133, title: 'Kuyez’ Ukuhlwa', lyrics: `1. Kuyez’ ukuhlwa, hlala nami, \nUhlale nami, sekuyahlwa; \nLapho abanye behluleka, \nWen’ osizayo, hlala nami. \n\n2. Kushesha ukudlul’ okwethu; \nUbuhle obomhlaba buphi? \nKuyaguquguquka konke; \nE. Simakade, hlala nami. \n\n3. Ngithand’ ukuba-nawe njalo, \nUngekho, ngowa izilingo; \nUbani ongasiza njalo? \nInkathi yonke hlala nami. \n\n4. Ungangishiyi nakancane, \nOhlalakade, hlala nami. \nBekezelel’ ububi bami, \nYizake, uzakhele nami.` },
  { id: 134, title: 'Siyalala Manje, Baba', lyrics: `1. Siyalala manje, Baba, \nSithandazakuwe; \nUsilondoloze, Baba, \nSiyethemba kuwe. \n\n2. Namhla siphilile, Baba, \nSiyagcinwa nguwe; \nYiba-nomsa futhi, Baba, \nSiyacela kuwe. \n\n3. Naz’ izono zethu, Baba, \nSiyakhala ngazo; \nUze usisize, Baba, \nSahlukane nazo. \n\n4. Masibe-abakho, Baba, \nSisesemhlabeni; \nSiphumule nawe, Baba, \nKhona ezulwini.` },
  { id: 135, title: 'Lishonil’ Ilanga manje', lyrics: `1. Lishonil’ ilanga manje, \nSelinyamalele; \nBufikile ubumnyama, \nBusisibekele. \n\n2. Ngawo lomhla uJehova \nUsibusisile; \nNgayo yonk’ imihla yethu \nUsiphilisile. \n\n3. Baba wosilondoloza \nNasebuthongweni, \nUsivuse ekuseni \nSinamandla ethu. \n\n4. Ngamasuku ethu onke \nSiphe umsa wakho; \nEkufeni singeniswe \nEmbusweni wakho.` },
  { id: 136, title: 'Manje Lishonile', lyrics: `1. Manje lishonile, \nFuthi sekuhlwile; \nAmathunz’ ehlile, \nEhlil’ ezulwini. \n\n2. Jesu, Kuhl’ ungiphe \nUbuthong’ obuhle; \nManje ungigcine, \nUngival’ amehlo. \n\n3. Ebusuku bonke, \nIngelosi ize, \nNgamaphik’ amhlophe \nIngilondoloze. \n\n4. Lapho sekusile, \nMangivuke nam, \nNgingenal’ icala \nKuwe, Nkosi yami.` },
  { id: 137, title: 'Selishon’ Ilanga', lyrics: `1. Selishon’ ilanga, \nLibhejil’ izulu; \nMasiwenz’ umthandazo, \nKusavel’ izinkanyez’ \nEzulwini. \n\nNgcwele Ngcwele, Ngcwele, \nNkosi yethu, \nIzwe likudumisa, \nNal’ izulu lonke, \nO Somandla. \n\n2. Nkosi yokuphila, \nOsikhweza thina, \nUsimboze ngephiko, \nUsigone ngengalo, \nUbusise \n\n3. Nxa kuhlwil’ ezweni, \nI’ nhliziyo zethu \nNgaz’ izinkanyezi \nZenyukela ngamaphik’ \nOkukhanya. \n\nNgcwele Ngcwele, Ngcwele, \nNkosi yethu, \nIzwe likudumisa, \nNal’ izulu lonke, \nO Somandla.  \n4. Nxa kufik’ ukufa, \nSishonelw’ ilanga, \nUsivuse sekuse, \nAmathunzi ephelil’ \nEsethe nya.` },
  { id: 138, title: 'Kusebusuku, Sekuyakulalwa', lyrics: `1. Kusebusuku, sekuyakulalwa, \nIsibusiso sakho, Baba, siphe; \nSiguqe kuwe, Baba, siyakholwa, \nNkosi enkulu. \n\n2. Msindisi wethu, ub-eduze nathi, \nUsithumele ingelosi futhi, \nUthando lwakho \nMalube-phakathi, \nKhanyis’ indlela. \n\n3. Ukhona njalo, Siphe ukuphila, \nSigcine kungabikho ukulia; \nEzingalweni zakho sesilala, \nNkosi, sisize. \n\n4. Thixo odumileyo, siza kuwe, \nUkuphumula kuvela kuwena, \nNezibusiso zonke zimi kuwe, \nNkosi yezulu.` },
  { id: 139, title: 'Mawube Nathi', lyrics: `Mawube nathi, sekuyez’ ukuhlwa, \n1. Nguwe opheth’ imini nobusuku, \nPhansi kwomthunzi wakho \nSophumula \nUsivikele. \n\n2. Nxa sesilala makube-ngobuhle, \nNxa sesivuka \nKube-ngomkhuleko, \nImini yonke sikukhonze kahle \nNgesikwenzayo. \n\n3. Ubaduduze bon’ abalilayo, \nNabagulayo nababoshiweyo, \nNezintandane sizithandazela \nMabaphumule. \n\n4. Nguwena wedwa oyinqaba \nYethu, \nNgaphandle kwakho asinal’ \nIthemba; \nUthando lwakho lududuza bonke \nAbangabakho. \n\n5. Mawudunyiswe, uzumbuso \nWakho, \nIntando yakho yenziw’ \nEmhlabeni, \nSiph’ ukuphila, usithethelele \nManje nanini.` },
  { id: 140, title: 'Ngokuhlwa, Lishonile Lapho', lyrics: `1. Ngokuhlwa, lishonile lapho \nWaphahlw’ abagulayo, Nkosi, \nBeyilayila izinhlungu, \nKepha bahamba bethokoza. \n\n2. Kunjalo manje sekuhlwile, \nSesiza kuwe sisindiwe, \nNoma ngamehlo ungebonwe \nNokho sikwaz’ ukhona kithi. \n\n3. O Jesu, xosh’ amanqe kithi \nAwokugula nokujabha, \nNabanye bapholil’ uthando, \nAbanye abakakuthandi. \n\n4. Msindisi, Kristu, ungumuntu \nOwavivinywa wahlupheka, \nAmehlo anomusa akho \nAngefihlelw’ inxeba lethu. \n\n5. Usanamatha njengendulo, \nKaphel’ amandla ezwi lakho, \nUsizwe, Nkosi, kulokuhlwa, \nNgas’ isihawu siphilise.` },
  { id: 141, title: 'Idlulil’ Imini', lyrics: `1. Idlulil’ imini, sekuyahlwa, \nAmathunzi ehla ezulwini. \n\n2. Baphumuze, Nkosi’, \nAbasindwayo, \nNgomsa wakho usicimezise. \n\n3. Lapho singenabo ubuthongo, \nI’ngelosi zakho zisibheke. \n\n4. Kuthi la kusayo, usivuse \nSesihlunyelelwe, Moya Muhle. \n\n5. Kadunyisw’ uYise, neNdodana, \nNay’ uMoya Muhle njalonjalo.` },
  { id: 142, title: 'Siyacela Kuwe, Jesu', lyrics: `1. Siyacela kuwe, Jesu, \nYiba-nathi kulendawo; \nKhona sisendlini yakho, \nWoza njengokusho kwakho. \n\n2. Wathi “Lapho behlangene \nAbabili nabathathu, \nBebuthene ngezwi lami, \nNgoba-khona nabo nami.” \n\n3. Thina siyethemba kuwe, \nNjengelizwi lelo lakho, \nYizwa umthandazo wethu, \nSiphe ubusiso lwakho.` },
  { id: 143, title: 'Nkosi, Sihlangene', lyrics: `1. Nkosi, sihlangene, \nSisendlini yakho; \nYiza nawe, Nkosi, \nSesiphambi kwakho. \n\n2. Qhuba izwi lakho, \nMasilizwe lona; \nMalisibonise \nUkuvusa kwakho. \n\n3. Usikhanyisele \nNgeqiniso lakho, \nNgezwi elingcwele \nVus’abantu bakho. \n\n4. Inhliziyo yethu \nIyakukhalela, \nNomphefumlo wethu \nUyakuhlalela.` },
  { id: 144, title: 'Jesu Kristu, Themba Lethu', lyrics: `1. Jesu Kristu, themba lethu, \nSihlangene lapha sonke, \nSizokuzwa izwi lakho; \nJesu, yiba-nathi namhla \n\n2. Jesu Kristu, Simakade, \nMawusiph’ izinhliziyo \nEzifudumele, zonke, \nUkwamkela izwi lakho. \n\n3. Mawumnik’ umkhonzi wakho, \nEkukhuluni kwakhe, \nUMluleki wokumsiza, \nunguMoya OyiNgcwele. \n\n4. Masifundisise kahle \nNgenhliziyo ecwebile, \nNgobukhulu bomsa wakho \nEsisindisiwe ngawo. \n\n5. Vus’ inhliziyo zethu, \nZingalali ekoneni; \nSilamkele izwi lakho \nOsishumayeza ngalo.` },
  { id: 145, title: 'Jesu, Siyabheka Kuwe', lyrics: `1. Jesu, siyabheka kuwe, \nSibuthene ngawe lapha; \nVel’ obala kithi sonke, \nSikubon’ ukob’ ukhona. \n\n2. Hlambulula ngaphakathi, \nPhefumul’ uMoya wakho, \nNgen’ uzinze kithi sonke, \nUsabele ukuphila.  \n\n3. Mawusenze siphelele, \nSifanele ubungcwele, \nSize sime phambi kwakho, \nSibe-naw’ ebukhosini.` },
  { id: 146, title: 'Baba Wethu, Singenile', lyrics: `1. Baba wethu, singenile \nEndaweni eyingcwele; \nWena sewusimemile, \nWoza phela usondele. \n\n2. Mawusiz’ inceku yakho, \nEkufundisweni kwayo; \nMawehlis’ uMoya wakho \nPhezu komphefumle wayo \n\n3. Vul’ izinhliziyo zethu, \nSiliqonde izwi lakho; \nSusa ubumnyama bethu, \nSiphe ukukhanya kwakho. \n\n4. Masihambe emhlabeni \nNjengokusho kwezwi lakho; \nMasingene ezulwini \nNgakho ukusiza kwakho.` },
  { id: 147, title: 'Baba, Sibuthene', lyrics: `1. Baba,sibuthene, \nLaph’ endlini yakho; \nSesifuna ukuphiwa \nNgokwabela kwakho. \n\n2. Ziyashunyayelwa \nIzindaba zakho; \nThina sizakulalela \nOkwelizwi lakho. \n\n3. Lona lingukudla \nEsisutha ngakho, \nLingamanzi okuphila \nEsiphuza kuwo. \n\n4. Kusemnandi konke \nOkwasenkosini, \nMasiphiwe, thina sonke, \nOkwasezulwini. \n\n5. Nkosi, siyabonga \nUkwabela kwakho; \nNalokhu siyacela \nOkomusa wakho.` },
  { id: 148, title: 'E Jehov’ Omkhulu', lyrics: `1. E Jehov’ omkhulu, \nSisondele kuwe; \nNkosi, usisize, \nSikhulek’ okuhle: \nThixo, wena \nUyafuna \nUdumiso \nLwenhliziyo \n\n2. Mawuzwe kalokhu \nUmthandazo wethu; \nUsiphe uMoya \nOvela phezulu; \nMasikholwe \nIzwi lakho, \nSinike \nKuwe, Nkosi.` },
  { id: 149, title: 'Nkosi, Baba, Silizwile', lyrics: `1. Nkosi, Baba, silizwile \nLelilizwi elikhulu; \nIsibili lilungile, \nKanti thina si’zithulu. \n\n2. Sabe-sisebumnyameni, \nKwasekuzalweni kwethu; \nBesihlezi ezonweni \nYonke leminyaka yethu. \n\n3. Weza wena wasibona, \nWasizwisa izwi lakho; \nSiyalizwa, lize lona \nUkwazis’ indlela yakho. \n\n4. Ngakho siyakudumisa, \nSilalele lona futhi, \nLiyisibusiso kithi.` },
  { id: 150, title: 'Nkosi, Siqedile', lyrics: `1. Nkosi, siqedile \nUkufunda kwethu; \nLokhu esikuzwileyo \nKungubomi bethu. \n\n2. Thina singabakho, \nSithi siyizimvu; \nLina ngokwalusa kwakho, \nSingalahlekeli. \n\n3. Masilizwe izwi \nLomalusi wethu, \nNjengezimvu zilalela \nUmalusi wazo.` },
  { id: 151, title: 'Hlala Nathi, Nkosi Yethu', lyrics: `1. Hlala nathi, Nkosi yethu, \nSiphe ububele bakho; \nAsinakuphila thina, \nSiyadinga umsa wakho. \n\n2. Hlala nathi, Langa luthu, \nUsikhanyisele thina; \nSizwe lonke iqiniso, \nSilamkele, siligcine. \n\n3. Hlala nathi, O Mahluli, \nNqoba zonk’ izitha zakho; \nSivikele kumkhohlisi, \nWen’ oyisihlangu sethu. \n\n4. Hlala nathi, O Mlamuli, \nNezwi elimnandi lakho; \nSiqinise singaphuli \nYona imithetho yakho. \n\n5. Hlala nathi, O Mpheleki, \nOsenzele insindiso, \nSiza asikwajwayeli \nUkuhlala konwabiso. \n\n6. Hlala nathi, Thixo wethu, \nMasiphathwe ngomsa nguwe, \nKuthi, engozini yethu, \nNkosi, usihlangulise.` },
  { id: 152, title: 'UJehova Abe-nawe', lyrics: `1. UJEHOVA abe-nawe, \nNgemiqondo akuphathe, \nAkuphas’ ebuthongweni \nSize sibonane futhi. \n\n2. UMsindisi abe-nawe \nNoma usuthuthumela, \nNgezingalo akuthwale, \nSize sibonane futhi. \n\n3. UMduduzi abe-nawe, \nAkugcine njengabakhe \nPhansi kwamaphiko ache, \nSize sibonane futhi. \n\n4. Onguthando abe-nawe, \nAkunik’ uthando lwakhe, \nNokuthula phambi kwakhe, \nSize sibonane futhi.` },
  { id: 153, title: 'Nxa Sahlukana, Nkosi Yethu', lyrics: `1. NXA sahlukana, Nkosi yethu, \nNgamaphimbo linye sesihuba; \nSith’ asibonge siphakula, \nSikhothamel’ ufefe lwakho. \n\n2. Nxa sigoduka, Mgcini wethu, \nSinesizotha say’ inkonzo, \nLond’ izilimine’ nhliziyo \nEzikutheth’ endlini yakho. \n\n3. Nxa sesingena emakhaya, \nQeda usizi nal’ ivuso; \nPhephis’ uland’ usapho lwakho, \nLukuthobele, Nhloko yethu. \n\n4. Nxa sibhekis’ I’ngqondo kuwe; \nSolala sivukela kuwe; \nKuth’ usunqum’ imihla yethu, \nUsibizele kuwe, Nkosi.` },
  { id: 154, title: 'Ingelosi Ziyagwaba', lyrics: `1. Ingelosi ziyagwaba phambi \nKway’ iNkosi. \nIzingubu ziyakhala, zonke aziyeki \nIzinkulungwane ziyayidumisa \niNkosi. \n\n2. Wena, ongenakubonwa ngw’ \nAmehlo ethu, \nKonje, uyanaka ukugwaba \nKwethu zoni? \nKonje, useduze nathi, uyasizwa? \nHe, yebo. \n\n3. Namhla, Nkulunkulu, siyaleth’ \nOkwethu kuwe; \nSiyakhala ukwamkele noma \nKunganele. \nInhliziyo, naz’ izandla, nezwi \nLethu, ‘he, konke.` },
  { id: 155, title: 'Nkosi Yeth’, Udumo Lwakho', lyrics: `1. Nkosi yeth’, udumo lwakho \nLugcwalis’ izulu, \nNezidalwa emhlabeni \nZenz’ intando yakho \nYini into \nEshiyelwa thina? \n\n2. Ith’ iNkosi, iphendula, \n“Nina, bantu bami, \nAngidingi umsebenzi \nNom’ usizo lwenu. \nNoma itshe \nNgingalenz’ inceku. \n\n3. “Engikufisayo kini \nUluthando lwenu \nOluqoq’ uqobo lwenu, \nLubuyele kimi. \nNanso yodwa \nIntokozo yami.” \n\n4. Nkosi int’ oyifisayo \nYob’-intando yethu. \nSokuthande noma yini \nEsivelelayo. \nSiphe umsa \nOsiqinisayo. \n\n5. Konke osenzela khona \nSiyavuma ngakho; \nUkulunga kwakho, Nkosi, \nKuphelele njalo, \nThatha, nakhu \nUkubonga kwethu. \n\n6. Ekujabuleni kwethu, \nEkuhluphekeni, \nOsizini, ekufeni, \nSokuthanda wedwa. \nThatha, Nkosi, \nNant’ uqobo lwethu.` },
  { id: 156, title: 'Baba Wethu,Bavumele', lyrics: `1. BABA wethu, bavumele \nLaba abaphambi kwakho; \nUbavume ubamkele, \nBona bab’-abantu bakho. \n\n2. Jesu, bangabantu bakho, \nNgoba wena wabafela; \nNabo bathi, “Singabakho, \nIzwi lakho silamkele.” \n\n3. Wena, Moya oyiNgcwele, \nYiba-nabo lababantu; \nUbasize banikele \nNgenhliziyo zonke zabo. \n\n4. Mabasizwe njalo bona, \nBakhuthal’ ekulungeni; \nNgokuhamba baqinise, \nBaze baye ezulwini.` },
  { id: 157, title: 'Vumelani Abantwana', lyrics: `1. Vumelani abantwana \nBeze othandweni lwami: \nNingabanqabeli bona \nBangen’ embusweni wami.” \n\n2. Jesu, wena washo njalo \nKubo abafundi bakho; \nNgakho size nabantwana, \nSicel’ ubusiso lwakho. \n\n3. Nampa abantwana bethu, \nSibanike, Nkosi, kuwe; \nMabamkelwe, bab’-abakho, \nBakhanyiswe kahle nguwe` },
  { id: 158, title: 'Yizwanini, Yizwanini', lyrics: `1. Yizwanini, yizwanini, \nIlizwi elihle: \n“Vumelani abantwana \nUkuza kimina.” \n\nAleluya! Mukhulu umusa ka- \nJesu! \nSimenyiwe namhlanje ukuya \nKuyena. \n\n2. Wabafela, wabafela, \nNgokufa okubi, \nBakhululwe ekoneni, \nBahambe ngokuhle. \n\n3. Useduze nakubona \nAbanobuntwana, \nAbahole endleleni \nYokuya ekhaya. \n\n4. Masimbonge, masimbonge, \nOnomsa kangaka, \nSimuthande, simukhonze, \nImihla ngemihla.` },
  { id: 159, title: 'Baba, Menzi Othandayo', lyrics: `1. Baba, Menzi othandayo, sizwe, \nSiyacela kuwe; \nNgobubele usibheke manje, \nNalomntwana wethu; \nSimlethile, esemusha, \nBaba, sizwe, sizwe. \n\n2. Jesu, owafela thina sonke, \nSimlethile kuwe \nAbe-umntanakho: mamukele \nNgobubele bakho, \nUbe-naye engozini, \nIsihlangu sakhe njalo \nUbe-naye engozini, \nJesu, sizwe, sizwe. \n\n3. Nawe, Moya oMakade, sizwe, \nSiyakhala kuwe; \nWoza namhla kulomntwana \nWethu \nWakhe kuye njalo: \nKahlanzeke ngaphakathi \nAbe-nokuphila ngawe. \nKahlanzeke ngaphakathi, \nMoya, sizwe, sizwe. \n\n4. Thixo munye, njengokusho \nKwakho \nSimlethile kuwe; \nEse-musha inhliziyo yakhe \nIbe-indlu yakho: \nKalondeke ngobubele \nAz’ afike ezulwiniKalondeke ngobubele, \nThixo, sizwe, sizwe.` },
  { id: 160, title: 'Uthando Lwakho, Nkosi, Luyabonakala', lyrics: `1. Uthando lwakho, Nkosi luya- \nBonakala \nNgalokhukudla kwakho \nOkungcwele; \nMabeze bonk’ abantu bezw’ \nUkuthi unomusa. \n\n2. Usiphilise, mawusiphe \nNamhlanjena \nUkudla lokhu, mawusigcwalise; \nNjengokudinga kwethu, makube- \nKuithina, Nkosi. \n\n3. Nkosi Okwakho kungukudla \nkokuphila, \nNegazi lakho, l’ ukulunga kwethu; \nSibusisiwe, Nkosi, nxa siku- \nKhumbula njalo. \n\n4. Mawube-nathi, usijabulise, \nNkosi, \nNgamandla akho, mawusiqinise, \nKhona-ke kothi sikufakazele \nKahle, Nkosi. \n\n5. Vusa izinhliziyo zabakithi, Nkosi \nUkuze bathi, bakwamkele bonke \nMbasindiswe, beze badle kanye \nNathi lapha. \n\n6. Kumnandi kithi konke lokhu, \nBaba Nkosi, \nOsusenzele khona ngay’ uJesu; \nKuyoba-nini lapho thina \nSobekana nawe?` },
  { id: 161, title: 'Hlephul’ Isinkwa. Nkos’', lyrics: `1. Hlephul’ isinkwa, Nkos’\nEsokuphila,\nNjengoba wasabi\nNgaselwandle,\nNgiyakufuna,\nUwe isinkwa leso\nsomoya.\n\n2. Hlahlamelisa, Nkos’,\nIsinkwa kimi,\nNjengoba wasandis’\nEGalile.\nKhona ngobusiswa\nNgikhululeke,\nNgothola ukuthula\nKuwe, Nkos’.` },
  { id: 162, title: 'Jesu, Sinkwa Sokuphila', lyrics: `1. Jesu, sinkwa sokuphila\nEsihlephulelwe izwe,\nWayin’ elihle lenhliziyo\nElophiswa ngobubele,\nNguwe owakhiph’ amazwi\nOkuphila nobunene,\nNangokufa kwakh’ okubi\nZafa khon’ izono zethu.\n\n2. Mawbhek’ inhliziyo,\nZaphukile osizini;\nMawubhek’ izinyembezi,\nNaz’ izoni, ziyakhala,\nSidla isithebe sakho,\nSikhumbul’ ukufa kwakho;\nHhayi, uthando! Hhayi, umusa!\nInhliziyo yaneliswa.` },
  { id: 163, title: 'Wafa, wafa, UMkhululi', lyrics: `1. Wafa, wafa, uMkhululi,\nWafa ngenxa yabaphuli\nBemithetho yakhe;\nWafa ukubasindisa,\nWafa ukubangenisa,\nEzulwini lakhe.\n\n2. Hhayi, umusa ungapheli,\nHhayi, umusa usahlezi,\nNokho siwonayo!\nNkosi, wasimangalisa,\nNkosi, wasihloniphisa,\nNgent’ owayenzayo.\n\n3. Lesisikhumbuzo sakho\nSokuhlawulele kwakho\nAmacala ethu,\nKungasingamiswa kithi,\nKungasingahlaba futhi\nEnhliz’ yweni yethu!` },
  { id: 164, title: 'Sibheka Kuwe, Baba, Nkos’ Enobunene', lyrics: `1. Sibheka kuwe, Baba, Nkos’\nEnobunene,\nAsilungile, izindlela zethu zonke\nZimbi:\nSithethelele, Nkos’.\n\n2. Sihlanze, simbathise ngo-\nKulunga kwakho,\nSesize, siph’ amandla akho,\nMawusiqinise,\nNgomusa wakho, Nkos’.\n\n3. Masikukhonze wena onomusa\nWonke,\nNangokuphila kwethu masiku-\nDumise njalo,\nUsamukele, Nkos’.\n\n4. Yizake wen’, owahambela\neGalile,\nKunjalo, masikuzwe nathi,\nNjeng-\nBabelapho,\nSikulandele, Nkos’.\n\n5. Izinhliziyo zethu, Nkos’, ziya-\nDungeka.\nNgoMoya oyiNgcwele ube-nathi;\nSiduduze,\nUsithulise, Nkosi.\n\n6. Owadla kanye nabo abafundi\nBakho,\nUsikhumbule, usenzel’ idili kithi\nLapha,\nUsiphe thina, Nkosi.’` },
  { id: 165, title: 'Sondelani, Sithabath’ Umzimba', lyrics: `1. Sondelani, sithabath’ umzimba\nwoMsindisi,\nMasiphuz’ igazi lilo elophela\nThina.\nAleluya, aleluya, siyabonga\nWena, Nkos’.\n\n2. Sesisindisiwe yiwo lowo-\nMzimba wakhe,\nSithokoza emoyeni, asibong’\niNkosi.\nAleluya, aleluya, siyabonga\nWena, Nkos’.\n\n3. Lo oyiNdodan’ eyodwa esiphila\nNgayo,\nWafa esiphambanweni ukunqob’\nUkufa.\nAleluya, aleluya, siyabonga\nWena, Nkos’.\n\n4. Wanikelw’ uJesu ngenxa yabo\nBonk’ abantu,\nUye ongonikelayo, uy’ ongumnikelo.\nAleluya, aleluya, siyabonga\nWena, Nkos’.\n\n5. Yena owahleng’ abantu,\nObakhanyisayo,\nUyasiph’ amandla onke esidlweni\nSakhe.\nAleluya, aleluya, siyabonga.` },
  { id: 166, title: 'Jesu, uMsindisi Wethu', lyrics: `1. Jesu, uMsindisi wethu,\nYizwa ukuvuma kwethu;\nSesifike ekudleni\nWakumisa ekufeni.\n\n2. Ngokuvalelisa kwakho\nWasho kubafundi bakho,\n“Ngokulonda izwi lami\nNobonis’ ukufa kwami.”\n\n3. Yidlanini lesisinkwa,\nSona singumzimba wami;\nPhuzanini lesisitsha,\nSona siligazi lami.\n\n4. Yebo, Jesu lesisinkwa\nSisamkela ngokukholwa;\nNgokuphuz’ isitsha,\nSikhumbul’ ukufa kwakho.` },
  { id: 167, title: 'Ngimenywa Uwe, Nkosi Yami', lyrics: `1. Ngimenywa uwe, Nkosi yami;\nNgosithabath’ isidlo sakho,\nNgikukhumbula, O Msindisi,\nNgipheth’ ukudla okungcwele.\n\n2. Isinkwa esibusisiwe\nSesingumzimba wakho kimi,\nNgikukhumbula, O Msindisi,\nNangalandeb’ egcwel’ igazi.\n\n3. Sengivulil’ umnyango kuwe,\nNgokungqongqotha kwakho, Jesu,\nNgikukhumbula, O Msindisi,\nUngen’ ube-ongabelayo.\n\n4. Ngikanye nazo izigidi\nEzingabakho emhlabeni,\nZikukhumbula, O Msindisi,\nZidla ukudla lokhu nathi.` },
  { id: 168, title: 'Laph’ Esidlweni Sakho, Jesu', lyrics: `1. Laph’ esidlweni sakho, Jesu,\nUngibonis’ ubuso bakho,\nMangiyiqond’ im’fihlakalo\nYothando olusindisayo.\n\n2. Mangidl’ isinkwa sokuphila,\nNgiphuz’ indebe enhle yakho,\nNgethule phans’ im’thwalo yami,\nNgizwe ngithethelelw’ izono.\n\n3. Lapha, ngimenywa edilini,\nNgidle ukudla komphefumlo,\nMangidle nawe, Nkosi yami,\nNgifakazel’ ukufa kwakho.\n\n4. Nxa sengisuka esidlweni,\nNgizokhumbul’ uthando lwakho,\nNgiqond’ ukuthi wen’ ukhona,\nUsuseduze name njalo.\n\n5. Alukh’ oluny’ usizo kimi,\nAngiyiding’ ingalo enye;\nSenganeliswa, Nkosi yami,\nIthemba lami likuwena.` },
  { id: 169, title: 'Sondelan’ Emzimbeni', lyrics: `1. Sondelan’ emzimbeni,\nOngoweNkos’ uJesu;\nWaf’ esiphambanweni,\nSize siphile.\n\n2. Ethabathil’ isinkwa,\nWabong’ esihlephula,\nWanika abafundi,\nBadla benama.\n\n3. Wathi laph’ ebanika,\nLokhu ngumzimba wami;\nThabathani yidlani,\nNingikhumbule.\n\n4. Ngendebe wathi futhi,\nLokhu igazi lami;\nThabathani, phuzani,\nNinokubonga.\n\n5. Masikhumbul’ uJesu,\nNothando olukhulu,\nSimtuse simbabaze,\nYen, oyiNkosi.` },
  { id: 170, title: 'UJehova Wabadala', lyrics: `1. UJehova wabadala\nLabobantu bokuqala,\nWenz’ umlisa nay’ intombi\nBobabili banyamanye.\n\n2. Lab’ abantu abakithi\nBemi khona phambi kwethu;\nBayavumelana, bathi,\nNamhla bayashada bona.\n\n3. Ubasize, Menzi wabo,\nBaqinise izwi labo;\nBathandane, basizane,\nBangabuyi bahlukane.\n\n4. Mabathemb’ iNkosi njalo,\nYona ize ibasize,\nIbusis’ ikhaya labo\nNokuhlala konke kwabo.` },
  { id: 171, title: 'O Mdali Onguthando', lyrics: `1. O Mdali onguthando, owath’\nEkuqaleni\nWahlanganis’ abantu, bamunye\nEmshadweni,\nNanamhla abemiyo ukuze\nBashadiswe,\nUbaphe injabulo, nothando\nMalwandiswe.\n\n2. O Jes’, owaguqula amanzi\neGalile,\nUbaphe labantwana impilo\nEngadile;\nEzabo izimbiza ngokuhle\nZigcwalise,\nEnjabulweni bazi ukuth’\nUbabusise.\n\n3. O Moya waphezulu, phefumu-\nlela kubo,\nBazuze ubumhlophe’ obuhle\nNjengengubo;\nBaxwaye konk’ ukona, bahlale\nNgokuthula,\nBakhwezan’ empilweni,\nNanomanxa begula.\n\n4. Umuzi wabo, Baba, nxa\nUngakhiwa uwe,\nKosetshenzelwa ize, kuphuth’\nOkuhlosiwe;\nMababe-munye kuwe bakholwe,\nBakhisane,\nUmshado wabo ume, wahlul’\nImpikiswano.` },
  { id: 172, title: 'Wen’ Onguthando Oludlul’ Ukwazi', lyrics: `1. Wen’ onguthando oludlul’\nUkwazi,\nSesithandaza siguqile,\nSithi, uthando luze lungapheli\nKulab’ asebehlanganisiwe.\n\n2. Wen’ owaphil’ impilo ephelele,\nMabakufuze bengabakho,\nBabekezele babe-nesibindi,\nNxa sebehlelwa izinkathazo.\n\n3. Baph’ injabulo ekwahlul’ okubi,\nBenze bezwane nxa kunzima;\nBenezelele ingomuso enhle\nUhambo lwabo seluphela la.` },
  { id: 173, title: 'Sifikile Phambi Kwakho, Kristu', lyrics: `1. Sifikile phambi kwakho, Kristu,\nNgalo lolusuku lwenjabulo,\nSiyacela kuwe, babusise\nLaba, lomakoti nalomyeni.\nSiyacela kuwe, babusise.\n\n2. Walithath’ ibandla lakho, Nkosi,\nLibe-umakoti wakho njalo;\nWena ungumyeni owebandla,\nLona liyanamathela kuwe.\n\n3. Lomakoti kalingis’ ibandla,\nKathandis’ okwakhoke lomyeni,\nKhona beyojabuliswa uwe\nBenenhlanhla noma benosizi.\n\n4. Siyabonga lenjabul’ enkulu,\nLoluthando lwabo nalomshado;\nSiyakudumisa, Baba wethu,\nNeNdodane yakho, nay’ uMoya.` },
  { id: 174, title: 'O Nkosi, Ukushada Lokhu', lyrics: `1. O Nkosi, ukushada lokhu\nKwalab’ abantu bakho,\nMakubusiswe nguwe manje\nNgokuba-khona kwakho.\n\n2. Bahlanganiswa egameni\nElihle loMsindisi,\nMabenz’ we manye kuwe manje,\nBaluzw’ uthabo lwakho.\n\n3. Izintokozo eziyize\nAsizidingi zona;\nQha, ubusiso lwakho, Baba,\nSibacelela lona.\n\n4. Makuthi ezintweni zonke\nBavume wena, Nkosi,\nMakuthi lonk’ uhambo lwabo\nLukudumise njalo.` },
  { id: 175, title: 'Yankulu Injabulo', lyrics: `1. Yankulu injabulo\nKumyeni nomakoti\nAbahanjelw’ uJesu\nEmzini waseKana.\n\n2. Wamenywa emshadweni\nWavum’ ukuya khona,\nKwaqina ukwethaba\nAbabe-nakho bonke.\n\n3. Zana kithina, Nkosi,\nUbabusise laba\nAbez’ endlini yakho,\nBahlanganiswe nguwe.\n\n4. Uxosh’ ububi kubo\nNgesibusiso sakho.\nUlungisel’ indlela\nAbangenayo kuyo.\n\n5. Mawube-nabo, Nkosi,\nZonk’ izinsuku zabo;\nUbaph’ inhlalo enhle\nUkube bathandane.` },
  { id: 176, title: 'Mlalelen’ uJesu Ethi', lyrics: `1. Mlalelen’ uJesu ethi\nOngisebenzel’ ubani?\nYiskhathi sokuvuna\nOzongivunel’ ubani?\nYizwa, nangu ekubiza,\nWen’ uqobo uyafunwa;\nYisho, ungavuma yini,\nUthi, “Nkosi, nangu mina.”\n\n2. Noma ungenakuhamba\nUye kude emazweni,\nNamp’ eduze abaningi\nAbakudingayo wena.\nNom’ imali ingeningi,\nUngamkhonza ngakh’ onakho,\nKoba-mnandi eNkosini\nKonke oyenzela khona.\n\n3. Uz’ ungasho ngobuvila,\nAnginakh’ engingakwenza.\nNamp’ abafa ezonweni,\nNans, iNkosi ikuthuma.\nYenza akunika khona,\nUthokoz’ ukuyikhonza,\nUsabele nxa ubizwa,\nUthi, Nkosi nangu mina.` },
  { id: 177, title: 'O Nkosi Yokuphila', lyrics: `1. O Nkosi yokuphila\nSibuthe thina,\nSihlome izikhali,\nSilwele wena.\nSiphum’ izimpi zakho,\nSisiz’ abantu bakho\nNgamandla ethu sonke,\nSilwele wena.\n\n2. O Jesu, owalingwa\nNjengathi sonke,\nSisize sinqobise,\nSilwele wena,\nSinqob’ izono zethu,\nSilunge, sibe-mhlophe,\nSinik’ umusa wakho,\nSilwele wena.\n\n3. Masiphuthume bona\nAbahaqiwe\nIzitha zomphefumlo,\nSilwele wena;\nSelekelele bonke\nAbalwa noSathane,\nSibasondeze kuwe,\nSilwele wena.` },
  { id: 178, title: 'Lowomuzi Okhanyayo', lyrics: `1. Lowomuzi okhanyayo\nObubonw’ abaprofeti,\nOkukhanya kwaphakade\nKuwukhanyisela njalo;\nKuhla!’ abangcwele bodwa\nKulomuz’ othenjiswayo,\nAkungen’ okubi kuwo,\nKunguthand’ olubusayo.\n\n2. Thina singabakhi bawo,\nUyavela emhlabeni,\nSizimisa izindonga\nNgaz’ izenzo zeth’ ezinhle.\nMasifak’ amatsh’ amahle\nAhlobis’ umuzi lowo,\nSingasiza ukufeza\nOkuhloswe uMsindisi.\n\n3. Lokho esikubekayo\nNgakh’ ukukhuthala kwethu\nAkuyikunyamalal,\nNgeke siphuthelwe yikho;\nKuzokhanya njalonjalo\nSekubusa ukulunga,\nKukhulis’ inkazimulo\nYalomuzi wokukhanya.` },
  { id: 179, title: 'Ibandla LikaKristu Malikhaliphe', lyrics: `1. Ibandla likaKristu malikhaliphe;\nKugcwele emhlabeni uvalo olubi;\nIzizwe zicwasene, zisongelana kabi,\nIthemba lokuthula linguy’ uKristu.\n\n2. Ibandla liyinqaba yemiphefumlo,\nImpilo yonke yethu isuka kulo;\nIm’shado ibusiswa, abafi bayafihlwa,\nIndlela neqiniso kutholwa kulo.\n\n3. Aliyinqaba yodwa, libizwa uye,\nLilwel’ umbuso wakhe la emhlabeni,\nLichith’ ubandlululo limis’ ubuzalwane,\nKuhlalwe emhlabeni ngenkululeko.\n\n4. Nakuba kusemnyama uvalo lubhaqa,\nSihlos’ akuhlosayo sithemba yena;\nSesibuthene lapha sifun’ intando yakhe,\nUkudumisa kwethu kuvus’ inhloso.\n\n5. Malibe-nobuqhawe ibandla lakhe,\nEzakhe izikhali zingezoMoya,\nIlizwi liyinkemba, umkhonto umthandazo,\nAloze laphathelwa inqob’ enkulu.` },
  { id: 180, title: 'UMsindis’ UJesu, Lapha Esekhona', lyrics: `1. Umsindis’ uJesu, lapha esekhona,\nWayehamba izwe labaJuda lona,\nWayebafundisa, wayebaphilisa,\nKwelakwaIsrael, wayebasindisa.\n\n“Hambanini namhla ezizweni zonke,\nNgoba-nani ngezikhathi zonke.”\n\n2. Wathi ezomuka aye ezulwini,\nWabuthela abafundi entabeni,\nWathi, “Nginikiwe onk’ amandla mina,\nHambanini ezizweni zonke nina.”\n\n3. “Nenze abafundi ebantwini bonke,\nNibafundisise ukugcina konke,\nEnganifundisa, ngisekhona nani;\nNingesabi lutho, mbala ngoba-nani.”\n\n4. Wathi, “Niyakubashumayeza, nithi,\n‘Okholwayo uzosinda kanye nathi.’\nNaye ongevumi ukukholwa yimi,\nWobhujiswa yena, ongeziyo kimi.”` },
  { id: 181, title: 'UJesu Wabatshela', lyrics: `1. UJesu wabatshela\nAbalandeli bakhe\nEsezakubuyela\nEkhaya ezulwini,\nHambani nifundise\nNgegama leli lami,\nIzizwe nizazise\nIndaba yonke yami.\n\n2. Hambani nimemeze\nElami ivangeli,\nNibafundis’ abantu\nAmazw’ omthetho wami;\nOkuthi, okholwayo\nWoba-Osindiswayo.\nNokuthi ongalayo Woba-obhujiswayo.\n\n3. Hambani emandleni\nAphiwe onke kimi,\nBhekani, ngoba-nani\nNakhon’ ekupheleni,\nEkusho wenyukela\nPhezulu ezulwini;\nBasuka bay’\nEzweni, Beshumayela izwi.` },
  { id: 182, title: 'Yaziw’ Ezweni Nasezulwini', lyrics: `1. Yaziw’ ezweni nasezulwini,\nImnandi ngoba iqiniso,\nIndab’ endala, intsha njalo;\nQhub’ indaba kaJesu.\n\nQhub’ indaba kaJesu,\nQhub’ indaba kaJesu,\nOwangithanda\nNgingakamazi,\nQhub’ indaba kaJesu.\n\n2. Kobuna kufe okuyimbali,\nLisithw’ ilanga amafu emvula,\nKoshesh’ okuhle ukudlula.\nQhub’ indaba kaJesu\n\n3. Bayaf’ abantu bengamazi,\nBakhala besindw’ izaphulo;\nMasiphuthume sibephule.\nQhub’ indaba kaJesu\n\n4. Ubomi sesibufumene,\nNendawo yethu ezulwini,\nNanini siyovuma njalo,\nQhub’ indaba kaJesu.` },
  { id: 183, title: 'Thabani, Thabani, Sesiyez’ Isikhathi', lyrics: `1. Thabani, thabani, sesiyez’\nIsikhathi,\nThabani, thabani, kokhahlel’\nEhlane;\nMasimemeze sivume,\nMasimemeze sivume\nKuJehova, simkhulise.\n\n2. Thabani, thabani, lifikil’\nIvangeli,\nThabani, thabani, izizwe zosinda;\nKoshunyayezwa izizwe,\nKoshunyayezwa izizwe\nZabantu bonke belizwe.\n\n3. Thabani, thabani, sesiyez’\nIsikhathi,\nThabani, thabani, kokhahlel’\nEhlane;\nBon’ abahlakazekile\nBon’ abahlakazekile\nBohlabelel’ IJubile.` },
  { id: 184, title: 'Sisebusweni Bakho', lyrics: `1. Sisebusweni bakho,\nBaba, Nkosi yethu,\nSifun’ umusa wakho,\nNgomthandazo wethu;\nSizwile ukukhala\nKwabalahlekile,\nSiyabathandazela,\nNkosi, mabaphile.\n\n2. Izizwe eziningi\nZisebumnyameni,\nZisendleleni embi\nEya ekufeni;\nYiba-nomusa kuzo,\nZiphe izwi lakho,\nSus’ ubumnyama bazo\nNgokukhanya kwakho.\n\n3. Thumel’ abafundisi,\nBenamandla akho,\nBatshel’ abantu bonke\nIzindaba zakho;\nUmbuso wakho uze\nEmhlabeni wonke\nYandis’ abantu bakho\nEzizweni zonke.\n\n4. Sheshisa isikhathi\nEsimnandi sakho\nLapho abantu bonke\nBoba-nezwi lakho;\nBamazi uJehova\nOnguMenzi wabo,\nBamthand’ uJesu Kristu\nuMsindisi wabo.` },
  { id: 185, title: 'Koba Nini, Laph’ Amazwe', lyrics: `1. Koba nini, laph’ amazwe\nAlomhlaba okhanyiswa?\nLapha njengasezulwini\nMadunyisw’ uThixo yedwa.\n\n2. Mawuze umbuso wakho,\nNkosi yamakhosi onke.\nBuyisel’ izizwe kuwe,\nBusa izindawo zonke.` },
  { id: 186, title: 'Khangel’ INkos’ UKristu', lyrics: `1. Khangel’ iNkos’ uKristu,\nUkhany’ umkhathi wonke;\nAnakusithakala\nEmehlweni ethu.\nWakhanya engabonwa,\nManje waziwa naphi;\nUkhanya-nje abonwe,\nAkanakuphelaphi.\n\nKhangel’ iNkos’ uKristu,\nUkhany’ umkhathi wonke;\nAnakusithakala\nEmehlweni ethu.\n\n2. Kuwena, Jesu Kristu,\nSiguqa ngamadolo;\nSikhonza, siyabonga\nOngenansolo.\nAkakho ongakhohlwa\nOkwenzileyo konke;\nIlanga seliphume,\nAkusenakh’ ukuhlwa.\n\n3. Kukhanya kwezwi leli,\nKhanwsa izwe lakho,\nUkwenze konk’ okwethu\nKugcwal’ ubuhle,\nNezizwe zezwe lonke\nZiphume ekoneni,\nZidalwe ngakh’ okusha,\nZingen’ ekukhanyeni.` },
  { id: 187, title: 'UJesu Uzobus’ Umhlaba', lyrics: `1. UJesu uzobus’ umhlaba,\nUwonk’ ophansi kwal’ ilanga,\nUmbuso wakh’ umboz’ ulwandle,\nKuphele bonke ubumnyama.\n\n2. Izizwe zezilimi zonke\nZihub’ ingoma yal’ uthando\nNabancinyane bazocula,\nBalibabaz’ igama lakhe.\n\n3. Izibusiso ziyandiswa,\nZihub’ ingoma yal’ uthando\nNabancinyane bazocula,\nBalibabaz’ igama lakhe.\n\n4. Makuphakame izidalwa,\nZiyidumis’ iNkosi yethu,\nKwehl’ I’ ngelosi zinehubo,\nUmhlaba wonke mawuvume.` },
  { id: 188, title: 'Jesu, Nkosi Yethu', lyrics: `1. Jesu, Nkosi yethu,\nYiba-nathi sonke;\nSesamkele izwi lakho,\nNgenhliziyo yonke.\n\n2. Yiba-nathi sonke,\nSilibambisise;\nVusa I’nhliziyo zethu,\nZilithandisise.\n\n3. Kade abaningi\nBese bumnyameni;\nKweza ukukhanya kwakho\nKubakhanyisile.\n\n4. Namhla, Simakade,\nBayakudumisa;\nAbakade bekuphika\nBakubonga namhla.\n\n5. Kepha abaningi\nBasesekoneni,\nNgawubaphendula bonke,\nBonke basindiswe.\n\n6. Jesu, Simakade,\nYiba-nathi sonke;\nSikhanyise ngaphakathi\nNgokulunga kwakho.` },
  { id: 189, title: 'Vuthelani Icilongo', lyrics: `1. Vuthelani icilongo,\nNina, bantu bakhe,\nIcilongo lezwi\nLakhe, lihlokomiseni.\n\n2. Malihambe ivangeli\nElizweni lonke,\nLize lamukelwe lona\nAbakithi bonke.\n\n3. Vuthelani icilongo,\nNina, bantu bakhe;\nMalizwiwe izwi lalo\nNgabangakalizwa.\n\n4. Vuthelani icilongo,\nNina, bantu bakhe;\nMalihambe izwi lakhe\nNgokushesha konke.\n\n5. Naz’ izizwe ezikude\nMazilazi lona;\nZikhonjiswe konguJesu,\nZimuthande Yena.` },
  { id: 190, title: 'Baba, Sesibusisiwe', lyrics: `1. Baba, sesibusisiwe\nNgalo izwi lakho;\nSafundiswa, sakhanyiswa\nNgokukhanya kwakho\n\n2. Ngakho siyabakhumbula\nAbasezonweni;\nBayadinga, behlupheka,\nBasebumnyameni.\n\n3. Lapha siyayinikela\nIm’nikelo yethu;\nMayihambe ikhanyise\nIzihlobo zethu\n\n4. Baba, mawukwamukele\nEsikunikayo;\nUkuphathe, ubusise\nAbasadingayo.` },
  { id: 191, title: 'Ninethuba Lokulizwa', lyrics: `1. Ninethuba lokulizwa\nIzwi likaJesu,\nMusanini ukunqaba\nNge’ nhliziyo zenu.\n\n2. Soba-khona isikhathi,\nYoba-khon’ indawo,\nLapho bezokhala khona\nAbasanqabayo.\n\n3. Mazivulw’ izinhliziyo,\nZivumele lona,\nLize lime njalo kuzo,\nLiholele zona.\n\n4. Nisamenywa njalo namhla\nNize nisindiswe;\nMusanini ukwenqena,\nSukanini nize.\n\n5. Sekuyiskhath’ esihle\nSabo abonayo;\nIzwi likaJesu lithi,\n“Ngomankel’ ozayo.”` },
  { id: 192, title: 'Yizwanini, Bantu Nonke', lyrics: `1. Yizwanini, bantu nonke,\nNibe-nenjabulo;\nNiqaphele Ivangeli\nElimemayo.\n\n2. Nina bantu nilambile,\nNisalidla ize;\nWozanini eNkosini,\nNosuthisw’ ukudla.\n\n3. Nina bantu enomile,\nNingenakuphuza,\nPhuzanini emanzini;\nNanka, akuJesu.` },
  { id: 193, title: 'Landa Indaba Endala', lyrics: `1. Landa indaba endala\nYombuso ophezulu,\nNgoJesu nobukhosi,\nNothando olukhulu.\nLanda indaba kahle,\nNginjengomntwan’ omncane\nUmoya udangele,\nNamandla aphelile.\n\nLanda indaba endala,\nLanda indaba endala,\nLanda indaba endala,\nNgoJesu nothando.\n\n2. Landa kancane; ngitshele\nUkuze ngiyamkele\nLendaba yempiliso,\nNgokub’ iyinsindiso.\nLanda indaba njalo,\nNgikhohlwa masinyane;\nBhek’ amazol’ okusa\nSeyledlulil’ emini.\n\nLanda indaba endala,\nLanda indaba endala,\nLanda indaba endala,\nNgoJesu nothando\n\n3. Landa indaba kahle,\nQinisa ngeqiniso,\nYimina lowomon’\nUJesu amzelayo.\nLanda lendab’ emnandi,\nUma impel’ uthanda\nUbe- oduduzayo,\nLapho ngihluphekayo.\n\n4. Landa indaba leyo\nUma ubon’ ukuthi\nIzinto zalomhlaba\nZingenza impumputhe.\nUma lelozw’ elihle\nSengifa ngolibona,\nYiland’ indaba leyo\nNgoJesu, uMsindisi.` },
  { id: 194, title: 'Wena Ongohluphekayo', lyrics: `1. Wena ongohluphekayo.\nWoza kimi.\nWena ongothwesiweyo.\nWoza kimi.\nLithabath’ ijokwe lami,\nMawuthwal’ umthwalo wami\n\n2. Lithambil’ ijokwe lami,\nWoza kimi,\nUlulan’ umthwalo wami,\nWoza kimi.\nNgithobile, funda kimi,\nNawe wophunyuzwa yimi,\n\n3. Nginomusa nobunene,\nWoza kimi\nNgakuthanda ekuteni,\nWoza kimi.\nNgalithwal’ icala lakho.\nNgoyekel’ izono zakho.\n\n4. Ngokuphatha emhlabeni,\nWoza kimi,\nNgokusiza ekufeni,\nWoza kimi.\nEmva wobusiswa name\nEmbuswen’ omkhulu wami.` },
  { id: 195, title: 'Nina Enikhatheleyo', lyrics: `1. Nina enikhathaleyo,\nEneduka eNkosini,\nWozanini kuMsindisi\nOwafela thin’ aboni;\nNxa nifuna ukuthola\nUkucweba kwenhliziyo.\nNganigeza ecibini\nEligcwel’ igazi lakhe.\n\n2. Endaweni yokweduka,\nLapho niya engozini,\nWozanini khona-manje.\nNifumane ukulunga\nOkukhona eNkosini,\nOkukuyo ukuphela.\nNize nizozuz’ ubomi\nKuyo, ngoba yanifela.\n\n3. Manikholwe kulelizwi\nEliyiqiniso njalo;\nSeniphiwe iNdodane\nNguy’ uYis’ onithandayo;\nPhumulani thokoze,\nNina enikhatheleyo,\nNgoba ingumthunz omuhle\nEniyakuphumla kuwo.\n\n4. Manje thokozani nina,\nNifumane emhlabeni\nUkuphila okufana\nNakho okusezulwini;\nLapho akungen’ ukona\nNobusuku abaziwa,\nAsidingwa nesibani,\nYen’ uJesu ulilanga.` },
  { id: 196, title: 'O Ndodana kaDavide', lyrics: `1. “O ndodana kaDavide,\nUngihawukele!”\nWasho njal’ oyimpumputhe\nEzodlul’ uJesu.\n\n2. Abakhona babemkhuza,\nBathi, makathule,\nKepha wamemeza ethi,\n“Unguhawukele!”\n\n3. Wem’ uJesu, wathi kuye,\n“Ngikwenzele ntoni?”\nYena waphendula wathi,\n“Nkosi, mangibone!”\n\n4. Wath’ uJesu, “ukukholwa\nKukusindisile.”\nKhon’ amehlo evuliwe,\nWamlandel’ uJesu.\n\n5. Nonke enihluphekayo,\nNangu uMsindisi,\nKayikumalel’ umuntu\nNxa ekholwa uye.` },
  { id: 197, title: 'Ukhathele, Udangele', lyrics: `1. Ukhathele, udangele,\nUnosizi na?\n“Woza kimi,” Ush’ uJesu\nKwabanje.\n\n2. “Ziph’ I’mbavu zingihole\nNgize kuye na?”\n“Ezandleni, e’nyaweni\nZibheke.”\n\n3. “Unomqhele wobukhosi\nOmkhombayo na?”\n“Yebo, kodwa ngowameva\nKuyena.”\n\n4. “Nxa ngimfuna ngimlandela,\nNgozuzani na?”\n“Izinsizi nobunzima\nNokunje.”\n\n5. “Nxa ngimcela angamkele\nUzonqala na?”\n“Ngek’ akwale, qha, nakanye,\nMthembe-nje.”\n\n6. “Nxa ngimthemba ngimlandele\nNgobusiswa na?”\n“bathi, ‘Yebo,’ abangcwele\nLaphaya.”` },
  { id: 198, title: 'Uyadlula Ngokushesha', lyrics: `1. Uyadlula ngokushesha;\nKonje ubengaphi na?\nUyayaz’ indlela lena\nOsahamba ngayo na?\nUyadlula, uyadlula\nUya ezulwini na?\n\n2. Uyadlula ngokushesha;\nLingemisw’ ilanga, qha,\nLiyaphuma, liyashona,\nAwuyikushona na?\nUyadlula, uyadlula,\nAwunakuhlala la.\n\n3. Uyadlula ngokushesha;\nUyadlulelaphi na?\nEzulwini ungengene,\nUngaphendukanga, qha.\nUyadlula, uyadlula,\nWophenduka nini na?\n\n4. Uyadlula ngokushesha;\nKusondel’ ukufa ha!\n“Akumang’ ungenathuna;\nUyophepha wena na?\nUyadlula, uyadlula,\nAkukheth’ ukufa, qha.\n\n5. Uyadlula, ngokushesha;\nUyekelw’ izono na?\nNamhla yisikhath’ esihle\nUngesinde laphaya.` },
  { id: 199, title: 'Isikhathi Sifushane', lyrics: `1. Isikhathi sifushane,\nNina, zoni, lalelani!\nIminyaka iyadlula,\nMasinyane iyaphela.\n\n2. Isikhathi sifushane,\nNina, zoni, phangisani.\nNamhla nina niyabizwa\nuMsindisi onomusa.\n\n3. Isikhathi sifushane,\nNina, zoni, khothamani,\nNiwe phansi, nimdumise\nuMsindis’ uJesus Kristu.\n\n4. Isikhathi sifushane,\nThokozani bantu bakhe,\nWosondel’ uJesu Kristu,\nNina nonke wonamkela.` },
  { id: 200, title: 'Yizwani Izindaba', lyrics: `1. Yizwanini izindaba,\nYizwani boni nonke,\nNilapha emhlabeni,\nEzindaweni zonke;\nKuzwiwe ngaphezulu,\nKuzwiwe nangaphansi;\nMasizwe nesithulu,\nNosenhla nosenzansi.\n\n2. Wabuba uMkhululi,\nWachith’ igazi lakhe;\nWafela abaphuli\nBaphul’ umthetho wakhe.\nBengona nge’ nto zonke,\nNokho wangisindisa;\nUngiyekele konke.\nNgakho ngiyamdumisa.\n\n3. Ngiswele imilomo\nIbe-yinkulungwane\nIbonge ngenhlokomo\nUmusa nobunene;\nNgisize, Nkosi yami,\nNgitshel’ izizwe zonke\nUkuthokoza kwami,\nKubong’ abantu bonke\n\n4. Igama lakho, Jesu,\nLimnandi endlebeni,\nUmusa wakho, Jesu,\nUmnandi enhliz’yweni.\nKubonga obekhala,\nKuvuka obefile,\nNgoJesu basindile,\nNgoJesu bavukile.` },
  { id: 201, title: 'Ujesu Usabiza', lyrics: `1. UJesu usabiza \nBonk’ abakhatheleyo; \n“Zanini nophunyuzwa, \nNin’ enithwesiweyo; \nZanini kimi nonke, \nNina enikhalayo; \nNgonikhulula nonke, \nNina eniboshiweyo.” \n\n“Zanini enikhatheleyo, \nZanini enithwesiweyo.” \n\n2. “Zanini ekudleni, \nNin’ enilambileyo; \nZanini emanzini, \nNani enomileyo. \nZanini nisondele, \nNonke enivumayo; \nNgingeze ngamalela \nNoyedwa ofunayo.”` },
  { id: 202, title: 'Izwi Lithi, Yizwanini', lyrics: `1. Izwi lithi,”Yizwanini, \nNina, bami, ngonikhombisa; \nEndleleni ey’ ezulwini, \nNgeso lami ngoniqondisa. \n\n“Ngeso lami, ngeso lami, \nNgeso lami ngoniqondisa; \nEndleleni ey’ ezulwini \nNgeso lami ngoniqondisa.” \n\n2. Ngokuthuswa kwabalindi \nNezilingo seziniqhuba; \nNokho yiman’ isibindi, \n“Ngeso lami ngoniqondisa.” \n\n3. Mhla kushon’ izithembiso, \nKanye nakh’ ebenikufisa; \nLelolizwi lizosiza, \n“Ngeso lami ngoniqondisa.” \n\n4. Nom’ ukufa kusondele, \nUmphefumlo kuwumukisa, \nUMsindisi angenidele – \n“Ngeso lami ngoniqondisa.”` },
  { id: 203, title: 'Nom’ Izono Zenu Zibomvu', lyrics: `1. Nom’ Izono Zenu Zibomvu, \nZiyaba-mhlophe qhwa; \nNoma zibomvu tebu, \nZoba-njengeqhwa \nNom’ izono zenu zibomvu, \nZiyakuba-mhlophe qwa. \n\n2. Vumanini elincengayo, \nBuyelani kuThixo; \nUnomusa ovamayo, \nNal’ uthando du. \nVumanini elincengayo, \nBuyelani kuThixo. \n\n3. Ngonithethelela izono, \nFuthi ngozikhohlwa nya; \nQazani mina, bantu, \nYon’ iNkosi qwi. \nNgonithethelela izono, \nFuthi ngozikhohlwa nya.` },
  { id: 204, title: 'Wafika Esezwile NgoJesu', lyrics: `1. Wafika esezwile ngoJesu, \nUkuthi uMsindisi; \nWawunamath’ umphetho \nWengubo, \nWasinda khona-nje. \n\nNamath’ umphetho wengubo, \nUsinde nawe la; \nNgamandla akhe asindisayo \nUzakuphila nya. \n\n2. Wezak’ esaba ethuthumela, \nEkwaz’ okwenziweyo; \nWawezw’ amandla amphilisayo, \nWavuma konke la. \n\nNamath’ umphetho wengubo, \nUsinde nawe la; \nNgamandla ahe asindisayo \nUzakuphila nya. \n\n3. INkosi yathi, Yim’ isibindi, \nNgenkolo usindile.” \nWahamba kahle ethokozile, \nEthembe eNkosini.’` },
  { id: 205, title: 'Ngingahlanzwa Ngani Na', lyrics: `1. Ngingahlanzwa ngani na? \nIgazi likaJesu lodwa. \nNgingasinda ngani na? \nIgazi likaJesu lodwa. \n\nIgugu leli kimi, \nLingenza ngibe-mhlophe; \nUmthombo wodwa wam’, igazi \nlikaJesu lodwa. \n\n2. Nant’ elokuhlanzwa kwam’, \nIgazi likaJesu lodwa; \nNokuthethelelwa kwam’, \nIgazi likaJesu lodwa. \n\n3. Naso ‘sihlawulo sam’, \nIgazi likaJesu lodwa; \nAkusikh’ ukwenza kwam’, \nIgazi likaJesu lodwa. \n\n4. Nakho ukuthula kwam’, \nIgazi likaJesu lodwa; \nNakho ukulunga kwam’, \nIgazi likaJesu lodwa. \n\n5. Ngingahlanzwa ngani na? \nIgazi likaJesu lodwa; \nNgingasinda ngani na? \nIgazi likaJesu lodwa.` },
  { id: 206, title: 'Thina Masisuke Sonke', lyrics: `1. Thina masisuke sonke, \nEkoneni kwethu; \nSiye ngenhliziyo yonke \nENkosini yethu. \n\nWakufel’ uJesu, \nWangifela mina, \nWabafel’ abantu bonke, \nBeze basindiswe. \n\n2. Imikhuba yalomhlaba \nAyisizi lutho; \nSinovalo, siyesaba, \nSingethembe lutho. \n\n3. Masibheke ngaphezulu, \nENkosini yethu; \nElenzile lon’ izulu, \nKanye nezwe lethu. \n\nWakufel’ uJesu, \nWangifela mina, \nWabafel’ abantu bonke, \nBeze basindiswe. \n\n4. Siyakubusiswa thina \nEkuzeni kwethu; \nSibe-nakho ukubonga \nNgenhliziyo yethu.` },
  { id: 207, title: 'Woza, Moni Odangele', lyrics: `1. Woza, moni odangele, \nOgulayo, olimele, \nNans’ inyanga, uMsindisi, \nEnothando nesihawu, \nEnamandla: \nKuyo ungasind’ impela. \n\n2. Nongenanto uvunyelwe, \nThenga umsa ophelele, \nNokukholwa okugcwele, \nNomsa wonke osondeza \nWena, mdingi; \nThenga ngeze eNkosini. \n\n3. Bhek’ uJesu ensimini, \nEkhothama osozini, \nMbheke esiphambanweni, \nMuzwe esho ekufeni, \n“Kuphelile.” \nYisho, moni akwanele? \n\n4. Wenyukele ezulwini, \nOnk’ amandla asekuye. \nThemba kuye, themb’ impela, \nThemb’ iNkosi ukuphela; \nKuyo yodwa, \nUngasinda uphelele.` },
  { id: 208, title: 'UJesu Uyabiza', lyrics: `1. UJesu uyabiza, \nWozake, moni. \nUyazibiz’ izoni, \nWozake, moni, \nKuyil’ ithub’ elihle, \nWozake, moni. \nKuyisikhathi manje, \nWozake, moni. \n\n2. Sekuyasindwa yini? \nWozake, moni, \nUyakukuphumuza, \nWozake, moni, \nUJesu kakhohlisi, \nWozake, moni, \nUyakunik’ ubomi, \nWozake, moni. \n\n3. O yizwa esancenga, \nWozake, moni \nUyakubusisa, \nWozake, moni. \nSekade akubiza, \nWozake, moni. \nNa kalokh’ uyabiza, \nWozake, moni.` },
  { id: 209, title: 'Wozake, Masiye Ezweni', lyrics: `1. Wozake, masiye ezweni \nLobomi, \nIkhaya labahl’ abahlezi kulo. \nUthini, sihambi, ngendlela \nYokona? \nUthini? Wovuma ukuya kulo? \n\nWoya na? Woya na? Woya na? Woya na? \nVumake ukuya, ukuya phezulu \n\n2. Ayikh’ inhlupheko kubantu \nBakhona, \nKabezwa ukufa nosizi bona, \nBehlala neNkosi, ibapha ubomi; \nUthini? Wovuma ukuya \nKhona? \n\n3. Yekak’ ukuthanda izinto \nZomhlaba, \nZomuka zophela masinya zona; \nBhekake phezulu, imfuyo yakhona. \nUthini? Wovuma ukuya \nKhona? \n\n4. Oshaywa uvalo ngokwakhe \nUkona, \nOkhala efuna ukukhululwa, \nMakeze kuJesu, oyindlela \nYobomi; \nUthini? Isango likuvulelwe! \n\n5. Thabani maKristu, ngekhaya \nLobomi, \nSoshesh’ ukufika ekuphumu- \nLeni; \nSohlala noKristu- yizwani \nNiqonde! \nNithini? Ninjani \nEzinhliz’yweni? \n\nSoya na? Soya na? Soya na? Soya na? \nO Mfeli waboni, sisize manje!` },
  { id: 210, title: 'Buya, Mphefumulo Wami', lyrics: `1. Buya, mphefumulo wami! \nYiza manje eNkosini, \nBuya namhla ezonweni, \nMawungayi ekufeni; \nBuya, mphefumlo wami! \n\n2. Khala, mphefumulo wami! \nKhala ngaz’ izono zakho; \nZonk’ izono zilihlazo, \nNokho mina ngingonazo; \nKhala, mphefumulo wami! \n\n3. Shesha, mphefumulo wami! \nYiza manje kuMkhululi, \nVuma zonk’ izono kuye, \nZonke zihlangulwa nguye; \nShasha, mphefumulo wami! \n\n4. Themba, mphefumulo wami! \nKholwa manje eNkosini; \nYesa yona emhlabeni \nNgize ngiye ezulwini; \nThemba, mphefumulo wami! \n\n5. Vuma, mphefumulo wami! \nKowazinikela ngawe, \nWeza yena wakufela, \nManje usekuhlalele; \nVuma, mphefumulo wami!` },
  { id: 211, title: 'Sabelani Nibizwa', lyrics: `1. Sabelani nibizwa, \nNguy’ uKristu, iNkosi; \nUyabiza izoni \nZize kuye manjena. \nWozanin’ emthonjeni \nOnobomi beNkosi, \nNiyabizwa manjena, \nSukanini manize. \n\nWozanini manjena, \nWozanini nonkana, \nNiya izwa uKristu, \nSukanini manjena. \n\n2. Sabelani nibizwa \nNguMhlamuli wezoni; \nKade wasilamlela, \nKuy’ uYis’ ophezulu. \nManjena usabiza, \nAsigez’ egazini \nElaphuma kuyena, \nSibe-mhlophe kuneqhwa. \n\n3. Sabelani nibizwa \nOyindlela yenhlanhla; \nHambanini kuyona, \nYoniyisa phezulu. \nUyindlela yobomi, \nEkhawul’ ezulwini, \nSheshanini ningene, \nKulithuba manjena. \n\n4. Sabelani nibizwa \nNgalomzuzu omuhle; \nUyinhlanhla enkulu, \nLa nivuma manjena. \nSuka, woza, kalokhu \nUyabizwa nguMoya; \nNgokuzibambezela, \nUkulahlwa kuwena.` },
  { id: 212, title: 'Mntwana Onezono', lyrics: `1. Mntwana onezono, \nUnesabe; \nMawungathi, “Ngomso” \nWoza namhla, \nUmenyiwe \nUsindisiwe; \nMntwana onezono, \nYizwa wena. \n\n2. Mntwana onezono, \nUyakufa; \nCela ubusiso \nKuJehova \nOnamandla \nOkusiza. \nMntwana onezono, \nFuna lona. \n\n3. Mntwana onezono, \nWoya ngaphi? \nNgesikhathi leso \nEsofika \nSikuqeda \nUkuphila; \nMntwana onezono \nWoya ngaphi? \n\n4. Mntwana onezono, \nBheka kuye, \nUMsindisi wethu \nOsifele; \nWoza kuye, \nWoza manje, \nMntwana onezono, \nWosindiswa.` },
  { id: 213, title: 'Nang’ uMsindisi', lyrics: `1. Nang’ uMsindisi, nang’ \nuMsindisi \nWosisindisa thina; \nUyasibiza namhla: \nSizakuthini manje \nKuyena ozileyo? \n\n2. Uyasithanda, uyasithanda, \nKakhulu, ‘he kakhulu; \nIgazi walichitha, \nUkufa wakuvuma, \nNgokusithanda kwakhe. \n\n3. Uyasincenga, uyasincenga, \nUthi, “Wozani nonke, \nNin’ abathwesiweyo, \nNin’ abalambileyo, \nManize nina nonke. \n\n4. “Manize kimi, manize kimi, \nEninosizi nonke, \nNin’ abahluphekayo, \nNin’ ababoshiweyo, \nWozani, nize kimi.” \n\n5. Siyakuthini? Siyakuthini? \nKuyena ozileyo, \nKuyen’ osithandayo, \nKuyen’ osincengayo, \nSesiyavuma yini?` },
  { id: 214, title: 'Cish’ Ukuvuma', lyrics: `1. Cish’ ukuvuma \nUbe-umKristu \nCish’ ukuvuma \nUkukholwa. \nNokho uthi, wena, \n“Hayi, Moya! Hayi, namhla! \nNgelinye ilanga \nNgokubiza.” \n\n2. Cish’ ukuvuma \nUkuphenduka; \nCish’ ukuvuma, \nYiza, moni! \nYiza namhla; \nNgoba uyabizwa \nNguJesu noMoya, \nUnathandazelwa, \nYiza moni! \n\n3. Cish’ ukuvuma- \nUsenethuba; \nCish’ ukuvuma- \nLiyadlula; \nAkuyikubakho \nUkubizwa futhi, \nNokubelesela, \nEncwabeni.` },
  { id: 215, title: 'Yizanini Boni, Yizanini Nonke', lyrics: `1. Yizanini boni, Yizanini nonke, \nIsidlo salomusa sesilungile. \nMusan’ ukunqaba, kulungile \nKonke, \nYizani kalohu nisidle niphile. \nYizani kalokhu, nisidle niphile. \n\n2. Sithunywa iNkosi nasezweni \nLonke; \nKumenywa izizwe, amukh’ \nOwalelwe; \nMadoda, bafazi bantwana, ‘he, \nNonke, \nYizwani ilizwi, ningeza \nNamkelwe. \nYizani kalokhu, nisidle niphile. \n\n3. Yizani baphulw’ ubunzima be- \nZono. \nYizani niphumle nin’ \nAbadinwayo. \nOmpofu, nkubele, mpumputhe, \nLunyonga, \nYizani nisizwa uJes’ owafayo! \n\n4. Bonani umusa uvel’ eNkosini \nUfun’ ukungena unqobe \nInkani; \nKuvulwe indlela ebhek’ ezulwini, \nYizani ningene, yavulelwa \nNani! \nYizani kalokhu, nisidle niphile. \n\n5. Namhlanje, namhlanje, musan’ \nUkunqena. \nOkade elona umemo lweNkosi \nKafune izulu azuz’ ukungena, \nKuze kube-ngunaphakade \nEkhona!` },
  { id: 216, title: 'Buyani, Bungane, Buyani Ningafi', lyrics: `1. Buyani, bungane, buyani \nNingafi! \nUMenzi omkhulu useyanibiza; \nNezwile kaningi, niyezwa \nNamanje, \nLelozwi lokuthi, buyani ningafi. \n\nNizwile kaningi, buyani \nNingafi! \n\n2. Indlela yabahle yindlela yo- \nKusa, \nIlang’ endleleni liyabakhanyisa; \nLiyababusisa ngay’ imini yalo, \nOhambayo ngayo uy’ ekuphileni. \n\n3. Indlela yaboni yindlela yoku- \nHiwa, \nKwehlel’ ubunzima, kumnyama \nKuyona; \nZiningi kangaka izikhubekiso, \nOhambayo ngayo uya ekufeni. \n\n4. Buyani bangane, buyani \nNingathi, \nKhethani lendlela ey’ ekuphileni. \nYindlela kaJesu- wahamba ku- \nYona, \nWosiza abantu abamlandelayo.` },
  { id: 217, title: 'Mawungangedluli Jesu', lyrics: `1. Mawungangedluli Jesu, \nYizw’ amazwi ami; \nLapho ubabiz’ abanye, \nMawungizwe nami. \n\nJesu, Jesu, Yizw’ amazwi ami \nLapho ubabiz’ abanye, \nMawungizwe nami \n\n2. Isihlalo esomusa, \nNgikusona nami; \nNgiguqile, ngingumoni, \nUngisize nami; \n\nJesu, Jesu, Yizw’ amazwi ami \nLapho ubabiz’ abanye, \nMawungizwe nami \n\n3. Ngokulunga kwakho kodwa, \nNgiyacela nami; \nUngelaphe ngaphukile, \nNgisindise nami; \n\nJesu, Jesu, Yizw’ amazwi ami \nLapho ubabiz’ abanye, \nMawungizwe nami \n\n4. Ungumthombo wakho konke, \nNokuphila kwam’; \nEzulwini nasezweni, \nYikho konk’ okwam’;` },
  { id: 218, title: 'Namhlanje Niyabizwa', lyrics: `1. Namhlanje niyabizwa, \nBazuli, \nNinqabelan’ ukuza, \nBeduki? \n\n2. Namhlanje niyabizwa, \nYizwani, \nFindini la ngenani, \nGuqani. \n\n3. Namhlanje niyabizwa, \nWozani. \nKuvuk’ amandl’ omthetho, \nSheshani. \n\n4. NoMoya uyabiza \nNgamandla; \nMus’ ukumdabukisa, \nUnomsa.` },
  { id: 219, title: 'Uyamaz’ UJesu Yini', lyrics: `1. Uyamaz’ uJesu yini, \nOyiNkosi noMsindisi, \nOnothando, onomusa? \nUyamaz’ uJesu na? \n\nMfun’ uJesu uMsindisi, \nNguye owakufelayo, \nNxa umfuna uzomthola \nUsindiswe namhlanje. \n\n2. Wayesezulwini lakhe \nEnoYis’ uNkulunkulu, \nEdunyiswa njalonjalo, \nAmabandla aphezulu. \n\n3. Kepha laph’ ebon’ abantu \nBedukile njeng’ ezimvu, \nWabahawukel’ impela \nNgal’ uthando olukhulu. \n\nMfun’ uJesu uMsindisi, \nNguye owakufelayo, \nNxa umfuna uzomthola \nUsindiswe namhlanje. \n\n4. Ngakh’ ukusithanda kwakhe \nWeza lapha emhlabeni, \nEzokusibuyisela \nThin’ abantu endleleni. \n\nMfun’ uJesu uMsindisi, \nNguye owakufelayo, \nNxa umfuna uzomthola \nUsindiswe namhlanje. \n\n5. Awumuzwa ekubiza \nEhi, “Moni, woza kimi, \nUsindiswe ezonweni \nUbe-umlandeli wami”? \n\n6. Yebo, Jesu, ngiyavuma, \nSengiyeza kuwe, Nkosi; \nNgisindise, ungigcine, \nNgilandele wena njalo.` },
  { id: 220, title: 'Ungamncish’ Indaw’ UJesu', lyrics: `1. Ungamncish’ indaw’ uJesu!\nWazithwal’ izono zakho;\nNangu esemi engqongqotha,\nMon’, uzomngenisa na?\n\nUyiNkosi yobukhosi;\nShesh’ ulalel’ izwi lakhe\nUmvulele inhliziyo,\nThana, “Ngena, Nkosi yam!”\n\n2. Uvumela okomhlaba,\nKeph’ uKrist’ obethelweyo\nKanandawo yokuhlala\nEnhliz’ywen’ afela yona.\n\nUyiNkosi yobukhosi;\nShesh’ ulalel’ izwi lakhe\nUmvulele inhliziyo,\nThana, “Ngena, Nkosi yam!”\n\n3. Konje, awunasikhathi?\nNang’ uJesu esabiza;\nNamhla yisikhath’ esihle,\nIngomuso alifiki.\n\n4. Dela konke, dela manje,\nOlomusa luyadlula;\nMasinyane uzokufa-\nAkungabi-ezonweni.` },
  { id: 221, title: 'Phons’ Izwi-nje NgoJesu', lyrics: `1. Phons’ izwi-nje ngoJesu,\nUmhlobo wethu nya,\nVus’ inhliziyo zethu\nNgakwenzileyo la.\n\nIzwana-nje ngoJesu\nLosiza endleleni;\nIzwana-nje ngoJesu\nFakaza ngaye la.\n\n2. Phons’ izwi-nje ngoJesu\nSewuyekelwa na?\nUzama ngomsa wakhe\nUphuml’ ekhaya le.\n\n3. Phons’ izwi-nje ngoJesu.\nUngasho uthi, na,\n“Ngiyamthand’ uMsindisi,\nOwangifelayo”?\n\n4. Phons’ izw-nje ngoJesu,\nIthuba leli-nje,\nNgokuzindela kwakho\nUzilahlisa nya.\n\n5. Phons’ izwi-nje ngoJesu,\nIthemba nxa lincan’;\nSukuma nokho, uye,\nUthembe kuye nya.` },
  { id: 222, title: 'Niyakholwa Nini Na', lyrics: `1. Niyakholwa nini na,\nNin’ enidukayo?\nNiyakuvuma nini na,\nNin’ eninqabayo?\n\n2. Niyakubuya nini na,\nNin’ enibizwayo?\nNiyakuyeka nini na,\nNin’ eniphikayo?\n\n3. Niyakudela nini na,\nNina enonayo?\nNiyakulahla nini na,\nLokh’ okunqatshwayo?\n\n4. Niyakwethuswa nini na,\nNina enifayo?\nNiyakukhala nini na,\nNin’ enishonayo?\n\n5. Izinyembezi ziphi na,\nNin’ enilahlwayo?\nUJesu Kristu uphi na,\nYen’ ongasizayo?` },
  { id: 223, title: 'Uhlatshiw’ Umkhosi, Balekani Zoni', lyrics: `1. Uhlatshiw’ umkhosi, balekani\nZoni,\nNiye emthonjeni onabo ubomi!\nUbubi, nezono, namacala onke,\nIgazi leMvana likuhlanza konke.\n\nAlelua! UKristu osihlawulela,\nSombonga eJordan uma sili-\nWela.\n\n2. Nin’ eninokufa, manizwe iNkosi\nEsisindisayo, bukuyo ubomi;\nUma sinezono ezingangentaba,\nNgegazi leMvana lingaphel’ icala.\n\n3. UJesu iNkosi uya ngokwahlula,\nWosenza sinqobe ukona nokufa;\nMawuhlab’ umkhosi, wena\nOkholwayo,\n“Bohlanzwa nguJesu abon’ abe-\nZayo.”\n\n4. Lapho sidlulile, sifike phezulu,\nSoshaya ugubu, simbonge\nKakhulu;\nPhesheya komfula sohuba\nKuyena\nOsisizileyo, singeze sipheze.` },
  { id: 224, title: 'Bayabizwa Uy’ uKristu', lyrics: `1. Bayabizwa uy’ uKristu\nBonke bon’ abadingayo;\nUthi yena, “Kocelayo\nNgiseduze ngokusiza.\n\n2. “Nin’ eni’ zithunywa zami,\nThembanini kimi mina;\nMemezani izwi lami,\nNgiseduze, ngonisiza.\n\n3. ‘Nani nina, bantu bami,\nEnilwayo nakh’ okubi,\nQinisani, nginamandla,\nNgiseduze, ngonisiza.\n\n4. “Nina, zon’ enedukele\nEndleleni yobumnyama,\nBuyanini, nize kimi,\nNgiseduze, ngonisiza.\n\n5. “Phendukani, nifelani?\nNans’ indlela yokusinda;\nThembanini, nize kimi,\nNgiseduze, nosindiswa.”` },
  { id: 225, title: 'NginoMsindisi, Uyangikhalela', lyrics: `1. Nginomsindisi, uyangikhalela,\nUmhlobo omkhulu emhlabeni;\nNamanje ngesisa ungihlalele;\nSengathi angaba-owakho.\n\nNgikuthandazela, ngiku-\nThandazela,\nNgikuthandazela ukuba\nUphile.\n\n2. Nginay’ uBaba, wangipha\nIthemba,\nIthemba elihle, aliphuthi.\nUyakungabizela lona phezulu-\nKunga ungaba-khona futhi.\n\nNgikuthandazela, ngiku-\nThandazela,\nNgikuthandazela ukuba\nUphile.\n\n3. Nginay’ ingubo ekhazimulayo,\nIbekiwe, yongimangalisa.\nSengathi ingaba-ikhona neyakho,\nSengathi ingakwanelisa.\n\n4. Nginokuthula, kufana nomfula,\nKulomhlaba akunakutholwa.\nKuMsindisi wami, kukuye\nKuphela;\nKunga ungavum’ ukukholwa.` },
  { id: 226, title: 'Namhla Niyabizwa Nonke', lyrics: `1. Namhla niyabizwa nonke\nUMsindisi onguKristu,\nOselokhu anibiza,\nUsabiza nize kuye.\n\n2. Uthi, “Wozanini nonke”,\nNize ‘kuzwa izwi lakhe;\nNingabolibal’ ukuza,\nNiyabizwa uMsindisi.\n\n3. Akamemi ngokukhetha;\nUthi; “Wozanini nonke!”\nNina boni phendukani,\nNikhululwe nisindiswe.\n\n4. Phangisani niye kuye,\nKuseyisikhathi senu;\nNiye kuye ngokucela,\nNikhululwe nisindiswe.\n\n5. Isikhathi siyadlula\nKuza ‘kwahlulelwa konke;\nPhaphamani, boni nonke,\nNikhuleke kuMsindisi.\n\n6. Khulekani eNkosini,\nEnguBaba oMakade,\nNakuJesu iNdodana,\nNakuMoya oyingcwele.` },
  { id: 227, title: 'O Mfowethu, Woza Manje', lyrics: `1. O mfowethu, woza manje\nKuye uMsindisi;\nBuya namhla ezonweni,\nThemba kuy’ uJesu.\n\nWoza manje\nWoza kuy’ uJesu.\n\n2. Kad’uhamba, wedukile,\nShesh’ ungalibali;\nUngadeli umsa wakhe,\nWoza kuMkhululi.\n\n3. Izwe alinakuthula,\nNgakho ujabhile;\nKholwa manje eNkosini,\nIzokubusisa.\n\n4. Vuma, phel’ izono zakho,\nCela umsa kuye;\nNay’ uJesu unothando\nWosindiswa nguye.` },
  { id: 228, title: 'Yizw’ Insimbi Nans’ Ikhala', lyrics: `1. Yizw’ insimbi nans’ ikhala\nImemel’ abantu,\nBeze badumis’ iNkosi,\nYen’ uNkulunkulu.\nSondelani, sondelani,\nSondelani nonke.\nNant’ ithuba lokuzuza\nUkuphila kuye.\n\n2. Wez’ uJesu emhlabeni\nAbe-uMsindisi;\nWafa esiphambanweni.\nWakwahlul’ ukona.\nSondelani, sondelani,\nSondelani nonke.\nNingalahlekelw’ ithuba\nLokulizwa iZwi.\n\n3. Yizwa ukuhlabelela\nKwabasindisiwe;\nKuhlangana nay’ insimbi,\nIsimem’ esihle.\nSondelani, sondelani,\nSondelani nonke.\nNgenanini embusweni,\nNizw’ uthando lwakhe.` },
  { id: 229, title: 'Yizwa Mphefumulo wam', lyrics: `1. Yizwa mphefumulo wam’,\nIzwi loMsindisi,\nEsho kuwe wena,\n“Mon’ uyangithanda na?\n\n2. “Ngakophul’ uthunjiwe,\nNgakuboph’ inxeba,\nNgakuqoq’ uzula,\nNgakhanyis’ indlela.\n\n3. “Aluphel’ uthando lwam’,\nLuphakem’ impela,\nLujulile lona,\nLuyanqob’ ukufa.\n\n4. “Laph’ iphel’ imihla\nYokuphila kwakho,\nWobon’ ubukhosi,\nUbe-sezulwini.\n\n5. “Mon’, uyangithanda na?”\nYebo, inhliziyo\nIkuwena, Nkosi,\nUngithandisise.` },
  { id: 230, title: 'UJehova Waba Nomsa', lyrics: `1. UJehova waba nomsa\nKulo lonke izwe lethu;\nWathumela iNdodana,\nIbe-uMsindisi wethu.\n\n2. Yona yehla ezulwini,\nYafa endaweni yethu;\nYabethelwa emuthini,\nYazithwal’ izono zethu.\n\n3. Namhla kuyintando yakhe\nSiphenduke ezonweni,\nSiyethembe iNdodana,\nSingalahlwa ekufeni.\n\n4. Ngakho masamkel’ uJesu,\nAbe-uMsindisi wethu;\nSimlalele, simlandele,\nNgenhliziyo yonke yethu.` },
  { id: 231, title: 'Nginezono Eziningi', lyrics: `1. Nginezono eziningi,\nEzihluph’ umoya wam’;\nNgiyadinga uMkhululi\nAkhulul’ umoya wam’;\nWena Jesu,\nWena unguMsizi wam’.\n\n2. Wangithanda mina moni,\nWazifel’ izono zam’,\nUwe ongihlawulele,\nKusindis’ umoya wam’;\nWena Jesu,\nWena unguMsizi wam’.\n\n3. Ukulunga anginakho,\nUnobub’ umoya wam’;\nThuma uMlungisi wakho,\nAlungis’ umoya wam’;\nWena Jesu,\nWena unguMsizi wam’.\n\n4. Ngiyaduka endleleni,\nNgingaholw’ iNkosi yam’;\nIzwi lakho ngilibambe,\nLiwuvus’ umoya wam’;\nWena Jesu,\nWena unguMsizi wam’.\n\n5. Ngoshonake masinyane,\nUyesab’ umoya wam’;\nYiba-nami, ngibe-nawe,\nKhona ekufeni kwam’;\nWena Jesu,\nWena unguMsizi wam’.` },
  { id: 232, title: 'Singaboni, Sinecala', lyrics: `1. Singaboni, sinecala\nKuwe, Nkosi, Thixo wethu.\nSimbongoza, siyakhala\nPhansi kwaz’ izono zethu.\n\n2. Besinjalo ngendabuko,\nKwasekuzalweni kwethu;\nNakh’ okubi salandela\nYonke iminyaka yethu.\n\n3. Yethi inhliziyo yethu,\nInensila nobumnyama;\nSenza imikhuba yethu\nYenkanuko le, yenyama.\n\n4. Kepha namhla siyabheka\nKuwe, Nkosi, usisize;\nSiyethemba sikhuleka,\nKuwe, Nkosi, sisindise.` },
  { id: 233, title: 'Hawu, Jehova, Sengonile', lyrics: `1. Hawu, Jehova, sengonile,\nNginecala phambi kwakho;\nUma ngifa ulungile,\nKepha ngiphe umsa wakho.\n\n2. Mina angikuthandanga,\nNkos’ enkulu, Menzi wami;\nNgedukile, ngenz’ amanga,\nNgokuhamba konke kwami.\n\n3. Ngiza, Baba, sengibuye;\nYiba-nomsa, Nkosi yami!\nInhliziyo mayisinde-\nInhliziyo embi yami.` },
  { id: 234, title: 'Ukweduka Kwami Kwandile', lyrics: `1. Ukweduka kwami kwandile,\nNezono zami ziningi,\nI’nyembezi zami zandile;\nNgivulelwe ngongena nam’.\n\nNgiyazi ngigcwele ububi,\nNgiyisoni, ngivuma ngimubi;\nKephake uJesu wafel’ abanje,\nNgivulelwe ngongena nam’.\n\n2. Ngingomncane kwabamtha-\nNdayo\nNakubo abamcelayo;\nKephake uyen’ omemayo,\nUbani ongasho Qha?\n\n3. Umsa wakhe wositha izono,\nWohlanza bonke ububi;\nIzinyawo zisaba zidele,\nKantike songena-nje-\n\nNgiyazi ngigcwele ububi,\nNgiyisoni, ngivuma ngimubi;\nKephake uJesu wafel’ abanje,\nNgivulelwe ngongena nam’.\n\n4. Ukweduka kwami kwandile,\nUmoya ugula ngokona,\nI’nyembezi zami zandile;\nNgivulelwe ngongena nam’.` },
  { id: 235, title: 'Ngibheke, Baba, Ngobubele Bakho', lyrics: `1. Ngibheke Baba, ngobubele\nBakho,\nNgithethelele zonk’ izono\nZam’;\nNangal’ igazi leNdodana yakho\nUlilalele, Baba, izwi lam’,\n\n2. Nginakho, Nkosi, ukungcola\nKodwa,\nNgingeyihlanze inhliziyo yam’;\nSengethembile umsa wakho\nWodwa,\nNgokuba lilikhul’ icala lam’.\n\n3. Izono zonke engibengizenza\nSezimbi zonke ebusweni\nBam’;\nNgikujambele konk’ okwam’\nUkwenza,\nLinzima ngakho lonk’ icala lam’.\n\n4. Ngizwile namhla intethelo ikho,\nKungal’ igazi loMsindisi wam’;\nNgimzwile name, nokuvuma\nKukho-\nNgivuma ukubizw’ iNkosi\nYam’.` },
  { id: 236, title: 'Thixo, Nkulunkulu Wethu', lyrics: `1. Thixo Nkulunkulu wethu,\nSinecala phambi kwakho,\nNgoba kade sidelela\nYonke imiyalo yakho.\nKade sasiqom’ okwethu,\nSinganaki; Singathini?\nSidikila leyondlela\nEsingayo ezulwini.\n\n2. Zonk’ izinto zalomhlaba\nZikudis’ umoya wethu,\nNgoba ziyalibazisa,\nBaba, inhliziyo yethu.\nKapha ngobubele bakho\nWena wasihawukela;\nKawufisi uba sife,\nKawuthandi, nangempela.\n\n3. Uthi, “Sondelani kimi,\nNazo zonk’ izono zenu;\nNgiyakunithethelela,\nNgilisus’ icala lenu.”\nBaba, ngisondela kuwe\nNalo lonk’ icala lami;\nNgawo, Nkosi, umsa wakho\nSusa zonk’ izono zami.` },
  { id: 237, title: 'Baba, Wethu Ungibheke', lyrics: `1. Baba wethu, ungibheke,\nYizwa umthandazo wam’;\nAwuthandi ngibhujiswe,\nSusa zonk’ izono zam’.\nNgangizonda izwi lakho,\nNgangithand’ izono zam’;\nNgidelil’ uMoya wakho,\nNgenza okwentando yam’.\n\n2. Nginezono eziningi,\nNgithwesisw’ icala lam’;\nWongisiza, ngungumdingi,\nNgiyekel’ ukona kwam’.\nUngisize ngiphenduke,\nNgizishiy’ izono zam’;\nNgiwufun’ umbuso wakho,\nKusindisw’ umoya wam’.` },
  { id: 238, title: 'Safa Thin’ Abantu', lyrics: `1. Safa thin’abantu, Thixo,\nSibulewe sonke;\nNgaz’izono esinazo,\nSonakele sonke.\n\n2. Zinezifo, zinosizi,\nLezizono zethu;\nZinendlala, zinokufa\nOkuphezu kwethu.\n\n3. Safa thin’abantu, Jesu.\nO Mkhululi wethu,\nSikhulule, sisindise,\nEzonweni zethu.\n\n4. Phath’izembe lezwi lakho,\nZigawule ngalo;\nZibhujiswe, zisitshulwe,\nSikhululwe njalo.\n\n5. Yehla, Moya oyiNgcwele,\nUsisebenzise;\nLokhu okuthandwa uwe\nMasithandisise.` },
  { id: 239, title: 'Ngongompofu, Ngingumoni', lyrics: `1. Ngingompofu, ngingumoni,\nNgiyeza kuwe, Nkosi.\nSengithobe, nginenhloni,\nNgokuba nginengozi;\nSekukade ngikwenzile\nEngikuthanda khona;\nKuwe, Jesu, nginqabile\nIntando yakho yona.\n\n2. Bengihlezi ngeminyaka\n‘Miningi emhlabeni;\nWena, Nkosi, wanginaka,\nNgaphila emzimbeni:\nWangqongqotha ngezwi lakho\nKakhulu ovalweni;\nWawufun’ uMoya wakho\nAngene enhliz’yweni.\n\n3. Manje inhliziyo yami\nYesuka ithukile\nKukho ukwesaba kwami,\nNamandla aphelile:\nBaba wami wobubele,\nKhangela into yakhe;\nSengilapha ngizilahle\nEzinyaweni zakho.` },
  { id: 240, title: 'Into Inye Ngibuzayo', lyrics: `1. Into inye ngibuzayo,\nNgiyamthanda yini na?\nYena owangifelayo,\nNgenhliziyo yonke na?\n\n2. Angibon’ ubuso bakho,\nUsekude, Nkosi yam’.\nNgiyakhala phambi kwakho,\nNgikhalel’ izono zam’.\n\n3. Ngiyekele ngobunene,\nSusa zonk’ izono zam’;\nNgizohamba endleleni\nEkhawul’ ekhaya lam’.` },
  { id: 241, title: 'Sifile, Thin’ Aboni', lyrics: `1. Sifile, thin’ aboni,\nIzono zethu zimbi;\nZiyasiceba kabi,\nSithi, sosinda ngaphi?\n\n2. Zandile, ziyafana\nNesihlabath’ ogwini,\nZiyasibandezela;\nSithi, sosinda ngaphi?\n\n3. Sithuthumela ngazo,\nSiyayesab’ iNkosi,\nYona iNkos’ enkulu;\nSithi, sosinda ngaphi?\n\n4. Kuwena, Jesu Kristu,\nOwabathand’ aboni,\nOwabethelw’ emthini,\nKuwena singasinda\n\n5. Washaywa ngamivimbo\nEbifanele thina,\nWathwal’ ukona kwethu;\nKuwena singasinda.` },
  { id: 242, title: 'Nkosi, Ngawo Umsa Wakho', lyrics: `1. Nkosi, ngawo umsa wakho\nBona umphefumlo wam’;\nNgiguqile phambi kwakho,\nSusa zonk’ izono zam’.\n\n2. Baba, kade ngedukile,\nNgingalaz’ icala lam’,\nEzonweni ngangifile;\nSusa zonk’ izono zam’.\n\n3. Wena unomusa wonke,\nKade wancengana nam’;\nKade wangibiza, ngala;\nSusa zonk’ izono zam’.\n\n4. Ngimuzwile uMsindisi\nOwathwal’ icala lam’,\nNgidiniwe, ngibuyise,\nSusa zonk’ izono zam’.\n\n5. Jesu, ngibuyela kuwe,\nNabo bonk’ ububi bam’\nNgamukele ngomsa wakho,\nSusa zonk’ izono zam’.` },
  { id: 243, title: 'UJesu Nangw’esemi', lyrics: `1. UJesu nangw’esemi\nEmnyango ovaliwe,\nUhlal’ esalindela\nUkuba simvulele.\nSipheth’ igama lakhe\nIgama lamaKristu,\nNgasiba-namahloni\nNgokumvalela kanje.\n\n2. UJes’ usanqonqotha,\nIsandla sinenxeba,\nNomqhele ngowameva\nOqhel’ ikhanda lakhe.\nUthando lwesimanga\nAsihlalela ngalo;\nUkona kudlangile,\nUkuba simvalele.\n\n3. UJesu uyancenga,\nUsathi, ethobile,\n“Ngafela nin’ abami,\nNiyangenqaba kanti!”\nO Jesu, esivuma,\nSikuvulel’ umnyango;\nO, ngena, Nkosi, ngena,\nUngab’ usasishiya.` },
  { id: 244, title: 'Kade Ngokudinga Kwethu', lyrics: `1. Kade ngokudinga kwethu\nSasisezonweni;\nKade ngokumazi kwethu\nSasisemnyameni.\nKweza, Nkosi, izwi lakho\nLasikhanyisela;\nKweza izithunywa zakho\nZalishumayela.\n\n2. Namhla, Nkosi, sibonile\nUbubele bakho;\nNamhla, Nkosi, sesizwile\nOkomusa wakho.\nUMsindisi sesimazi,\nOsisindisayo;\nUMholeli siyamazi,\nOsiholelayo.\n\n3. Namhla sesibon’ indlela\nEya ezulwini;\nNamhla ukusikhombisela\nKuwe ebomini,\nNkosi, uyasethabisa\nNgobubele bakho;\nNkosi, siyawudumisa\nLowomusa wakho.` },
  { id: 245, title: 'Ngiyakubonga Jesu', lyrics: `1. Ngiyabonga Jesu,\nUkungifela kwakho,\nUze ungikhulule,\nNgibe-ngowakho, Nkos’.\n\n2. Ngangisebumnyameni,\nNgangingenakulunga;\nWeza, wangikhanyisa,\nNgibe-ngowakho, Nkos’.\n\n3. Ngabon’ ububi bami,\nNgabon’ uthando lwakho;\nNgahlulwa umsa wakho,\nSengingowakho, Nkos’.` },
  { id: 246, title: 'Wangenzelan’ UJesu Na?', lyrics: `1. Wangenzelan’ uJesu na?\nBheka, wehla ezulwini,\nWashiy’ umbuso laphaya,\nNgize ngiye ebomini.\n\nUnguJesu, unguJesu,\nINkosi ethandayo,\nOngiphe ifa laphaya,\nEndaweni ekhanyayo.\n\n2. Wangenzelani futhi na?\nWangikhipha ekoneni.\nWazuza into ngakho? Qha;\nWaholelwa ekufeni.\n\n3. UJesu uphi manje na?\nWenyukela ngaphezulu;\nUyobuyela futhi la\nNgobukhosi obukhulu.\n\n4. Ngithini ngaye manje na?\nNgithi, uyangibusisa.\nNgombon’ uqobo laphaya,\nNaphakade ngomdumisa.\n\n5. Ningamazi kanjani na?\nPhendukani, nimlandele.\nAngemalel’ umuntu? Qha;\nSheshanini, nimamkele.` },
  { id: 247, title: 'Bonk’ubuhle Balomhlaba', lyrics: `1. Bonk’ubuhle balomhlaba,\nNokucweba kwal’ izulu,\nNal’ uthand’ oluhle lwakho\nOlusisingatha njalo,\nSikubonga kuwe, Nkosi,\nSesivum’ ingoma yethu.\n\n2. Zonke izimangaliso,\nEzemini nobusuku,\nEzemithi nezintaba\nEzenyanga ne’nkanyezi,\nSikubonga kuwe, Nkosi,\nSesivum’ ingoma yethu.\n\n3. Lonk’ uthando lwezihlobo,\nAbazali nabantwana,\nIzihlobo emhlabeni,\nNazo ezisezulwini,\nSikubonga kuwe, Nkosi,\nSesivum’ ingoma yethu.\n\n4. Konke esikuphiwayo\nNgaw’ umusa wakh’ omkhulu,\nNezimilo zokulunga\nOkufuza okwezulu,\nSikubonga kuwe, Nkosi,\nSesivum’ ingoma yethu.` },
  { id: 248, title: 'Jesu Ngiyakuthanda', lyrics: `1. Jesu ngiyakuthanda, ngiyaz’\nUngowami,\nSengishiy’ izono nokwenama\nKwezwe;\nMuhleng’ onomusa, O Msindisi\nWami,\nInxa ngakuthanda kukhulu\nManjena.\n\n2. Ngikuthanda ngokuba usungi-\nThandile,\nWangihlawulela ezonweni\nZami;\nNgothando wathwala umqhele\nWameva,\nInxa ngakuthanda, kukhulu\nManjena.\n\n3. Ngokuthanda ngikhona, nokuba\nSengifa,\nNgobonga selokhu ngihamb’\nEmhlabeni;\nNgiyoth’ ekufeni komzimba lo\nWami,\nInxa ngakuthanda, kukhulu\nManjena.\n\n4. Khona ezigodlweni zeNkosi\nYezulu,\nNgomtusa ekhaya elimi\nPhakade;\nNgohuba nomqhele ekhanda\nKimina,\nInxa ngakuthanda, kukhulu\nManjena.` },
  { id: 249, title: 'Ngamuzw’uJesu Ethi Kimi', lyrics: `1. Ngamuzw’uJesu ethi kimi:\n“Woza uphumule;\nUsudiniwe, bek’ ikhanda kimi,\nNgikugone.”\nNgafika kuye, ngidiniwe, ngathi,\n“Nkosi yami!”\nWangamukela ngobunene,\nWangithokozisa.\n\n2. Ngamuzw’ uJesu ethi kimi:\n“Woza uphuziswe;\nUphuze kimi lawomanzi\nAngakuph’ amandla.”\nNgafika kuye, ngiwacela lawo-\nManz’ amahle;\nNgahluyelelwa ngokuphuza,\nManje ngingowakhe.\n\n3. Ngamuzw’ uJesu ethi kimi:\n“Ngi’kukhanya kwakho;\nUhambelani ebusuku?\nKukhanya kimi.”\nNgafika kuye olilanga, wang-\nKhanyisela;\nNgohamba manje ngokukhanya\nLokho ngize ngife.` },
  { id: 250, title: 'Ukucabanga Ngawe Jesu', lyrics: `1. Ukucabanga ngawe Jesu,\nKumnandi enhliz’yweni yethu,\nKodwa kudlulw’ ukubonana\nKhon’ ekuphumuleni kwakho.\n\n2. Limnand’ igama lakho, lihle\nKunamagama onk’ amanye;\nLiyezwakal’ ezindlebeni\nZabantu abasindisiwe.\n\n3. Ithemba labaphendukayo,\nUthabo lwabamnene bonke,\nOthethelela abawayo,\nUmgcine low’ okufumene.\n\n4. Uthando lwakho olumnandi\nLwaziwa yib’ abakho bodwa,\nAbasingethw’ ingalo yakho,\nBezwa ubuhle bosindiso.\n\n5. Ube-luthabo lwethu lodwa,\nNjengoba ungumvuzo wethu,\nSilwaz’ udumo lwakho lapha,\nNasebuphakadeni nawe.` },
  { id: 251, title: 'Thwal’ Isiphambano Sakho', lyrics: `1. Thwal’ isiphambano sakho,\nKwash’ uJesu kubafundi,\nUzidele, shiy’ umhlaba,\nUlandele ngokwethaba.\n\n2. Thwal’ isiphambano sakho,\nUngesabi ubunzima;\nYena uzokuqinisa\nZonke izinsuku zakho.\n\n3. Thwal’ isiphambano sakho,\nUngethuki luth’ olubi;\nWoqondiswa iso lakhe,\nLeyondlela yaphezulu.\n\n4. Thwal’ isiphambano sakho,\nUdelel’ ihlazo laso;\nWasithwal’ uJesu Kristu\nUkukusindisa wena.\n\n5. Thwal’ isiphambano sakho,\nWosishiya ekufeni;\nWena wedwa othwalayo\nWoba-nakho ukuphila.` },
  { id: 252, title: 'Ngihlala Othandweni', lyrics: `1. Ngihlala othandweni\nLweNkosi enguJesu,\nNgingebe-nal’ uvalo\nNgokwenzekayo la.\nNgisindisw’ izinhlupheko,\nUmoya uthe dica;\nUkhona uMsindisi,\nNgohamba naye la.\n\n2. Ukheth’ indlela yami,\nNgizomlandela njalo,\nUnguMalusi wami\nNgisemhlabeni la.\nNoma ngisemhosheni\nWethunzi elimnyama,\nNginaye uMvikeli,\nWohamba name la.\n\n3. Kukhona amadlelo\nAngakabonakali;\nIlanga lizokhanya,\nLixosh’ amafu nya.\nNginal’ ithemb’ elihle,\nNginay’ inkululeko,\nNginaye uMsindisi,\nNgohamba naye la.` },
  { id: 253, title: 'Mphefumlo Wami, Qina, Ungesabi', lyrics: `1. Mphefumulo wami, qina, unge-\nSabi;\nUbekezel’ izinhlupheko;\nUNkulunkulu ngezingalo zakhe\nUzokuphas’ akuphumuze;\nMphefumlo wami, nom’ indlela\nImbi,\nUzokuhol’ akuse kuye.\n\n2. Mphefumlo wam’, uNkulunkulu\nWakho\nUsenguYena waphakade,\nQinis’ ithemba, mus’ ukungabaza,\nOkusemnyama kuzokhanya;\nMphefumlo wam’ amaze naw’\nUmoya\nKusalelel’ elakhe izwi.\n\n3. Mphefumlo wami, mhla ungo-\nFelweyo,\nIzinyembezi ziphophoza,\nUthando lwakhe luzobonakala\nEkududuza inhliziyo;\nMphefumlo wami, wobusisw’\nUJesu,\nUzuze kuye injabulo.\n\n4. Mphefumlo wam’, inkathi\nSeyiyeza-\nSohlala njalo nay’ iNkosi,\nKuphel’ uvalo nayo indabuko,\nSizuz’ uthabo olungcwele;\nMphefumlo wam’, izinyembezi\nZonke\nZophela nye sisezulwini.` },
  { id: 254, title: 'Wen’ Ozwela Iziguli', lyrics: `1. Wen’ ozwela iziguli zisakhala\nZibuhlungu,\nZiza kuwe zikwethemba, wena\nWedwa, Nkosi yethu,\nSizwe, siziletha lapha phambi\nKwesihlalo sakho.\n\n2. Iziguli zisahlushwa, zisadinge\nUkwelashwa,\nZisabhek’ amandla akho. Nathi\nSizikhulekela.\nSizwe, siziletha lapha phambi\nKwesihlalo sakho.\n\n3. Vuma, Nkos’, ukuba sonke\nSijabul’ ukusizisiza,\nSigcwalis’ uthando lwakho ‘kuba\nSiziduduzele.\nSizwe, siziletha lapha phambi\nKwesihlalo sakho.\n\n4. Ngakho makuxoshw’ ukufa\nNgawo lawamandla akho,\nMabuphele ubuhlungu lapha\nEmhlabeni, Nkosi,\nSize sihlangane sonke\nNgokubong’\nAmandla akho.` },
  { id: 255, title: 'Sengiyabaleka', lyrics: `1. Sengiyabaleka ngiya\nEnqabeni yami;\nMangilondwe, ngiphumule,\nLihlomil’ izulu.\n\n2. Mangilondolozwe uwe,\nO Msindisi wami,\nKuso isiphepho lesi\nEsesabekayo.\n\n3. Mangingene enqabeni,\nUze ungikhweze,\nMangicashe lize lise;\nNgisind’ ekufeni.\n\n4. Ngezikhathi zezinsizi\nNxa ngikhala kuwe,\nWophendula, ungikhiphe\nEngozizni yami.\n\n5. Wena, oyiNqaba yami,\nEngisinda ngayo,\nNgokubonga, ngikukhonze,\nNgakho konk’ okwami.` },
  { id: 256, title: 'Ukusindiswa! Hawu, Kuhle', lyrics: `1. Ukusindiswa! Hawu, kuhle\nEkuzweni kwethu!\nNgoba sikhululwe yikho\nEzonweni zethu.\n\nDumisani, dumisani,\nUMninimusa nimdumise,\nAleluya, aleluya,\nMakubongwe uMsindisi!\n\n2. Kade sasilahlekile\nEzonweni zethu;\nKepha manje sikhishiwe\nEngozini yethu.\n\nDumisani, dumisani,\nUMninimusa nimdumise,\nAleluya, aleluya,\nMakubongwe uMsindisi!\n\n3. Ukusindisw’ akubongwe\nEmhlabeni wonke;\nNaphezulu kuyabongwa\nNgamabandla onke.` },
  { id: 257, title: 'Othandweni LukaJesu', lyrics: `1. Othandweni lukaJesu\nSengihlala njalo;\nKuyindawo yobumnandi\nKalungen’ uvalo.\nNjalo ngibusiswa nguye,\nEngilondoloza;\nUngiphethe ngobunene\nSengiyathokoza.\n\n2. Nxa ikhona into embi\nEngivukelayo,\nNjalo ngiyakhwezwa uye\nEngimethembayo.\nNant’ uthando njengezulu,\nLungekhawuliswe;\nNank’ umusa njengolwandle,\nUngelinganiswe.\n\n3. Uyafisa ukumazi?\nKuhle umamkele;\nBheka, manje useduze,\nShesha umlandele!\nOthandweni lukaJesu\nBonke bangangena;\nMina ngomethemba njalo\nNgiyamthanda yena.` },
  { id: 258, title: 'Kukade Inhliziyo Yam’', lyrics: `1. Kukade inhliziyo yam’\nIbanjwe ezonweni;\nKukade umphefumulo wam’\nUhlezi emnyameni.\n\n2. Kantike, namhla, Nkosi yam’,\nUsuyangisindisa;\nKwafika ukukhanya kim’,\nKwasekungihanyisa.\n\n3. Ngisekulahleni kwam’\nNgalizwa izwi lakho;\nKwafika abafuni bam’,\nBazisa umsa wakho.\n\n4. Ngizwile ngoMkhululi wam’,\nOweza emhlabeni\nUkuhlawul’ icala lam’,\nNgisinde ezonweni.\n\n5. Lukhulu ubusiso lwam’\nEngiluzuza kuwe;\nKukhulu ukwethaba kwam’,\nEngikuphiwe uwe.\n\n6. Namhlanje izifiso zam’\nZibheka ezulwini;\nLamhlanje umphefumulo wam’\nUyaya ebomini.` },
  { id: 259, title: 'Lowomunt’ uyabusiswa', lyrics: `1. Lowomunt’ uyabusiswa,\nOngahambi nabonayo,\nOngahlal’ esihlalweni\nSabo abanengekayo.\n\n2. Uyathanda imithetho\nKaJehova, onguMenzi;\nUngumuthi othelayo\nIzinhlamvu eziningi.\n\n3. Abonayo bayafana\nNamakhoba emoyeni;\nKepha abasoze bema\nNamaKristu ekwabeni.\n\n4. UJehova uyathanda\nIzindlela zokulunga;\nAmashinga ayahamba\nEndleleni ebubayo.` },
  { id: 260, title: 'Izibusiso Ziyeza', lyrics: `1. Izibusiso ziyeza\nYizwa, uyasithembisa;\nKuyakuvela umusa,\nUze-nje ukusisiza.\n\nIzibusiso, izibusiso zivela:\nUmsa uyasifikela,\nUmsa siyawukhalela.\n\n2. Izibusiso ziyeza,\nZiyakusivuselela,\nPhezu kwentaba niyezwa,\nImvula seyiyathela.\n\nIzibusiso, izibusiso zivela:\nUmsa uyasifikela,\nUmsa siyawukhalela.\n\n3. Izibusiso ziyeza,\nMaziwele kithi futhi,\nYizake, Nkosi, sivuse,\nUbe-uMsindisi wethu.\n\nIzibusiso, izibusiso zivela:\nUmsa uyasifikela,\nUmsa siyawukhalela.\n\n4. Izibusiso ziyeza;\nKuhleke zize nalapha,\nZisivumise izono;\nWoza, Jesu, woza manje.` },
  { id: 261, title: 'Imnandi, Awu, Imnandi', lyrics: `1. Imnandi, awu imnandi,\nIndaba yaphezulu,\nyeNkosi yobukhosi\nNothando olukhulu.\nKumnand’ ukuyilanda,\nNgiyaz’ iliqiniso,\nIhlab’ umxhwele kimi\nKakhulu ‘he kakhulu.\n\nKumnand’ ukuyilanda,\nNgohuba naphezulu\nNgoJesu Nobukhosi,\nNothando olukhulu.\n\n2. Imnandi, awu, imnandi,\nIyisimangaliso,\nIdlula namaphupho,\nIdlula nezifiso.\nKumnand’ ukuyilanda,\nIngisizil’ impela;\nNgakhoke ngiyilanda,\nNgifisa niyamkele.\n\n3. Imnandi, awu, imnandi,\nNgiphinda njalonjalo,\nNangokuphindwa kwayo\nBuyanda ubumnandi.\nKumnand’ ukubatshela\nAbanga zanga bezwe\nLendaba yensindiso\nEvezw’ uNkulunkulu.\n\n4. Imnandi, awu, imnandi,\nKakhulu koyaziyo;\nNgiyilambele nami,\nYomile inhliziyo.\nNgohuba ezulwini\nIgama lelo ‘lisha,\nLiyob-indab’ endala\nEkade ngayithanda.` },
  { id: 262, title: 'Jesu, Bomi Bami', lyrics: `1. Jesu, bomi bami,\nNgiyabheka kuwe;\nWen’ uyinjabulo yami,\nNgithobiswa nguwe;\nWena ungumthombo\nEngiphuza kuwo;\nUngumfula wal’ uthando\nEngigeza kuwo.\n\n2. Ngiyakufa, Jesu,\nNxa umuka kimi.\nNgikhumbule, Nkosi, yami\nHlala njalo kimi.\nNgothokoza njalo\nEnkosini yami,\nNgayo yonke iminyaka\nYokuhlala kwami.` },
  { id: 263, title: 'Ilizwi! Ilizwi! Manje Lizwakele', lyrics: `1. Ilizwi! Ilizwi! Manje lizwakele\nIlizwi leNkosi yezulu;\nWothola icala osuk’ elidela\nIlizwi le Nkosi enkulu.\n\n2. Ubizo! Ubizo! Luzweni, luzweni!\nUbizo luvel’ ezulwini;\nLubiza abantu baphum’\nEzonweni,\nBenyuke bahlal’ eNkosini.\n\n3. Umusa! Umusa! Sesingakhu-\nlulwa,\nINkosi yowenza umusa;\nOdinwa isono- umnyang’\nUvuliwe\nMangene, amkelwe iNkosi.\n\n4. Uthabo! Uthabo! Usizi lwa-\nPhela,\nLugqitshwa iNkosi enkulu;\nIthemb’ elisipha ubomi livele,\nUmnyango wezul’ uvuliwe.` },
  { id: 264, title: 'Uma Uthokoza', lyrics: `1. Uma uthokoza,\nBonga, bonga\nNjengenyoni enhle,\nHlabelela!\nNxa uqhutshw’ uMoya,\nShesha ulalele;\nXwaya ukhuleke;\nHlabelela!\n\n2. Nxa umbhek’ uJesu,\nBonga, Bonga!\nBong’ umusa wakhe;\nHlabelela!\nWasiz’ ohlushwayo,\nEvus’ ofileyo,\nEsifela thina,\nHlabelela!\n\n3. Nxa udabukile,\nBonga, Bonga!\nKuyajabulisa,\nHlabelela!\nZonk’ izingelosi\nZiyabon’ iNkosi,\nBonga, bonga, nawe;\nHlabelela!` },
  { id: 265, title: 'Thokozani Nonke', lyrics: `1. Thokozani nonke,\nNiqhubeke njalo;\nMdumiseni Yena\nLo osithandayo\nUma sinosizi\nAluveli kuye,\nNxa kuvela ifu\nKasilo elakhe.\n\nThokozani nonke,\nNiqhubeke njalo;\nMdumiseni Yena\nLo osithandayo.\n\n2. Thokozani nonke,\nHubanini bandla,\nUyenqoba Yena\nZonk’ izitha zethu.\nIntokozo yethu\nInguKrist’ uqobo,\nUlithemba lethu\nNxa sithembekile.\n\nThokozani nonke,\nNiqhubeke njalo;\nMdumiseni Yena\nLo osithandayo.\n\n3. Siyahlabelela\nKuy’ uNkulunkulu\nThixo uMsindisi,\nSiyabonga njalo.\nWena, Moy’ oNgcwele,\nSikhothama kuwe,\nSithokoza njalo\nEndleleni yethu.` },
  { id: 266, title: 'Ngiyakudumisa', lyrics: `1. Ngiyakudumisa\nUMkhululi wam’;\nUyangisindisa\nEzonweni zam’;\nUyangethabisa,\nEnhliz’yweni yam’;\nNgakho ngomdumisa\nUMkhululi wa’.\n\n2. Ngangibambekila\nEcaleni lam’;\nNgangilahlekile\nEbubini bam’;\nWawusewufile\nUmphefumlo wam’;\nUwuphilisile\nWena, Nkosi yam’!\n\n3. Sengihlezi ngaye\nUMkhululi wam’;\nSengihamba naye\nEndleleni yam’;\nUsesezulwini,\nNgiya khona nam’;\nNgoba-sebomini\nNoMkhululi wam’.` },
  { id: 267, title: 'Ngiyabheka Kuwe', lyrics: `1. Ngiyabheka kuwe,\nOngihlawulele,\nNkosi yami;\nKalokhu mawuzwe,\nNgikhuleka kuwe,\nUngithukulule\nEzonweni.\n\n2. Ungenzel’ umusa,\nMawungiph’ amandla,\nNgiqinise;\nVus’ uthando lwami,\nWena, Nkosi yami,\nNgakho konk’ okwami\nNgikukhonze.\n\n3. Ngisebumnyameni\nLapha emhlabeni\nFuthi futhi;\nYiza ungikhaphe,\nNgihambise kahle\nUkuze ngifike\nEzulwini.` },
  { id: 268, title: 'Jesu, Langa Lokulunga', lyrics: `1. Jesu, Langa lokulunga,\nKhanya enhliz’yweni yethu;\nAsiboni, siyadinga,\nSusa umumnyama bethu.\n\n2. Kade besiphuphutheka,\nUmphefumlo ungaboni;\nLanga lokulunga, woza,\nUkhanyise thina zoni.\n\n3. Inhlizy’ ongekho kuyo\nIyaduka kodwa;\nVela, Langa, nxa ukuyo\nYoba-nokukhanya kodwa.` },
  { id: 269, title: 'Umi Khon’ Emnyango, Jesu', lyrics: `1. Umi khon’ emnyango, Jesu,\nUngqongqotha khona;\nUngqongqotha ngezwi lakho,\nMasilizwe lona.\n\n2. Jesu, zonk’ izinhliziyo\nZiwumnyango lowo;\nUsibiza ngezwi lakho,\nMasikuvulele.\n\n3. Masivume, silalele,\nSizwe izwi lakho.\nVul’ izinhliziyo zethu\nSikwamkele ngazo.\n\n4. Ukuvuma nokuvula\nSingaphiwa nguwe;\nLawamandla okuvula\nSiwacela kuwe.` },
  { id: 270, title: 'Thandazan’ Imihla Yonke', lyrics: `1. Thandazan’ imihla yonke\nKuye onezinto zonke,\nOnibusisayo;\nBonganini umsa wakhe,\nNicel’ ukulonda kwakhe,\nEnikudingayo.\n\n2. Thandazani ngokukholwa,\nMusanini ukubonga\nNgezindebe zodwa;\nThandazani ngenhliziyo\nKuJehovah onaziyo;\nUyiNkosi yedwa.\n\n3. Khulekani egameni\nLikaKristu mubongeni\nOwasifelayo.\nThina singcolile, kodwa\nKuligazi lakhe lodwa\nElisihlanzayo.\n\n4. Umthandazo uligugu,\nWulondeni, ‘he, kakhulu,\nU’kuphila kwenu;\nUngukudla komphefumlo,\nNiyazuza ngomthandazo\nUkuqina kwenu.` },
  { id: 271, title: 'Baba, Encwadini Yakho', lyrics: `1. Baba, encwadini yakho\nSiyalelw’ ukuthi,\n“celanini nizophiwa,\nFunani namkele.”\n\n2. Ngakho, Baba, sisondela\nEbusweni bakho;\nNgomthandazo siyacela\nUkusiza kwakho.\n\n3. Uyathanda sisondele\nNgenhliziyo yethu;\nNgokukholwa sikutshele\nIzinswelo zethu.\n\n4. Wena unguBaba wethu;\nUnezinto zonke;\nUsisize sithandaze\nNgenhliziyo yonke.` },
  { id: 272, title: 'UJehova Ungumoya', lyrics: `1. UJehova ungumoya,\nSiyaziwa nguye;\nSingembone, nokho konke\nKusobala kuye.\n\n2. Uyayaz’ izinhliziyo\nZabamdumisayo;\nAkathandi umthandazo\nWabazenzisayo.\n\n3. Ngakho masihole kahle\nUkuhamba kwethu;\nSizikhulekele kuye\nNgenhliziyo yethu.\n\n4. Masithobe phambi kwakhe\nNgeqiniso lodwa;\nSiqaphele, singamkhonzi\nNgezindebe zodwa.` },
  { id: 273, title: 'Jesu, E Malusi Wethu', lyrics: `1. Jesu, E Malusi wethu,\nSikhombise namhla\nAmadlelo aluhlaza\nLapho sozidlela.\nSingabakho, usigcine,\nUbe-nathi ekweneni,\nUngavumi siseduke,\nUsinqande sonke.\n\n2. Uthe, uyakusamkela,\nSingelalutho ‘mpela.\nUnomusa ukusiza,\nUmsa ‘kusindisa.\nSiyafuna umsa wakho,\nSize senz’ intando yakho;\nBaba, Nkosi noMsindisi,\nSiphe umsa wakho.` },
  { id: 274, title: 'Luthand’ Olungangiyekiyo', lyrics: `1. Luthand’ olungangiyekiyo,\nMangiphumule kuwe manje,\nImpilo engiyiphiweyo\nSengiyibuyisela kuwe;\nYicebise Nkos’.\n\n2. Kukhany’ okungunaphakade,\nKhanyis’ indlela yonke yami!\nOlwam’ ubaq’ alusasizi;\nLokhu ngikhanyiselwe nguwe\nKuyimini, Nkos’.\n\n3. Kuthula okumiyo njalo,\nUngangishiyi naphakade!\nNasosizini mangihlale\nNgikuzwe lokhukujabula\nOkukuwe, Nkos’.\n\n4. Esam’ isiphambano, Nkosi,\nNgimelw’ uba ngisivumele,\nNxa ngibethelwe kanye nawe\nNgovuka name ebomini,\nNginjengawe, Nkos’.` },
  { id: 275, title: 'Ngiphe, Baba, Inhliziyo', lyrics: `1. Ngiphe, Baba, inhliziyo\nEhlanzekileyo;\nUngenzel’ umoya musha\nOqinisileyo.\n\n2. Uyathanda inhliziyo\nEdabukileyo;\nAwuzondi umphefumlo\nOthobekileyo.\n\n3. Baba, mawungangilahli\nEbusweni bakho,\nKodwa ungijabulise\nNgenjabulo yakho.\n\n4. Vula izindlebe zami\nZizwe ngomsa wakho;\nNgobatshela abonayo\nIzindaba zakho.` },
  { id: 276, title: 'Thixo, Ngiyabheka Kuwe', lyrics: `1. Thixo,ngiyabheka kuwe;\nNkosi, ngisindise;\nIzwi lokukhala kwami\nMalifike kuwe.\n\n2. Uwe oyiNkosi yami\nEngilinda yona.\nNgithi ngenhliziyo yami\nAwu, mangikubone.\n\n3. Siphi isigodlo sakho\nLapho wakhe khona?\nMawungivumele, Nkosi,\nNgihlonzele khona.\n\n4. Sengikwazi, senginawe,\nUphakathi kwami;\nNkosi, ngohlalela wena\nNgezinsuku zami.` },
  { id: 277, title: 'Jesu, Mthandi Wenhliziyo', lyrics: `1. Jesu,Mthandi wenhliziyo,\nKuhle ngindizele kuwe,\nAyagub’ amaze lapha,\nKuvunguz’ umoya.\nSiza, E Msindisi, siza,\nIsiphepho siyandiza;\nNgiqondis’ icweba lami,\nUngamkele mina.\n\n2. Eny’ inqaba anginayo,\nEngibalekela kuyo;\nMawungangishiyi ngedwa,\nUngiphase kodwa.\nLonk’ ithemba limi kuwe,\nNokusiza konke kuwe;\nEthunzini lamaphiko\nSith’ ikhanda lami.\n\n3. Kuwe, Kristu, ngizibika,\nKonke wena wanginika;\nUyamisa abawayo,\nUyavus’ ofayo.\nUkulunga, into yakho,\nKepha mina anginakho;\nYebo, ngingcolile kodwa\nWena- umsa wodwa.\n\n4. Umsa wakho sewandile,\nUngisitha ngiwonile;\nUyandis’ im’thombo leyo,\nNgenz’ ogeziweyo.\nUngumthombo\nWokuphila,\nNagesihle ungiphile;\nVuka, Mthombo wenhliziyo.\nWenz’ ongapheliyo.` },
  { id: 278, title: 'Mangibe Qotho', lyrics: `1. Mangibe qotho,ngoba ngiye-\nThenjwa,\nMangihlanzeke ngenxa yab’\nAbanye,\nMangiqinise ngidel’ inhlupheko,\nNgibe-iqhawe, ngilwe nakh’\nOkubi.\n\n2. Mangibathande nabangangi-\nThandi,\nMangib’ iophana,\nNgingasakubali,\nMangizithobe, ngazi ngibuthka,\nNgibe-nomusa ngibathwes’\nAbanye.` },
  { id: 279, title: 'Bamba Isandla, Baba', lyrics: `1. Bamba isandla, Baba, nxa\nNgingedwa,\nInzima, ifiphel’ indlela yam’,\nBamba isandla; khona\nNgingesabe,\nNoma kumnyama lapha Nkosi\nYam’.\n\n2. Bamba isandla, ngingumntwan’\nOmncane,\nNgingazi ukukheth’ indlela\nYam’,\nBamba isandla uma ngikhathele,\nFuna ngiwele phansi, Nkosi\nYam’,\n\n3. Bamba isandla, Baba, ngitho-\nKoza\nNgisizwe son’ isandla sakho,\nNkos’;\nBamba isandla, ngiyathol’\nAmandla\nUma ngikwazi useduze, Nkos’.\n\n4. Bamba isandla lapho ngi-\nSondela,\nNgishone emfuleni, Msizi\nWam’;\nBamba isandla, ngifika ekhaya,\nNgibon’ ubuso bakho, Jesu\nWam’.` },
  { id: 280, title: 'Laph’ Izivunguvungu', lyrics: `1. Laph’ izivunguvungu\nZifus’ impilo yami,\nNobubi budlangile,\nUMlingi esenqoba,\n\nUngikhumbule, Nkosi yam’;\nUngikhumbule, Nkosi yam’;\n\n2. Lapho ngiwel’ ulwandle,\nLukhuz’ ulaka lwalo,\nLaph’ izingozi zalo\nZisong’ ukungigwinya.\n\nUngikhumbule, Nkosi yam’;\nUngikhumbule, Nkosi yam’;\n\n3. Lapho izono zami\nZinzim’ emphefumlweni,\nZisuse, wena Baba;\nNgothula ngomsa wakho.\n\n4. Lapho imihla yami\nIncipha emhlabeni,\nMangikubone, Nkosi,\nNgikhuphukele kuwe.` },
  { id: 281, title: 'Mangisondele', lyrics: `1. Mangisondele \nKuwena, Nkos’, \nNoma ngiqhutshwa \nInhlupheko, Nkos’, \nNgingathokoza; \nNgiphinda ngithi-nje, \nUngisondeze, Nkos’ \nKuwe manje. \n\n2. Noma ngehlelwa \nNgokubi Nkos’ \nNgilel’ etsheni, \nNgihlupheka, Nkos’ \nEmaphushweni \nNjalo ngingathi-nje, \nUngisondeze, Nkos’, \nKuwe manje. \n\n3. Ngibonisise, \nO Nkosi yam’, \nUkuthi konke \nOkukuwe, Nkos’, \nKuyizithunywa \nZokungisiza-nje, \nKungisondeze, Nkos’, \nKuwe manje, \n\n4. Nasekuseni \nNgobonga, Nkos’ \nNasosizini \nNgodumisa, Nkos’, \nUma kungabe \nNgokuhlupheka kwam’, \nNgiyasondezwa, Nkos’, \nKuwe manje. \n\n5. Noma ngindiza, \nNgethaba, Nkos’, \nNgiye phezulu \nEzulwini, Nkos’, \nNjalo ngovuma, \nNgiphinde ngithi-nje, \nUngisondeze, Nkos’, \nKuwe manje. ` },
  { id: 282, title: 'Khuluma Kimi, Nkosi Jesu', lyrics: `1. Khuluma kimi, Nkosi Jesu, \nNgikhulumis’ okwakho name; \nMangibafun’ abantu bakho \nNjengawe, nxa belahlekile. \n\n2. Ngisize ungihole, Nkosi, \nNgibuyis’ abacezukayo; \nNgiphiw’ ukudla nguwe, Nkosi, \nNgibaphe abalambileyo. \n\n3. Ngisiz’ ungiph’ amandla, Nkosi, \nUkuba ngisathemba wena, \nNgisize abalahlekayo, \nAbabengasakholwa kuwe. \n\n4. Ngisiz’ ungifundise, Nkosi, \nNgifundis’ iqiniso lakho; \nAmazwi am’ uwaqondisa, \nAzike ezinhliziyweni.  \n\n5. Ngisiz’ ungiduduze, Nkosi, \nUkuba ngenanyiswe nguwe; \nNgibaduduze name futhi \nBonk’ abakhwelwe ubunzima. \n\n6. Ngisiz’ ungigcwalise, Nkosi, \nNgezipho zakho zonk’ ezinhle, \nIz’ ichichime inhliziyo, \nIfuna ukuncoma ngawe. \n\n7. Angisebenze kuwe, Nkosi, \nNjengokubona kwakho njalo, \nNgize ngibon’ ubuso bakho, \nNgibuse nawe naphakade. ` },
  { id: 283, title: 'Jesu, Ngangikulahlile', lyrics: `1. Jesu, ngangikulahlile, \nKanti wena ungifele. \nNgize namhla ngijambile; \nMawuphinde ungamkele. \n\n2. Angisacabang’ ukuthi \nNgifanele ububele; \nNokho ngiyakhala ngithi, \nMawuphinde ungamkele. \n\n3. Nginezono ezinkulu, \nNamhla zingibandezele. \nNgiyabheka ngaphezulu; \nMawuphinde ungamkele. \n\n4. Konke lokhu ngikwenzile, \nKubi, sengikujambele; \nNkosi yam’, ngiqinisile, \nMawuphinde ungamkele. \n\n5. Nkosi Jesu, ngiyakhala, \nMawuze ungiduduze. \nNgililel’ elam’ icala; \nMawuphinde ungamkele. ` },
  { id: 284, title: 'Kuyezwakala KuThixo', lyrics: `1. Kuyezwakala kuThixo, \nNakuba-nje sithule, \nUkuvumela komoya \nUkwenz’ intando yakhe \n\n2. Kuyezwakala kuyena \nNokuwa kwe’nyembezi, \nNokulingoza komoya, \nSinaye yena yedwa. \n\n3. Kuyezwakala kuyena \nAmazwi ezingane, \nNemithandazo yomoya \nEbong’ uthando lwakhe. \n\n4. Kuyezwakala kuyena \nIlizwi las’ isoni \nEsiphenduka ngomoya; \nKubong’ izingelosi! \n\n5. Kuyezwakala kuyena \nIlizwi lokholwayo \nEsesondela ngomoya, \nEngena ezulwini. \n\n6. Masizwakale kuwe, Nkos’, \nEsisondela ngawe. \nIsifundise umoya \nNokuba sithandaze. ` },
  { id: 285, title: 'Mangikubone, O Nkos’ Ethandwayo', lyrics: `1. Mangikubone, O Nkos’ \nEthandwayo, \nKonke okunye kuyize kimi; \nNgizindle ngawe nasebusuku, \nNoma ngilele mawungikhanyele. \n\n2. Yiba-ulwazi, ube-izwi lami, \nNgikhona kuwe, ukhona kimi; \nUbe-uBaba, ngibe-umntwana. \nUhlale kimi, simunye kuwena.  \n\n3. Yiba-lihawu nowami umkhonto, \nUbe-‘sizotha nothabo lwami; \nNgiphakamise ngawakho \nAmandla. \n\n4. Angikhathali ngemfuyo \nNodumo, \nUyifa lami manje nanini; \nNguwena wedwa osenhliz’yweni, \nNkosi yezulu, ligugu kimina. \n\n5. Nkosi yezulu, nxa senginqobile, \nNgiph’ injabulo yasezulwini; \nWen’ othandwayo, noma \nKunjani, \nMangikubone obusa umhlaba. ` },
  { id: 286, title: 'Hola, Baba, Hol’ Abakho', lyrics: `1. Hola, Baba, hol’ abakho \nPhezu kwalamaza; \nSondle, siphe, siqondise, \nWena, Msizi wethu; \nSinezibusiso zonke, \nNgoba unguBaba. \n\n2. Musindisi, sixolele, \nUyayabaz’ abantu; \nOwasandulela lapha, \nWezwa lonk’ uhlupho; \nWakhandleka wedwa, wezwa \nUbunzim’ ehlane. \n\n3. Moya oyingcwele, yehla, \nUsithokozise; \nSiphe ukuthand’ abakho, \nNokwethaba kuwe; \nNxa sabelwe, siyekelwe, \nSoba-nokuthula.  \n\n4. Nkulunkulu, Baba wethu, \nSingabakho njalo; \nJesu Kristu, Musindisi, \nSiqinis’ amandla; \nNkosi, Moya oyingcwele \nHlala nathi njalo. ` },
  { id: 287, title: 'Lubhaq’ Oluhle', lyrics: `1. Lubhaq’ oluhle, sekumnyama \nKimi, \nNgihole; \nUngiqondise, angibon’ indlela, \nNgiyis’ ekhaya. \nNgihole-nje; Nganele ngingaboni \nPhambili le, uma ngihamba nawe \n\n2. Kukade ngingenje, ngikhala \nNgithi, \nNgihole; \nNgathand’ eyam’ indlela. Manje \nNgithi, \nMawungihole. \nNgethamb’ umhlaba nokukhanya \nKwawo; \nNgithethelel’ ungakubali kimi. \n\n3. Amandla akho kade angigcina; \nKahole. \nAngidlulis’ ezingozini zonke \nZalokhukuhlwa. \nKusile sengobon’ im’hlobo yami \nEkade ngangihlukaniswe nayo. ` },
  { id: 288, title: 'Ekuthokozeni Kwakho', lyrics: `1. Ekuthokozeni kwakho, usubu- \nSisiwe, \nMema umzalwane wakho,abe- \nNawe. \n\n2. Nxa uvun’ insimu yakho, kuku- \nNing’ ukudla, \nUbekel’ iNkosi yakho nabampofu.  \n\n3. Nxa uzizwa unamandla, uzwa \nUliqhawe, \nFuna low’ oding’ usizo, umphu- \nThume. \n\n4. Nxa usindwa inkathazo enhli- \nZ’yweni yakho, \nUz’ uthwale eyomunye; \nIzoncipha. \n\n5. Owenzela omncinyane, nom’ \nIluph’ usizo, \nUmenzela yen’ uJesu; washo \nNjalo. ` },
  { id: 289, title: 'Alukh’ Ubandlululo', lyrics: `1. Alukh’ ubandlululo \nKuKristu Jesu; \nBamunye ngaluthando \nAbamthandayo. \n\n2. Abeqiniso bonke \nBe’ nhlanga zonke \nBahlanganiswa \nUye, \nBemkhonza yena. \n\n3. Sibandakanywa sonke \nNgejokwe lakhe; \nOngokaBab’ umntwana \nUngumfowethu. \n\n4. KuKristu abasenhla \nNabasezansi \nBamunye othandweni, \nEzweni lonke. \n\n5. Kakhethi buso bamuntu \nNambala wakhe. \nWathath’ ubuntu bethu; \nSimunye kuye. ` },
  { id: 290, title: 'Sisindw’ Umthwal’ Omkhulu', lyrics: `1. Sindisw’ umthwal’ omkhulu \nWasemhlabeni; \nSisizw’ uJesu kodwa, \nEthwele nathi. \n\n2. Siyezw’ ubandlululo, \nSinenhlupheko; \nSiyalandel’ uJesu \nOwahlupheka. \n\n3. Siphiw’ ithemba nguye, \nLofezwa lona. \nUngumzalwane wethu; \nAlukh’ uvalo. \n\n4. Amafanelo onke \nAbantu bonke \nAhlalel’ ukwamkelwa \nKwentando yakhe. \n\n5. Upheth’ izizwe zonke, \nZifana kuye. \nAbantu boba-munye \nNgothando lwakhe. ` },
  { id: 291, title: 'Ake Sibonge INkosi Enkulu', lyrics: `1. Ake sibonge iNkosi enkulu \nYezulu! \nIzakuqeda ukulwa nezimpi \nNokufa. \nIso leNkosi lisiqaphela njalo, \nIsivikela, inomsa. \n\n2. Makubuyel’ ukuthula ezweni \nKubantu, \nYasho iNkosi; kwafik’ ukuthula \nEzweni, \nNokujabula kubo abantu bonke, \nManje sebezakubusa. \n\n3. Ake sibonge iNkosi, iNkosi \nKuphela, \nEsisizileyo, ezwil’ ukukhala kwa- \nBantu, \nuSimakade uMninimandla onke; \nMasidumise iNkosi. \n\n4. Masinikel’ umnikelo othandwa \niNkosi; \nNxa sijabula, sithobe, sibonge \niNkosi; \nNxa isihaya, sibekezele yona, \nSiyilalele, sikhonze.  \n\n5. Nkosi, mawulibusise lelizwe \nLakithi, \nNababusayo ubanikezele ukwazi, \nUbafundise, baze babuse kahle, \nSize sibe-nokuthula. ` },
  { id: 292, title: 'Thixo Baba, Ngedukile', lyrics: `1. Thixo Baba, ngedukile, \nNasekhaya ngisukile; \nNgifundise ngivumele \nIntando yakho. \n\n2. Noma kumbi konke kimi, \nMangithule; ngingathini? \nNgibonise osizini \nIntando yakho. \n\n3. Noma kade nglilela, \nIzihlobo ngiziswela, \nMangithoba, ngiphendule, \n“Intando yakho.” \n\n4. Noma uthi mangidele \nOkukhulu, kufanele; \nNgenjabulo ngivumele \nIntando yakho. \n\n5. Kuthi uma ngiphiliswa, \nNangoMoya ngibusiswa, \nThixo wami ngenanyiswa \nIntando yakho. \n\n6. Thoba njal’ intando yami, \nSus’ ukungavumi kwami, \nNoma kulukhuni kimi, \nIntando yakho. \n\n7. Emhlabeni ngingasekho, \nNenyembezi nankuleko, \nNgizogwaba phambi kwakho. \nIntando yakho. ` },
  { id: 293, title: 'Kristu, Musindisi Wethu', lyrics: `1. Kristu, Musindisi wethu \nWena ulithemba lethu; \nUlithemba labo bonke \nAbalahl’ ukona konke, \n\n2. Abazond’ izono zabo, \nAbadel’ intando yabo, \nAbakheth’ indlela yakho, \nAbathwal’ umthwalo wakho. \n\n3. Ulithemba leqiniso, \nAwunayo inkohliso, \nUyagcin’ abathembayo, \nNgize, Nkosi, nangu mina! \n\n4. Ngithi, sengizinikile, \nNgingowakho, ngivumile; \nMawube-ithemba lami, \nIngeyam’ intando yakho. ` },
  { id: 294, title: 'Ukukhonza Yon’ INkosi', lyrics: `1. Ukukhonza yon’ iNkosi \nAsikh’ okomlomo wodwa; \nUkuthanda yon’ iNkosi \nAsikh’ okwamazwi odwa. \n\n2. Ku’ kuhamba ngokulunga \nNangothando nobubele; \nKu’ kubamba iqiniso \nNokukhula ngobungcwele. \n\n3. Ku’ kusuka ebubini, \nNgenhliziyo ezamayo; \nKu’ kubheka eNkosini, \nNgenhliziyo ethandayo. ` },
  { id: 295, title: 'Ngiyakudinga, Jesu', lyrics: `1. Ngiyakudinga, Jesu, \nInkathi yonke; \nIlizwi lakho lodwa \nLinokuthula. \n\nMsindisi, ngikuswele \nZonke izikhathi; \nBusisa, umntanakho, \nNgiyeza kuwe. \n\n2. Ngiyakudinga, Nkosi; \nUhlale nami; \nZiyize izilingo \nNxa useduze. \n\n3. Ngiyakudinga njalo, \nSenginosizi; \nUngekho, ngohluleka, \nMawungisize. \n\n4. Ngiyakudinga njalo, \nGcwalis’ okwakho; \nUngifundise, Nkosi, \nIntando yakho. \n\n5. Ngiyakudinga, Jesu, \nUngenz’ owakho; \nUngiph’ uMoya wakho \nOcwebileyo. ` },
  { id: 296, title: 'Jes’, UnguMalusi Wethu', lyrics: `1. Jes’ unguMalusi wethu, \nSiyethemba kuwe; \nWena, unguMbusi wethu, \nSizinika kuwe. \n\n2. Wasifuna silahleka, \nKungomusa wakho; \nWasihlanza, wasamkela \nEmhlambini wakho. \n\n3. Siyabonga umsa wakho \nOsiphile wona; \nWazithwal’ izono zethu, \nWazifela zona. \n\n4. Imizimba ib’ eyakho, \nSikukhonze ngayo; \nIb’ eyakho nenhliziyo, \nSikuthande ngayo. \n\n5. Zonk’ izono sozishiya, \nSizwe izwi lakho; \nUnqamlezo soluthwala, \nSenz’ intando yakho. \n\n6. Ube nathi, usisize, \nLapha emhlabeni; \nEkufeni usamkele \nKuwe ezulwini. ` },
  { id: 297, title: 'Baba, Ngithabathe, Ngenze', lyrics: `1. Baba, ngithabathe, ngenze \nNgibe-ngcwele, ngingowakho; \nMangifunyaniswe njalo \nEzinyaweni zakho. \n\n2. O Msindisi, ungikhangqe, \nNgigcwalis’ uthando lwakho; \nMangingabuyiswa lutho \nOnqamlezweni lwakho. \n\n3. Moya oyiNgcwele, size, \nNgibonis’ okoMkhululi; \nNgiholele, ungigcine, \nNgifikise ekhaya. ` },
  { id: 298, title: 'Nkosi, Namhla Ngiyathela', lyrics: `1. Nkosi, namhla ngiyathela, \nNgingowakho ukuphela; \nThatha konke kub’ okwakho, \nWon’ umzimba nenhliziyo. \n\n2. Naz’ izandla, zingezakho, \nZisebenz’ intando yakho; \nNezinyawo zingezakho, \nZigijime zenz’ okwakho. \n\n3. Nal’ ulimi lukhulume, \nLuyazis’ intando yakho; \nLumemeze, lufundise, \nLulibong’ igama lakho. \n\n4. Nay’ impahla ingeyakho, \nYonke yona asiyami; \nThatha, Nkosi, yenz’ okwakho \nNgakho konk’ okungokwami. \n\n5. Thatha futh’ intando yami, \nAngisash’ ukuth’ eyami; \nNenhliziyo ingeyakho, \nBusa kuyo, Nkosi yami. ` },
  { id: 299, title: 'O Msindis’ Othandekayo', lyrics: `1. O Msindis’othandekayo, \nNgingowakh’, owakho wedwa; \nSengihlanzw’ igazi lakho, \nAkubongwe wena, Mvana! \n\nAleluya, Aleluya! \nAyibongwe yon’ iMvana; \nSengihlanzw’ igazi layo, \nAyibongwe yon’ iMvana.  \n\n2. Kad’ izama inhliziyo \nUkuthol’ ukuphumula; \nKepha ngath’ ukwahluleka, \nNgabusiswa ngokwethemba. \n\nAleluya, Aleluya! \nAyibongwe yon’ iMvana; \nSengihlanzw’ igazi layo, \nAyibongwe yon’ iMvana. \n\n3. Ngiyethemba, ngiyethemba, \nNgizw’ igazi lingihlanza; \nSengihlezi emthonjeni, \nLa kugezw’ izono zonke. \n\n4. Ngizinkezela kuwe, \nNgikukhonze, ngikufele; \nNgoqinisa ngomsa wakho \nZizw’ izoni, zisindiswe. \n\n5. Yebo, ngiyommel’ uJesu, \nNgoba ungisindisile, \nUngihlanze inhliziyo; \nMakabongwe njalonjalo. ` },
  { id: 300, title: 'Baba, Sewungowam’', lyrics: `1. Baba,sewungowam’ \nNgizinikile la \nKuwe wedwa. \nWen’ ungaluse, \nWen’ ungifunze \nUngibonise la, \nNakho okwam’. \n\n2. Ngiyazethula, Nkos’, \nUmphefumulo wam’, \nNomzimba lo; \nNakh’ ukuqonda kwam’, \nNakh’ ukuthanda kwam’, \nMakukhonjiswe ngqo \nNguwe wedwa. \n\n3. Busa izandla zam’ \nNaz’ izinyawo zam’, \nWena wedwa. \nBus’ inhliziyo yam’, \nYon’ ingumthombo wam’, \nWakh’ ukuphila kwam’, \nBusa kuyo ` },
  { id: 301, title: 'Ngiyamuzwa uMsindisi', lyrics: `1. Ngiyamuzwa uMsindisi \nEngibiza ngimlandele, \nEthi, unqamlezo lwami \nNgiluphathe, ngimlandele la. \n\nLa engiholela khona, \nNgomsa wakhe ngomlandela la. \n\n2. Ngomlandel' eGetsemane, \nNasekuhluphekeni, \nNasekudelelweni, \nNgomsa wakhe ngomlandela la. \n\nLa engiholela khona, \nNgomsa wakhe ngomlandela la \n\n3. Ngomlandel' ekuqunyweni, \nNgomlandel' ekubinqweni, \nNasekubethelweni, \nNgomsa wakhe ngomlandela la \n\n4. Wonginika umsa wakhe, \nNgoqinisw' amandla akhe, \nWonginika nobukhosi, \nAngishiye? Phinde, khona la! ` },
  { id: 302, title: 'Mangibe Njengo Jesu', lyrics: `1. Mangibe njengo Jesu, \nWayengothobileyo; \nKuhle ngibe njengaye, \nWayengothobileyo. \n\n2. Mangibe njengoJesu \nNgamazwi onke ami, \nNgibeke kahle kuye, \nLithambe izwi lami. \n\n3. Mangibe njengoJesu, \nEhlutshwa edelelwa \nKaziphindiselanga, \nQha, wabathandazela \n\n4. Mangibe njengoJesu; \nKaningi ethandaza \nEyedwa entabeni, \nUYise wayemuzwa. \n\n5. Mangibe njengoJesu, \nNgemisebenzi yami, \nNgimbheke, ngimlandele, \nEkuhambeni kwami, \n\n6. Anginjengawe, Jesu; \nNgozama nokho ngawe, \nNgimele, ungisize \nNgize ngifane nawe. ` },
  { id: 303, title: 'Ngiyeza, Nkosi, Ngiza Nginje', lyrics: `1. Ngiyeza, Nkosi ngiza nginje, \nYileli lodwa izwi lam' \nLokuba wangifela nami; \nJesu, Mvana, ngiyeza. \n\n2. Ngiyeza, Nkosi, ngiza nginje, \nNgingelisus' icala lam'; \nIgazi lakho longihlanza, \nJesu, Mvana, ngiyeza. \n\n3. Ngiyeza, Nkosi ngiza nginje, \nNgishayw' uvalo enhliz' ywen'; \nKukhon' ukulwa emoyeni. \nJesu, Mvana, ngiyeza. \n\n4. Ngiyeza, Nkosi, ngiza nginje, \nNgimpofu, ngi' mpuputhe nam'; \nAmehlo nokufuya ngiphe; \nJesu, Mvana, ngiyeza. \n\n5. Ngiyeza, Nkosi, ngiza nginje; \nWothethelel' izono zam', \nWohlanza wonk' umoya wami; \nJesu, Mvana, ngiyeza. \n\n6. Ngiyeza, Nkosi, ngiza nginje, \nUthando lunqobile kim', \nNgithela konke, ngingowakho; \nJesu, Mvana, ngiyeza. ` },
  { id: 304, title: 'Jesu, Mukhululi, Ngingowakho Wedwa', lyrics: `1. Jesu, Mukhululi, ngingowakho wedwa, \nNgiyazinikela kuwe, Jesu; \nAnginato manje, Nkosi ethandwayo, \nKonke okukimi kungokwakho. \n\nJesu, Nkosi yami, manje \nngingowakho, \nNawe, othandwayo, ungo-wami. \n\n2. Kade ngangeduka, wangihawu-kela \nWaze wangifela ngasindiswa; \nSengisndleleni engiyis' ekhaya, \nNgiyakhwezwa nguwe, O Msindisi. \n\n3. Mawuhlale nami, ngivikele njalo, \nNgiyabheka kuwe, wena, Nkosi, \nUma wen' ukhona ngothokoza njalo, \nNgoba wena ungamandla ami. \n\n4. Selumnandi kimi loluthando lwakho, \nWena unqabile ngobubele, \nAngibon' omunye olingana nawe, \nEnhliz'yweni yami busa, Nkosi. ` },
  { id: 305, title: 'O Jesu, Ngingowakho', lyrics: `1. O Jesu, ngingowakho, \nNgithembisile \nUkuthi ngokukhonza \nNgikulandele; \nYiba-seduze nami, \nO Nkosi yami, \nUkuze ngingeduki \nNgilahlekele. \n\n2. Yiba-seduze nami, \nNgikwaz' ukhona, \nIzinto zalomhlaba \nZiyangikhanga; \nIsono zihlasela \nZingizungeza, \nSondela kimi, Jesu, \nUngivikele. \n\n3. Mangizw' ilizwi lakho, \nMalizwakale, \nLikhuz' izinkanuko, \nLithob' inkani; \nKhuluma kimi, Nkosi, \nNgivuse njalo, \nKhuluma ngize ngizwe, \nMvikeli wami. \n\n4. O Jes', uthembisile \nAbalandeli \nUkuthi boba-nawe \nEbukhosini; \nNgithembisile mina \n'Kukhonza njalo, \nNgisize ngilandele \nO Nkosi yami. ` },
  { id: 306, title: 'Ngiya Emsebenzini Wam\'', lyrics: `1. Ngiya emsebenzini wam' \nNgegama lakho, Jesu, \nNgifun' ukusebenza ngaz' \nUkuthi ngingowakho \n\n2. Namuphi umsebezi Nkos' \nEngimiselwa wona \nUngakufakazel' ukuth' \nUsenhliz'yweni yami. \n\n3. Ukhona, Jes', uyangibon' \nEm' sebenzini yonke, \nNgoqhuba njalo, Nkosi yam' \nNgethule konke kuwe. \n\n4. Ngisize, Nkosi, ngilithwal' \nIjokwe elilula, \nNgibhek' ithemb' elihleke \nLempilo ephakade ` },
  { id: 307, title: 'O Jesu, Mangihambe Nawe', lyrics: `1. O Jesu, mangihambe nawe, \nNgisiz' abanye, nginjengawe, \nNgizuze kuwe ngomthandazo \nAmandl' omthwalo nenkathazo. \n\n2. Mangithi ngal' uthando lwakho \nNgivuse bon' abangenayo, \nNginqande bon' abedukayo, \nBethol' indlela yasekhaya. \n\n3. Mangizithobe njengomntwana, \nNgizw' ubumnandi bokuzwana \nUbubi bonke ngibunqobe \nNgamandla okukholwa kuwe. \n\n4. Indlela yam' uyikhanyise, \nNgalo ithemba ngiqondise, \nUngiph' eyakho injabulo, \nNgihlale nawe njalo. ` },
  { id: 308, title: 'Singekugcobe Ngamahl\' Amakha', lyrics: `1. Singekugcobe, ngamahl' amakha \nNjengay' uMagdalene ekudumisa \nNokho uthando lunjengempepho \nMalwenyukele kuwena, Nkos' \n\n2. Kwanga impilo ingaqiniswa \nSibaduduze abasindwayo, \nSithi ngomusa nangobunene \nSibasondeze kuwena, Nkos', \n\n3. Masibavuse abanovalo, \nSisul' amehlo abalilayo, \nSibakhalime abedukayo, \nBabuyiselwe kuwena, Nkos', \n\n4. Siqhube njalo, size sihlwelwe \nKuze kuphele imini yethu, \nNxa sesimuka laph' emhlabeni \nMawusamkele kuwena, Nkos'. ` },
  { id: 309, title: 'Siyabizwa Uy\' uJesu', lyrics: `1. Siyabizwa uy' uJesu, \nSisasindwa izinsizi, \n'Mihla yonke usibiza, \nEthi, Mkristu, ngilandele \n\n2. Usibiza nxa silingwa \nUkukhonza okomhlaba, \nUsikhipha ekoneni, \nEthi, Mkristu, ungithande, \n\n3. Usibiza sitamasa, \nSifuyile ngokuyize, \nUsidonsa siye kuye, \nEthi, Mkristu, nans' imfuyo. \n\n4. Siyabizwa uy' uJesu; \nNkosi, masikulalele, \nSikuthande, sikukhonze, \nSithi, Jesu, sisabele. ` },
  { id: 310, title: 'Ngizinikela Kuyen\' UJesu', lyrics: `1. Ngizinikela kuyen' uJesu, \nNgizolandela iNkosi yethu, \nNgikheth' iNkosi ngenkululeko; \nYiyo indlela, ngohamba ngayo. \n\nO Jesu, uMsindisi, \nNgizinika kuwe \nNgokuba wangifela \nUkungisindisa; \nAyikho eny' iNkosi, \nWobus' enhliz'yweni, \nNgizinikela ngingowakho \nWedwa njalo \n\n2. Ngizinikela kowangifela, \nWangithwalela izono zami, \nUthando lwakho lukhulu kimi, \nNgizwa ubizo ngomnika konke. \n\n3. Ngizinikela nokuba ngiphi, \nNgosebenzela umbuso wakhe; \nNoma zinzama izinhlupheko \nZoba-esami isiphambano. \n\n4. Ngiyinikela impilo yami, \nUzongamkela angibusise, \nUyangithuma kwabedukile, \nNgize ngibabuyisele kuye. ` },
  { id: 311, title: 'Yimani isibindi', lyrics: `1. Yimani isibindi, \nMabutho akaJesu, \nUmkhosi niwuhlabe, \nNgayenganqotshwa qha, \nEnqob' uyakunqoba \nEsabahol' abakhe. \nIzitha wozinqoba, \nAbus' i'indawo zonke. \n\n2. Yimani isibindi, \nImbande nans' ikhala, \nYiyani ekulweni \nKuseyinamhlanje; \nYibani-amaqhawe, \nNilwel' iNkosi yenu; \nIgwal' alingabikho, \nYimani nithi nqo. \n\n3. Yimel' uJesu Kristu, \nYim' emandleni akhe; \nIngalo enye ize, \nNeyenu ingesize, \nHlomani izikhali \nZeNkosi yamakhosi, \nNilinde, nithandaze, \nNizodl' umvuzo wenu. \n\n4. Yimani isibindi, \nSekuzophel' ukulwa, \nUmsindo wempi namhla, \nKobongw' iNkosi ngomso; \nKobongwa namaqhawe, \nAphiwe nemiqhele, \nAbuse njalonjalo, \nNeNkosi yobukhosi. ` },
  { id: 312, title: 'Mbal\' Unaso Isibindi', lyrics: `1. Mbal' unaso isibindi \nUmlandel' uJesu na? \nMbal' unaso isibindi \nNxa lihleka izwe na? \nMbal' unaso isibindi \nUphenduk' ikholwa na? \nUyesaba bala, kanti, \nWokugcina kabi na? \n\n2. Nxa uKristu engomkhulu \nKuyo inhliziyo--ha \nNgek' uthule, ngek' ufihle \nUkukholwa kwakho qha. \nAsilutho ubukhulu \nBalomhlaba nokunci; \nKuhli' udumo lukaKristu \nLugcwalise izwe swi. \n\n3. Hlola ukuhamba kwakho, \nSekukade uthi qha; \nWawuphik' iNkosi yakho, \nGuqa ngamadolo la; \nCela umsa, cel' inkambo \nKuye uMsindisi lo, \nCela isibindi naso, \nCel'uqine, uthi ngo. \n\n4. Khumbulake sewahlengwa, \nLahla konke, woza, 'he \nNoma inhlupheko lapha, \nUzobusa khona le. \nIsibindi usunaso, \nUmlandel' uJesu la; \nUkwesaba akusekho, \nYena wokugcina nya. ` },
  { id: 313, title: 'Jesu, Singabakho', lyrics: `1. Jesu, singabakho, \nSiyethemba kuwe; \nUyinqaba yethu \nEzitheni zonke; \nSiyadlul' ezweni \nElinezingozi \nEziyibulala \nImiphefumulo. \n\nJesu, Themba lethu, \nNkos' ebongekayo, \nMawusiqinise \nThin' abakho. \n\n2. Jesu, ungashiyi \nAbantwana bakho, \nSiphe inhliziyo \nYokwethemba njalo; \nSiphe inhliziyo \nYokuthanda wena \nYokusihambisa \nNgemithetho yakho. \n\n3. Uma singethembi, \nNoma singathandi, \nNokuhamba kabi, \nImpi lokho kithi! \nJesu, uyinqaba \nEzitheni zonke; \nNgawusiph' amandla \nOkwahlula ngawe \n\n4. Impi yasekhaya \nUma inqotshiwe, \nLeyo yangaphandle \nAyisenamandla. \nNkosi, singabakho, \nUyinqaba yethu, \nAsingene kuwe, \nSingesabi lutho. ` },
  { id: 314, title: 'Qina, Mngan\', Ungakhubeki', lyrics: `1. Qina, mgan', ungakhubeki \nNom' indlel' imnyama; \nNang' uMholi womthobeki, \nThemba kuy' uJesu. \nNom' indlela iba-inde, \nIsehlane, imbi, \nHamba, noma ukhathele; \nThemba-nje, themba-nje, \nYenza ukulunga. \n\n2. Xwaya wen' izinkanuko, \nNemikhub' emibi; \nNoma usuhlekw' abantu, \nThemba kuy' uJesu; \nNom' uzondwa, nom' uthandwa, \nUtotshozw' udelwa, \nYek' abantu--nans' iNkosi! \nThemba-nje, themba-nje, \nYenza ukulunga. \n\n3. Izw' elihl' ukuthi, \"Themba, \nYenza ukulunga,\" \nLithulis' izinhliziyo, \nLivuthis' amandla. \nQina, mngan' ungakhubeki \nNom' indlel' imnyama; \nNang' uMholi womthobeki! \nThemba-nje, themba-nje, \nYenza ukulunga. ` },
  { id: 315, title: 'We, Nhliziyo Yami', lyrics: `1. We nhliziyo yami, \nMawuhlakaniphe; \nZikuhanq' izitha zakho, \nZivukela wena. \n\n2. Linda uthandaze, \nUngayek' ukulwa; \nCela ngezinsuku zonke \nENkosin' amandla. \n\n3. Ungalahli wena \nIzikhali zakho; \nEkufeni uzoqeda \nUmsebenzi wakho. ` },
  { id: 316, title: 'Qina Kuyez\' Ukulwa', lyrics: `1. Qina kuyez' ukuhlwa, \nQina imin' ikhona, \nQina umbeth' umanzi, \nImbal' iphuma; \nQina im'seb' ivela, \nQina ngemini yonke, \nQina kuyez' ukuhlwa, \nKoyekwa konke. \n\n2. Qina kuyez' ukuhlwa, \nQina kushon' ilanga, \nSebenz' mini yonke, \nKunasaphuthi lutho; \nQina kuyez' ukuhlwa, \nKungenz'we lutho. \n\n3. Qina kuyez' ukuhlwa, \nBheka seliyashona, \nBhek' ukubheja kuhle, \nSelishona. \nQina sekuzophela, \nKufe kunyamalale, \nQina kuyez' ukuhlwa, \nKophela konke. ` },
  { id: 317, title: 'Onobuqhawe Bokulwa Nokubi', lyrics: `1. Onobuqhawe bokulwa nokubi \nMakaqinise ngqo, emkhonz' uJesu \nNgek' adangale la, ngek' azisole qha, \nEsazimisisel' abe-'sihambi. \n\n2. Abamsabisa, bamhleka bemdela, \nBazikhathaza-nje, \nKuyamkhuthaza \nNgek' avinjelwe qha, nakub' ehlaselwa, \nUsezophumelel' eyisihambi. \n\n3. Usavikelake ngoMoya wakho, \nEkuphumuleni sothola ubomi, \nNgingephumuleni sothola ubomi, \nNgingephuthiswe-bo, ngizoqinisa ngqo, \nNgithemb' izwi lakho, ngiyisihambi. ` },
  { id: 318, title: 'Naz\' Izinkulungwane', lyrics: `1. Naz' izinkulungwane \nZembeth' ezithe qwa, \nIzimpi zabangcwele \nZenyuka laphaya; \nUkulwa kuphelile. \nKunqotshw' ukufa nya, \nBavulelen' im'nyango. \nSebenqobile. \n\n2. Umhlaba nal' izulu \nKuduma kuthi zwi, \nKuhalaliswa bona, \nBengena bethi swi. \nUsuku lwenjabulo \nLwezizwe zonke la. \nIzinhlupheko zonke \nSeziklonyelwa. \n\n3. Kuzobonanwa khona \nEzweni laphaya, \nNalab' abasishiya \nBasandulela la; \nKophel' izinyembezi, \nKube-kumnandi du, \nKungekh' abafelweyo \nNezintandane. \n\n4. Sondeza usindiso, \nO Mvana kaThixo, \nUqoq' abantu bakho, \nUmis' umbuso ngqo; \nUbuye nobukhosi, \nNqobis' abakho la, \nMalikuvez' izulu, \nUfike, Nkosi. ` },
  { id: 319, title: 'Sihole, Simakade', lyrics: `1. Sihole, Simakade, \nYiphake impi \nSizolwa nakh' okubi, \nSiqhube izwi; \nAmandla siwaphiwe \nNgokufundisa kwakho, \nManjeke, Simakade, \nUsinqobise. \n\n2. Sihole, Imakade, \nSihlom' ezakho, \nAsilwi ngokwenyama \nKulempi yakho; \nUmkhont' ungokaMoyo, \n'Sihlangu si'kukholwa, \nNgothando nangomusa \nKunqotshw' isitha. \n\n3. Sihole, Simakade \nSikulandele, \nKukhon' ukus' okuhle, \nSewuqhamuka; \nSipheth' isiphambano, \nSiyasikhanyisela, \nOnqob' uthol' umqhele; \nSihole, Nkosi ` },
  { id: 320, title: 'INkosi Yethu Yinqaba', lyrics: `1. INkosi yethu yinqaba \nIyisihlangu sethu \nSisizwa yiyo kalokhu \nNangezikhathi zonke. \nInyoka endala \nInonya olubi, \nIyasikhohlisa, \nAmacebo ayo \nAndil' ezweni lonke. \n\n2. Amandla ethu awakho, \nSingawa masinyane, \nKodwa simiswa iNkosi \nEmnqoba uSathane, \nINKosi enguba? \nUyena uJesu, \nUngumthetheleli, \nUmninimandl' onke, \nINkosi yamabandla. \n\n3. Khath' izwe lonke ligcwele \nOSathane bodwana, \nSingeke sesabe khona; \nSithemb' INkosi yethu, \nSonqoba nempela. \nAngasenzani na \nUmbusi wezwe lo? \nUngolahliweyo. \nUwiswa izwi lodwa. \n\n4. Nezwi leli elikhulu \nBangeke balithinte; \nKhathi behlupha kakhulu, \nUmuntu bemaphuca \nImali nomntwana, \nUmkakhe nomzimba; \nAsilutho lokhu \nINkosi inathi, \nUmbuso ungowethu. ` },
  { id: 321, title: 'Ngingumhambi, Emhlabeni', lyrics: `1. Ngingumhambi emhlabeni,\nAphelil' amandla am';\nNgikhathele ukuhamba,\nNgiyafun' ikhaya lam';\nAwu, Jehova,\nWena unguMsizi wam'.\n\n2. Ngiphe min' amandla akho,\nPhasa umphefumlo wam';\nUngihole endleleni\nEyofik' ekhaya lam'.\nMangisheshe\nNgiyofik' ekhaya lam'.\n\n3. Ngiyakufa masinyane,\nNgizoqed' indlela yam';\nEkufeni ungisize,\nNgingesabi, Nkosi yam';\nEzulwini\nUwawamkel' umoya wam'.` },
  { id: 322, title: 'Sihambi, Qina Ungesabi', lyrics: `1. Sihambi, qina ungesabi,\nSothokoza ekuseni;\nIsho iNkos' uqobo lwayo,\nSothokoza ekuseni.\n\nSothokoza ekuseni,\nSothokoza ekuseni,\nNoma lapha sisahlupheka\nSothokoza ekuseni.\n\n2. We, bandla, ngingathuthumeli,\nSothokoza ekuseni;\nEnikhalayo, manithule,\nSothokoza ekuseni.\n\n3. Enisindwayo, nizw' uJesu,\nSothokoza ekuseni;\nNezoni, manethembe kuye,\nSothokoza ekuseni.\n\n4. Losulwa unyembezi lonke,\nSothokoza ekuseni;\nAlukh' usizi ezulwini,\nSothokoza ekuseni.` },
  { id: 323, title: 'Ngingumhambi, Ngingumfokazi', lyrics: `1. Ngingumhambi, ngingumfokazi,\nNgisahlezi lapha umzuzwana-nje;\nUngangithiyi, ngoba ngiqonda\nEmifuleni enokuphila.\n\nNgingumhambi, ngingumfokazi,\nNgisahlezi lapha umzuzwana-nje\n\n2. Ngiyabheka, ngifuna izwe,\nLaph' ilanga lizokhanya njalo!\nEzweni lapha kumnyama khona,\nNgiyadukiswa, ngiyadukiswa!\n\n3. Kulelozwe engiya kulo,\nUkukhanya kwalo kunguJesu!\nAzikh' izono nezinyembezi,\nAkukh' ukufa nokuhlupheka!` },
  { id: 324, title: 'Ngingumhambi, Nkosi', lyrics: `1. Ngingumhambi, Nkosi,\nKulelizwe la;\nNoma kuba-mnandi\nKunokona la.\n\n2. Lihl' eliphezulu\nKunaleli la;\nAlinanhlupheko\nLona laphaya.\n\n3. Kepha yen' umhambi\nEya laphaya,\nMakazambathise\nNgokumhlophe la.\n\n4. Ungihlanzisise,\nJesu, Nkosi yam':\nMawungiholele\nEndleleni yam'.\n\n5. Nkosi, ngingumhambi,\nAnginafa la;\nNginendawo enhle\nKhona laphaya.` },
  { id: 325, title: 'Ngingowezizwe, Anginalutho la.', lyrics: `1. Ngingowezizwe, anginalutho la,\nKithi kukude le, akusinjenga la;\nNgiyisithunywa sikaJehova,\nNgilapha ngezwi lakho, Nkos'.\n\nYileli izwi lakho, Nkos',\nAlithunywanga nangelos',\n\"Maniphenduke nize kuJehova\nManibuyele kuThixo\".\n\n2. Umthetho ukubantu bonke bezwe-nje\nBashiye umsebenzi wabo om'bilo\nYikhona bangahlala noJehova,\nYilona izwi lakho, Nkos'.\n\n3. Ukudla kwelakithi okwamehlo-nje,\nKukhona nokuphil' okuphakade le.\nNabantu bangahlala noJehova,\nYiwon' amazwi akho, Nkos'.` },
  { id: 326, title: 'Ngiyaz\' Ukhon\' UMhlengi Wami', lyrics: `1. Ngiyaz' ukhon' uMhlengi wami\nOwake waba semhlabeni\nUsengandulele ekhaya,\nLapho ngombona ezulwin'.\n\nUngangibambezeli qha\nKulesinyakanyaka la;\nNxa engibiza ngomsabela,\nNgomhlangabeza khona le.\n\n2. Ngisamangala mina namhla,\nNgiyakumbonga ngani na?\nWashiy' ikhaya lobukhosi,\nUkuz' afele khona la.\n\n3. Ngiyakhumbula mina kabi,\nNgikhona la emabuyeni,\nNgisaqedela emsebenzi,\nObekwa ezandleni zam'.\n\n4. Nginesizungu ngisahamba,\nNgiyakubizwa nini na?\nLomhlaba usuwonakele,\nAwusemnandi kimi, qha.` },
  { id: 327, title: 'Singabahambayo Emhlabeni', lyrics: `1. Singabahambayo\nEmhlabeni;\nKepha sinekhaya\nEzulwini;\nNoma sisahaqwa\nIngozi nosizi,\nSithi akunjalo\nEzulwini.\n\n2. Noma sisabethwa\nIsiphepho\nNgenxa yakho, Jesu,\nNkosi yethu,\nIsikhathi lesi\nEsihlushwa ngaso\nSophela masinya,\nNenhlupheko.\n\n3. Lapho kuMsindisi,\nEzulwinin,\nAbamlandeleyo\nEmhlabeni\nBophumula naye,\nKanye nabangcwele\nNabathandiweyo,\nEzulwini.\n\n4. Thina bakaKristu\nEmhlabeni\nSobheka ekhaya,\nEzulwini,\nSize sidle ifa\nEsiliphiwayo,\nIfa lokuphila\nEzulwini.` },
  { id: 328, title: 'Nginekhaya Laphaya', lyrics: `1. Nginekhaya laphaya,\nNginothil' impela;\nBheka lona lihle hle,\nSengiyalomela\nLapho ngiyobon' iNkos'\nNgakhe kanye nayo;\nNaphakade laphaya\nNgophiliswa ngayo.\n\n2. Nginelizwe laphaya,\nElinokuthula;\nBonk' abakhe lapho-nje,\nBanokujabula,\nKade behlupheka la,\nBeya osizini,\nManje bagcwaliswe swi\nLapho ezulwini.\n\n3. Bonk' abaya laphaya\nBadelel' ukona;\nKonk' okubi phansi la;\nKuvalelwe khona.\nNgihlomel' ikhaya lam',\nNokukhanya kwalo,\nNgokusizw' iNkosi yam',\nNgiqhubeka njalo.\n\n4. Yiba-nami, Nkosi yam',\nUngikhanyisele.\nBheka kimi, Msizi wam',\nMawungisingele.\nNgisesengozini la,\nMawungiqinise.\nNaphakade laphaya\nMangikudumise` },
  { id: 329, title: 'Zulu, Khaya Lami', lyrics: `1. Zulu, khaya lami,\nUyathandwa yimi.\nZulu khaya lami,\nUkhunjulwa yimi.\nZulu, khaya lami,\nUnxanelwa yimi;\nUnoBaba wami,\nUneNkosi yami.\n\n2. Zulu, khaya lami,\nUthenjiwe yimi.\nZulu, khaya lami,\nUnobomi bami;\nNgiyabeka phansi\nLob' obudlulayo;\nNgobamkela kuwe\nObungapheliyo.\n\n3. Unelifa lami\nElingabubiyo,\nElingagugiyo,\nElingangcoliyo,\nZulu, khaya lami\nUnemfuyo yami,\nUnobuhle bami,\nNobungcwele bami.\n\n4. Lapha emhlabeni\nNgidiniwe khona,\nNginosizi lapha,\nSengihluphekile;\nKungangingabona\nWena, khaya lami,\nNgizwe injabulo\nEbomini bami.` },
  { id: 330, title: 'Kuyadlula Isikhathi', lyrics: `1. Kuyadlula isikhathi,\nBayadlula nabakithi,\nNani nami siyashesha,\nSiya elibeni.\n\n2. Siyashesha mina nani\nUkuqonda elibeni,\nKuseduze ukushona\nKwethu thina sonke.\n\n3. Nibhekis' umoya wenu\nKuye lo owanenzayo,\nManimfune, nisindiswe,\nLaph' uJes' ekhona.\n\n4. E Msindisi wethu, Jesu,\nOngumbumbi wakho konke,\nUz' usikhumbulze manje\nInto esiyiyo.\n\n5. Sikhumbul' imvelo yethu,\nNokuqonda kwethu lapho\nKulelozwe lamathunzi\nEsingalaziyo\n\n6. Koba-Khona ukuncinca\nNokumnandi kwaphakade,\nKhathisimbe ukukholwa\nOkungapheliyo.` },
  { id: 331, title: 'Ngesikhashana Nje', lyrics: `1. Ngesikhashana nje\nSodlula khona la;\nSohlala nabo abaseNkosini\nLaphaya.\n\nNjalo ngilungisel’ usuku\nOlukhulu,\nMawungigeze, ungithethelele,\nNkosi yam’.\n\n2. Ngesikhashana nje\nKushon’ ilanga la;\nSokhanyiselwa, lingashon’ ilanga\nLaphaya.\n\n3. Ngesikhashana nje\nSizohlupheka la;\nKepha sohlala kahle kuthulile\nLaphaya.\n\n4. Ngesikhashana nje\nSinabakithi la,\nBemuka, sizohlanganiswa nabo\nLaphaya.\n\n5. Ngesikhashana nje\nLapho sobon’ iNkos’;\nNanjalo sizohlala nay’ uqobo\nLaphaya.` },
  { id: 332, title: 'Khay’ Elihle, Khaya Lami', lyrics: `1. Khay’ elihle, khaya lami,\nMangingene esangweni;\nMangiziphumuze kuwe,\nKhay’ elihle, khaya lami\n\n2. Kade ngangizulazula,\nNgingabon’ ubuhle bakho;\nSengifuna ngokufisa\nNgikubone, khaya lam’.\n\n3. Kunenhlanhla kuwe, khaya!\nAlusekho ulusizi;\nI’ nyembezi ziyasulwa,\nKhay’ elihle, khaya lam’.\n\n4. Abalambi abakithi,\nAbasomi, abasweli;\nBayaluswa oyiMvana,\nSebekuwe, khaya lam’.\n\n5. Sengiyezwa ubumnandi\nObuvela kuwe, khaya;\nNgizongena masinyane,\nKhay’ elihle, khaya lam’` },
  { id: 333, title: 'Lapho Ezulwini', lyrics: `1. Lapho ezulwini\nLikhaya lam’\nKhona eNkosini\nLikhaya lam’\nLapho ngophumula,\nNjalo ngojabula,\nManje ngikhumbula\nIkhaya lam’.\n\n2. Ayikho inkani\nEkhaya lam’.\nIzwe alifani\nNekhaya lam’.\nSisebumnyameni\nLapha emhlabeni,\nBasekukhanyeni\nEkhaya lam’.\n\n3. UMsindis’ ukhona\nEkhaya lam’.\nLapho ngizombona\nEkhaya lam’.\nU’ kukhanya kwalo,\nUlilonda njalo,\nKalungen’ uvalo\nEkhaya lam’.\n\n4. Ngiyalinxanela\nIkhaya lam’.\nNgiyasondezela\nEkhaya lam’.\nNkosi, masinyane\nMawungifumane,\nThin’ asihlangane\nEkhaya lam’.` },
  { id: 334, title: 'Banokuthula Abangcwele', lyrics: `1. Banokuthula abangcwele\nNxa bemuka lapha,\nAkukho okubethusayo\nEnhliz’yweni yabo.\n\nBanefa bona lapho ezulwini,\nBeqond’ ekhaya lapho\neNkosini.\n\n2. INkos’ iyabalungisela\nKhon’ ekhaya labo;\nIngukukhanya kwalo yona,\nIzohlala nabo.\n\n3. Bazakumbona uMkhululi\nOwabafelayo;\nBazomdumisa, bazomkhonza\nYen’ obathandayo.\n\n4. Baphiwa bona ukunqoba,\nAkungen’ uvalo;\nBasekubusisweni bona.\nBojabula njalo.` },
  { id: 335, title: 'Khon’ Ekhaya Labangcwele', lyrics: `1. Khon’ ekhaya labangcwele\nBophumula abeNkosi,\nLapho ayakhon’ uJesu\n‘Kugcwalis’ ufiso lwam’\n\nBophumula abosizi,\nBophumula abosizi,\nBophumula abosizi,\nNgophumula nam’.\nLapho sengiwel’ iJordan,\nEnsimini yaseEden,\nNgisemthini wokuphila,\nNgophumula nam’.\n\n2. Ungilungisele indlu\nEyakuma naphakade,\nNgoba ngiyohlala njalo\nKulelozwe labeNkos’\n\n3. Ubuhlungu bungengene,\nUkugula ngingekwazi,\nKepha ngoba-naw’ umqhele\nWokuphila laphaya.\n\n4. Nina, bantu bobukhosi,\nMemezani “Halahala;”\nAmasango ayovulwa,\nNiyongena ezulwin’.` },
  { id: 336, title: 'Phezulu eNkosini', lyrics: `1. Phezulu eNkosini\nBangabangcwele bodwa\nPhezulu ezulwini\nKuhlal’ imhlophe yodwa.\n\n2. Ofun’ ukuya khona\nMakazikhulekele\nAlungiselwe lona\nUMoya oyingcwele\n\n3. UJesu wasifela\nKuphel’ icala lethu\nIz’ ithi ibengcwele\nImiphefumlo yethu.\n\n4. Sithi, manxa sidliwa\nUkufa emhlabeni,\nSingabi-nakwaliwa\nUkuya ezulwini.` },
  { id: 337, title: 'Yek’ iJerusalema', lyrics: `1. Yek’ iJerusalema,\nUmuzi okhanyayo!\nNgingeze ngakubala\nOkuhle laphaya!\nAkukabonakali,\nKudlula konk’ okunye;\nUmnandi lowomuzi,\nINkos’ ikhona le.\n\n2. Kuyezwakala khona\nIhubo lentokozo,\nBaningi abangcwele\nBabonga laphaya,\nBafakazel’ uJesu\nNgegazi nangokufa;\nNguye owakhe khona,\nYena ukhona le.\n\n3. Bayaphumula khona\nAbahluphekileyo;\nNabo bayaphiliswa\nINkosi laphaya.\nIyabenzel’ idili,\nBembeswa okumhlophe;\nBahuba njalo, bethi,\nINkos’ ibongwe la.\n\n4. Elabakhethiweyo\nLelozwe laphezulu,\nBahlala, bejabula,\nBethi, likhaya la.\nThina silangazela\nIkhaya labangcwele;\nMasibe-nawe, Baba,\nNeNkosi yethu le.` },
  { id: 338, title: 'Khumbula Ikhaya Laphaya', lyrics: `1. Khumbula ikhaya laphaya,\nKoba-mnandi kakhulu kunala,\nBabuthen’ abangcwele kulona,\nAbembeth’ okumhloph’ okuthe\nQwa!\nLaphaya, laphaya,\nKhumbula ikhaya laphaya.\n\n2. Khumbul’ izihlobo laphaya,\nEzahamba zangena ezulwini’;\nSengigwaba igama leWundlu,\nZiphumule zisenjabulwen’.\nLaphaya, laphaya,\nKhumbul’ izihlobo laphaya.\n\n3. Khumbula uJesu laphaya,\nNabakithi asebekhona le;\nSenginas’ isizungu sakhona,\nSengikhohlwa usizi lwala.\nLaphaya, laphaya,\nKhumbula uJesu laphaya.\n\n4. Masinya ngofika laphaya,\nMasinyane ngibone abam’;\nSebefike balinda ekhaya,\nSebelinda ngofikake nam’.\nLaphaya, laphaya,\nMasinya ngofika laphaya.` },
  { id: 339, title: 'Ishesh’ Idlul’ Imihla Yam’', lyrics: `1. Ishesh’ idlul’ imihla yam’\nNgamandla andizayo;\nNgingesho kuyo, “Yima,” qha,\nNgoba ngingodlulayo.\n\nBakithi, simi eJordan,\nAbanye bayawela;\nNenkazimulo laphaya\nIcishu ukuvela.\n\n2. Ekumukeni kway’ iNkos’,\nYashiya izwi layo:\n“Bophani izinkalo nqi,\nZikhanye izibane,”\n\n3. Yebo, ngoboph’ ukhalo lwam’,\nNgiqonde-nje phezulu;\nLimnandi, lihl’ ikhaya lam’\nPhesheya kwalomfula.\n\n4. Lapha siphel’ amandla nya,\nPhesheya sophumula;\nNganeno kusemnyama-nje,\nPheshey’ inkazimulo.` },
  { id: 340, title: 'Silima Amasimu', lyrics: `1. Silima amasimu,\nSiwahlwanyele,\nIsandla sika Thixo\nSihlumisa;\nUmathis’ umhlabathi,\nIqhum’ Imbewu,\nUmoya nokukhanya\nKuvela kuye.\n\nKonke esinakho\nKuthunyw’ iNkosi;\nLukhulu, lukhulu\nUthando lwayo.\n\n2. Uyena onguMenzi\nWezinto zonke,\nUzenza izimbali\nNezinkanyezi;\nUzipha izilwane\nNe’nyoni zonke,\nNokudla kwethu thina\nKuvela kuye.\n\n3. Sibonga wena, Baba,\nNgomusa wakho,\nIhlobo nobusika,\nNempilo yonke;\nYamkela im’nikelo\nSibonga ngayo,\nKakhulu usamkele\nUqobo lwethu.` },
  { id: 341, title: 'Kuwe, Nkosi Yokuvuna', lyrics: `1. Kuwe, Nkosi yokuvuna,\nSiyabong’ okuvuniwe;\nKwalethelw’ ukuphilisa\nIzikhonzi zakho lapha;\nNgumsebenzi oyingcwele\nUkutshala nokuvuna.\n\n2. Njengoba okwakomile\nSekuvez’ okuluhlaza,\nOkufile sekwaphila,\nKwenz’wa kusha yiy’ iNkosi,\nBonk’ asebelele kuyo\nBayombesw’ im’zimb’emisha.\n\n3. Ngasicela nsukuzonke\nUkuphiwa khon’ ukudla\nKungabi- ‘kwenyama kodwa,\nKube- okomoya futhi;\nSinkwa sokuphila kwethu,\nYanelis’ abantu bakho.` },
  { id: 342, title: 'Nkosi Yethu, Siyatshala', lyrics: `1. Nkosi yethu, siyatshala,\nNans’ imbewu yethu;\nJesu Nkosi, yibusise,\nKhona iyochuma.\n\n2. Konk’ okubusiswa nguwe\nKuyathol’ inhlanhla;\nNay’ imbewu yethu lena\nIzomila kahle.\n\n3. Baba siyacel’ imvula,\nImathis’ umhlaba;\nNgob’ imbewu ingemile,\nNxa lingan’ izulu.\n\n4. nezinkab’ ezilimayo\nMazithol’ amandla;\nNabo bonk’ abatshalayo\nBabusiswe nguwe.\n\n5. Wena owadal’ izulu,\nNaw’ umhlaba futhi,\nUyiNkosi yamakhosi;\nBusa, Nkosi Jesu.` },
  { id: 343, title: 'Siyathatha Amageja', lyrics: `1. Siyathatha mageja,\nSiyalima amasimu,\nSiyethemb’ umusa wakho\nOngenamkhawulo;\nSiphe Nkosi, siphe Nkosi,\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwanele.\n\n2. Siyabheka ezulwini\nLa kuvel’ izipho zonke,\nAsinakho ukuthola;\nUngathandi, Baba.\nSiphe Nkosi, siphe Nkosi,\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwanele.\n\n3. Nxa izulu lomisile,\nAsithole ngomsa wakho;\nNxa inhlamvu ibubisa,\nAsithole ngomsa.\nSiphe Nkosi, siphe Nkosi,\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwanele.\n\n4. Lapha lina ligcugcisa,\nAsithole ngomsa wakho;\nNxa kushazwa kuluhlaza,\nSiphe ngomsa wakho.\nSiphe Nkosi, siphe Nkosi,\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwanele.\n\n5. Nxa kufika ukuvuna,\nAsithole ngomsa wakho;\nNxa sithela engotshweni,\nKungomusa wakho.\nSiphe Nkosi, siphe Nkosi\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwanele.\n\n6. Sibabaza onguyise\nNendodana yakh’ eyodwa,\nKanye naye onguMoya\nOyingcwelengcwele.\nSiphe Nkosi, siphe Nkosi,\nSiph’ ukudla okwaneleyo;\nSiphe Nkosi, siphe Nkosi,\nSiphe okwaneleyo.` },
  { id: 344, title: 'Nkosi, Baba, Usibheke', lyrics: `1. Nkosi, Baba, usibheke,\nSiyacela kuwe;\nBheka ukantula kwazo\nI’ ntandane zakho.\n\n2. Bheka izwe liyakhala,\nNgoba selomile;\nAbantwana balambile,\nIzwe selifile.\n\n3. Yebo, Nkosi, sonakele,\nAsinakuphika;\nKuze lokhukuhlupheka\nNgokuduka kwethu.\n\n4. Kodwa siyacela kuwe,\nUsithethelele;\nSusa lokhukufa kithi\nNgay’ owasifela.` },
  { id: 345, title: 'Jesu, Nkosi, Ungikhaphe', lyrics: `1. Jesu, Nkosi, ungikhaphe\nPhezu kwal’ ulwandle;\nPhambi kwam’ kushay’ amaza,\nNgolinyazw’ amatshe.\nAngibon’ indlela lapha,\nJesu, ungikhaphe.\n\n2. Njeng’ onin’ eyal’ ingane,\nWen’ ukhuz’ ulwandle;\nAyakulalel’ amaza,\nLapho uthi, “Thula.”\nNkos’ enkulu yal’ ulwandle;\nJesu ungikhaphe.\n\n3. Laph’ itheku liseduze,\nAgubaz’ amanzi,\nAthi mangingaphumuli,\nKuwe ngiyoncika;\nYisho kimi lelilizwi,\n“Mina ngokukhapha.”` },
  { id: 346, title: 'Sibheka Kuwe, Baba Nkos’', lyrics: `1. Sibheka kuwe, Baba, Nkos’\nOnguSomandla onke,\nKuwen’ okade walus’ ulwandle\nNgezwi lakho,\nMawuzwe, sikhalela bon’ aba-\nHambay’ elwandle, Nkos’\n\n2. Sibheka kuwe, Jesu, Nkos’,\nOwanyathel’ ulwandle;\nLwakhuzwa nguwe, wathulisw’\nUmoya ngezwi lakho,\nMawuzwe, sikhalela bon’ aba-\nHambay’ elwandle, Nkos’.\n\n3. Nakuwe oSithunywa la, ku-\nWena Moy’ omuhle,\nOkade wawukhona nxa umhlaba\nWadatshulwa,\nMawuzwe, sikhalela bon’ aba-\nHambay’ elwandle, Nkos’.\n\n4. Sicela, Nkulunkulu, Nkos’,\nKuwen’ onguButhathu,\nBagcine, basindise bonk’ ekhaya\nNaselwandle,\nMawuzwe, sikhalela bon’ aba-\nHambay’ elwandle, Nkos’.` },
  { id: 347, title: 'Ungumhlobo Wabantwana', lyrics: `1. Ungumhlobo wabantwana\nOkhona le phezulu,\nUmhlob’ ongaphenduki\nOmiyo yena lo;\nEminye imihlobo\nAyithembeki yona,\nLomhlobo ufanele\nIgama lakhe le.\n\n2. Bophumula abantwana\nAbaya le phezulu.\nBonk’ abathand’ uJesu\nBebong’ uYise la;\nBangabi besahlushwa,\nBangoni, bangakhali,\nBonk’ abakhatheleyo\nBayophumula le.\n\n3. Kungumuzi wabantwana\nOkhona le phezulu;\nKubus’ uJesu khona,\nBahlezi kahle la.\nAwukho emhlabeni\nOlinganayo nawo;\nLa bejabula bonke.\nAlukh’ uvalo le.\n\n4. Kungumqhele wabantwana\nOkhona le phezulu,\nBonk’ abathemb’ uJesu\nBazowufaka le;\nUmqhele wobukhosi\nUyobanika wona,\nBonk’ abamlandelayo\nBekhona kithi la.\n\n5. Bazohuba abantwana\nAbaya le phezulu,\nAbayikukhathala;\nIndab’ enkulu le.\nBohub’ igam’ elihle\nKunezingelosi,\nBebonga uMsindisi,\nZona zibong’ iNkos’.\n\n6. Bazogqoka okumhlophe\nAbaya le phezulu,\nBabethe izingumbu\nBethaba bonke le.\nKumnand’ impela lapho\nEzweni le phezulu.\nBantwana, lalelani,\nWozani kuy’ iNkos’.` },
  { id: 348, title: 'Wangithand’ UJesu Lo', lyrics: `1. Wangithand’ uJesu lo,\nKush’ incwadi njalo bo,\nNgiyingane yakhe-nje,\nAnginaw’ amandla, qha,\n\nYebo, uJesu uyangithanda,\nUyangithanda, incwadi isho la.\n\n2. Wangithand’ uJesu lo,\nWawuvul’ umnyango lo;\nWazigez’ izono zam’,\nNgongeniswa khona nam’.\n\n3. Wongithand’ uJesu na?\nUyohlala nami la?\nUma ngimuthanda-nje.\nWongiyis’ ekhaya le.` },
  { id: 350, title: 'Mina Ngingumntwana', lyrics: `1. Mina ngingumntwana,\nKodwa sengizwile\nNgaye uJehova,\nYen’ osenzileyo;\nFuthi ngitsheliwe\nAbafundisayo\nNgoMsindisi wethu\nOwasifelayo.\n\n2. Sengibusisiwe\nKune’nsaph’ ezinye;\nKuhle mangilunge\nNjeng’ abantu bakhe.\nNgiyakulalela\nAbazali bami,\nNgimuthand’ uThixo\nNgenhliziyo yami.\n\n3. Ngiyakuthandaza\nNgamasuku onke;\nOkungafanele\nNgokunqaba konke.\nThixo, ngibusise\nNgobusiso lwakho,\nNgihambise kahle\nEndleleni yakho.` },
  { id: 351, title: 'Namp’ Abantwana Bakho', lyrics: `1. Namp’ abantwana bakho\nBayajabula, Nkosi;\nNgamnandi amahubo\nBakudumisa, Nkosi;\nSibong’ ubuhle bonke\nBomhlab’ owenzileyo,\nNokusithanda kwakho,\nO Nkosi yethu.\n\n2. Noma singekubone,\nSithint’ isandla sakho,\nUmhlab’ owenzileyo\nUyakuveza kithi;\nUmhlab’ othel’ ukudla\nNekhaya nabathandwa\nKufakazela kithi;\nUkuth’ ukhona.\n\n3. Masidumise njalo,\nSihube ngenjabulo;\nMasibe qotho kuwe\nNgamazwi nangezenzo;\nUsenezel’ amandla,\nSikhule othandweni,\nNamanje naphakade\nSibe ngabakho.` },
  { id: 352, title: 'Uma Ngiyifunda Indaba Leyo', lyrics: `1. Uma ngiyifunda indaba leyo\nNgoJesu esesemhlabeni,\nEbiz’ abantwana, bafike kuye,\nKwanga mina ngangaba-naye\nKhona.\n\n2. Kwanga ngingazizwa izandla\nZakhe\nZibekwa ekhanda kimina,\nNgilizwe nephimbo elihle lakhe\nEthi, “Basondezeni la kimina.”\n\n3. Kant’ emthandazweni ngingaya\nKuye,\nNgigonw’ ezingalweni zakhe;\nUma ngisondela ngimlandele la,\nNgizombona ngisezulwini lakhe.\n\n4. Kwanga abantwanabezizwe\nZonke\nBangezwa ngoJesu’ uMsindisi,\nBaqond’ ubumnandi bothando\nLwakhe,\nBabusiswe besembusweni\nWakhe.` },
  { id: 353, title: 'Lapho uJes’ Engena', lyrics: `1. Lapho uJes’ engena\nKhon’ eJerusalema,\nKwakumi izingane\nZimuhalalisela;\nAkaze azikhuze,\nWathand’ ukwenza kwazo,\nZahamba zimlandela,\nZisamumemezela.\n\n2. UJes’ usasithanda\nThin’ izingane zakhe,\nNokuba seyebusa\nEbukhosini bakhe,\nMasisondele kuye,\nSihlabelele sithi,\nKabongwe uMsindisi,\nOthanda abantwana.\n\n3. Uma sithula thina,\nSingasabong’ iNkosi,\nAngakhulum’ amatshe,\nSithelwe amahloni.\nMasingabongi kodwa\nKuphela ngemilomo,\nSimnike nenhliziyo\nSibe-‘zingane zakhe.` },
  { id: 354, title: 'Umqumb’ Okhahlelayo', lyrics: `1. Umqumb’ okhahlelayo\nNenyoni eculayo-\nUThixo wenz’ umbala\nNephiko elincane.\n\n2. Wayenz’ inyamazane,\nWenz’ unogwaja futhi,\nNenhlanzi emfuleni,\nNentethe novemvane.\n\n3. Izinja namakati,\nIzimvu nezinkomo,\nSiphiwa zona nguye,\nMasiziphathe kahle.` },
  { id: 355, title: 'Bayahuba Abantwana', lyrics: `1. Bayahuba abantwana\nBedumis’ uJesu,\nAbezizwe eziningi\nNgezilimi zonke.\nBajabula, bajabula\nngoMsindisi wabo.\nKepha kusekhon’ abanye\nAbangakamazi.\n\n2. Thina bakaJesu sonke\nMasibakhumbule,\nSibathandazele njalo,\nSinikele futhi.\nBajabule, bajabula,\nSebemazi yena.\nYen’ uJesu ulindela\nUkwamkela bona.\n\n3. UyiNkosi enothando,\nUsithanda sonke.\nMasileth’ abanye kuye\nBabe-munye nathi;\nSijabule, sijabule,\nSesimkhonza sonke,\nYena wathi, “Bavumele\nBeze kimi bonke.”` },
  { id: 356, title: 'Yen’ Owenz’ Umhlaba', lyrics: `1. Yen’ owenz’ umhlaba\nNomoya nal’ ulwandle\nUThixo wokukhanya\nUyangithanda name.\n\n2. Yen’ owenz’ utshani,\nNe’mbali nezithelo,\nNemini nobusuku,\nUyangithanda name.\n\n3. Yen’ owenz’ ilanga\nNenyanga ne’nkanyezi,\nNgenkathi yenhlupheko\nUyangithanda name.\n\n4. Yen’ owenz’ abantu-\nUbaba nay’ umame,\nWangenza name futhi;\nUyangithanda name.` },
  { id: 357, title: 'Ngizohamba Kahle', lyrics: `1. Ngizohamba kahle,\nNgikhulume phansi,\nNgiya esontweni.\nNoma ngingembone,\nUJesu ukhona,\nUkimina njalo.` },
  { id: 358, title: 'Baba, Sibonga Ubuthongo', lyrics: `1. Baba, sibonga ubuthongo\nNokus’ okuhle kwal’ ilanga,\nNokudla kwethu, nacho konke\nEsithokoza ngakho namhla.\n\n2. Sisize, Baba, senz’ okuhle,\nSibe-simnene kubo bonke;\nNgesikwenzayo ‘mihla yonke\nSikhule kahle phambi kwakho.` },
  { id: 359, title: 'Baba, Ngiyingane Nje', lyrics: `1. Baba, ngiyingane-nje;\nUngahlala kimi na?\n“Vula inhliziyo-nje,\nWoba-ithempeli lam;”\n\n2. Nginesipho yini na,\nNgimbekel’ uJesu la?\n“Yebo loluthando-nje\nLuyigugu kuye du.”\n\n3. Yon’ indlela yakhe, pho,\nIngehlul’ i’nyawo zam’?\n“UnguMholi wakho-bo\nUzophaswa uye qho?”` },
  { id: 360, title: 'Wayenal’ Uthand’ UJesu', lyrics: `1. Wayenal’ uthand’ uJesu,\nEbasiz’ abantu\nUkumaz’ uNkulunkulu,\nBathandaze kuye.\n\n2. Wayebekezela njalo\nBaze bezwe bonke\nEd’ elanda ezimnandi-\n\n3. Lomfundis! Siyambonga\nKuwe Baba, Nkosi,\nNokusifundisa kwakhe\nUkuphil’ okuhle.` },
  { id: 361, title: 'Ngihlala Esontweni', lyrics: `1. Ngihlala esontweni, ngihlabe-\nLela,\nNgibonge, ngithandaze kwelam’\nIsonto.\n\n2. Sengikhumbul’ abanye ezweni\nLonke\nAbadumisa nabo uThixo wami.\n\n3. Kukhona abadala nabasha\nFuthi\nPhesheya naseAfrik’\nAbangabakhe.\n\n4. Ibandla likaKristu liqoqa bonke\nBezizwe eziningi abamthandayo.\n\n5. Simunye kuye sonke,\nSimkhonza yena,\nNxa senz’ intando yakhe la\nEmhlabeni.` },
  { id: 362, title: 'Wozani Nithule', lyrics: `1. Wozani nithule, kukhonani\nLapha.\nNgunin’ uMariya, eqhel’ uku-\nKhanya.\nKulesis’ tebele, elel’ emkhom-\nBeni,\nKukhona uJesu, ingane encane.\n\n2. Kufudumeziwe ngomoya\nWe’nkomo,\nKuhashaz’ utshani kumnand’\nEndlebeni;\nKungathi impepho enuka kam-\nNandi,\nKugcwel’ injabulo nothando nomusa.` },
  { id: 363, title: 'Bonke Abantwana', lyrics: `Bonke abantwana\nEzindaweni zonke,\nKulelizw’ elihle\nEsilithandayo,\nbanoYise munye\nonguYise\nwabantwana bonke\nemhlabeni.` },
  { id: 364, title: 'UJesu Omncane', lyrics: `UJesu omncane walal’ otsha-\nNini,\nWalala, wahleka wathuthuka\nNjalo,\nWakhula, waqina, wagijigijima,\nWasiza unina, enjengathi thina.` },
  { id: 365, title: 'Ngiza Nginje Kuwena, Jesu', lyrics: `1. Ngiza nginje kuwena, Jesu,\nMhlobo Wabasha onguthando,\nNgizinikela ngib’-owakho,\nNgiza kuwen, Nkosi.\n\n2. Ngiza nginje, ngisengomusha.\nYonk’ iminyaka yami, Jesu,\nNgiyinikela kuwe manje,\nNgiza kuwena, Nkosi.\n\n3. Ngiza ngingen’ ekukhanyeni,\nNgisebenzel’ umbuso wakho,\nNgikunikez’ amandla ami,\nNgiza kuwena, Nkosi.\n\n4. Ngiza nginje ngenkululeko.\nNgbe-iqhawe lokulunga,\nNgizikhethel’ indlela yakho,\nNgiza kuwena, Nkosi.` },
  { id: 366, title: 'Jesu, Siyizimvu Zakho', lyrics: `1. Jesu siyizimvu zakho,\nUsaluse njalo;\nSixhabise edlelweni,\nUsikhwez’ ekhaya;\nNkosi Jesu, Nkosi Jesu,\nSingezakho wedwa.\n\n2. Singezakho, sivikele\nNgodondolo lwakho;\nNxa seduka sibuyise,\nSingabanjw’ izono;\nNkosi Jesu, Nkosi Jesu,\nSithandaza kuwe,\nNkosi Jesu, Nkosi Jesu\nSithandaza kuwe.\n\n3. Uvumil’ ukusamkela\nSingenakulunga;\nNgomsa wakh’ uthethelela,\nUkhulul’ abakho;\nNkosi Jesu, Nkosi Jesu,\nSizinika kuwe,\nNkosi Jesu, Nkosi Jesu,\nSizinika kuwe,\nNkosi Jesu, Nkosi Jesu,\nSizinika kuwe.\n\n4. Sokufuna sisebasha,\nSenz’ intando yakho;\nUgcwalis’ izinhliziyo\nNgal’ uthando lwakho.\nNkosi Jesu, Nkosi Jesu,\nSokuthanda njalo,\nNkosi Jesu, Nkosi Jesu,\nSokuthanda njalo.` },
  { id: 367, title: 'Besekuphele Nya Inkonz’ Ethempelini', lyrics: `1. Besekuphele nya inkonz’\nEthempelini,\nKumnyama endaweni eying-\nCwele;\nLavela izwi elipheth’ intando yay’\niNkosi.\n\n2. Besekulel’ umpristi wakwa-\nIsrayeli,\nUmntwana onguSamuwel elin-\nDile;\niNkosi yavezel’ umntwan’ okufi-\nhlelw’ omkhulu.\n\n3. Ungiph’ indlebe, Nkos’, eshesha\nUkuwezwa\nAmazwi onke akho anyenyezwa,\nNgisheshe ngisabele ngenze oku-\nShoyo, Nkosi.\n\n4. Ngiph’ inhliziyo, Nkosi, etho-\nBela wena.\nEkuhlalel’ emasangweni akho;\nEmini nobusuku ngiqhaphel’\nIntando yakho.\n\n5. Ungiph’ ingqondo, Nkos’,\nEgcwele ukukholwa,\nNgivum’ intando yakho ngise-\nKhona,\nNgithole njalo njengomntwan’\nOkufihlelw’ izazi.` }
]